UPDATE words SET example_en_2 = 'My favorite author is from England.', example_ko_2 = '제가 가장 좋아하는 작가는 영국 출신이에요.', example_en_3 = 'The author of this book is very young.', example_ko_3 = '이 책의 작가는 매우 젊어요.', example_en_4 = 'Have you ever met a famous author?', example_ko_4 = '유명한 작가를 만난 적 있어요?', example_en_5 = 'She became an author after years of writing.', example_ko_5 = '그녀는 수년간 글을 쓴 후 작가가 됐어요.' WHERE id = 'w_humanities_A2_01';

UPDATE words SET example_en_2 = 'This novel is set in the future.', example_ko_2 = '이 소설은 미래를 배경으로 해요.', example_en_3 = 'I bought three novels at the bookshop.', example_ko_3 = '서점에서 소설을 세 권 샀어요.', example_en_4 = 'Her novel won an important prize.', example_ko_4 = '그녀의 소설이 중요한 상을 받았어요.', example_en_5 = 'This novel is a great introduction to English literature.', example_ko_5 = '이 소설은 영문학에 대한 훌륭한 입문서예요.' WHERE id = 'w_humanities_A2_02';

UPDATE words SET example_en_2 = 'I really like the main character in this novel.', example_ko_2 = '이 소설의 주인공이 정말 마음에 들어요.', example_en_3 = 'The character changes a lot throughout the book.', example_ko_3 = '등장인물은 책 전반에 걸쳐 많이 변해요.', example_en_4 = 'Which character do you like most?', example_ko_4 = '어떤 등장인물을 가장 좋아해요?', example_en_5 = 'The author created very believable characters.', example_ko_5 = '작가는 매우 설득력 있는 등장인물들을 만들어냈어요.' WHERE id = 'w_humanities_A2_03';

