UPDATE words SET example_en_2 = 'Reading about other cultures is very interesting.', example_ko_2 = '다른 문화에 대해 읽는 건 매우 흥미로워요.', example_en_3 = 'Literature shows us the culture of a country.', example_ko_3 = '문학은 나라의 문화를 보여줘요.', example_en_4 = 'Korean culture has a strong tradition of storytelling.', example_ko_4 = '한국 문화에는 강한 이야기 전통이 있어요.', example_en_5 = 'She studied the culture of ancient Greece.', example_ko_5 = '그녀는 고대 그리스 문화를 공부했어요.' WHERE id = 'w_humanities_A2_05';

UPDATE words SET example_en_2 = 'The tradition of reading aloud is still popular.', example_ko_2 = '소리 내어 읽는 전통은 아직도 인기 있어요.', example_en_3 = 'In Korean tradition, elders tell stories to children.', example_ko_3 = '한국 전통에서 어른들은 아이들에게 이야기를 들려줘요.', example_en_4 = 'This genre has a long tradition in English literature.', example_ko_4 = '이 장르는 영문학에서 긴 전통을 가지고 있어요.', example_en_5 = 'She wants to keep the tradition of folk songs alive.', example_ko_5 = '그녀는 민요의 전통을 살아있게 유지하고 싶어해요.' WHERE id = 'w_humanities_A2_06';

UPDATE words SET example_en_2 = 'Have you read any myths from Korea?', example_ko_2 = '한국 신화를 읽어본 적 있어요?', example_en_3 = 'This myth explains why the seasons change.', example_ko_3 = '이 신화는 왜 계절이 바뀌는지 설명해줘요.', example_en_4 = 'Myths are often very dramatic and exciting.', example_ko_4 = '신화는 종종 매우 극적이고 흥미로워요.', example_en_5 = 'The myth of Orpheus is one of my favorites.', example_ko_5 = '오르페우스 신화는 제가 가장 좋아하는 것 중 하나예요.' WHERE id = 'w_humanities_A2_07';

