UPDATE words SET example_en_2 = 'The hero of this story is a young girl.', example_ko_2 = '이 이야기의 영웅은 어린 소녀예요.', example_en_3 = 'In most myths, the hero faces a dangerous journey.', example_ko_3 = '대부분의 신화에서 영웅은 위험한 여정을 마주해요.', example_en_4 = 'Is the hero always the main character?', example_ko_4 = '영웅은 항상 주인공인가요?', example_en_5 = 'She became the hero of her own story.', example_ko_5 = '그녀는 자신만의 이야기의 영웅이 됐어요.' WHERE id = 'w_humanities_A2_09';

UPDATE words SET example_en_2 = 'Can you describe what happens in chapter two?', example_ko_2 = '2챕터에서 일어나는 일을 묘사해줄 수 있어요?', example_en_3 = 'She described the setting in great detail.', example_ko_3 = '그녀는 배경을 아주 자세하게 묘사했어요.', example_en_4 = 'Describe the main character using three words.', example_ko_4 = '세 단어를 사용해 주인공을 묘사해보세요.', example_en_5 = 'The book describes life in a small Korean village.', example_ko_5 = '그 책은 작은 한국 마을에서의 삶을 묘사해요.' WHERE id = 'w_humanities_A2_10';

UPDATE words SET example_en_2 = 'Reading helps to develop your imagination.', example_ko_2 = '독서는 상상력을 키우는 데 도움이 돼요.', example_en_3 = 'She has a wonderful imagination and writes great stories.', example_ko_3 = '그녀는 훌륭한 상상력이 있어서 멋진 이야기를 써요.', example_en_4 = 'Let your imagination guide your writing.', example_ko_4 = '상상력이 글쓰기를 이끌게 해보세요.', example_en_5 = 'Fantasy novels require a lot of imagination.', example_ko_5 = '판타지 소설은 많은 상상력을 필요로 해요.' WHERE id = 'w_humanities_A2_11';

UPDATE words SET example_en_2 = 'She reads poetry every morning to start her day.', example_ko_2 = '그녀는 하루를 시작하기 위해 매일 아침 시를 읽어요.', example_en_3 = 'Modern poetry can sometimes be hard to understand.', example_ko_3 = '현대시는 때로 이해하기 어려울 수 있어요.', example_en_4 = 'His poetry is full of beautiful images.', example_ko_4 = '그의 시는 아름다운 심상으로 가득해요.', example_en_5 = 'Poetry is a great way to express your feelings.', example_ko_5 = '시는 감정을 표현하는 좋은 방법이에요.' WHERE id = 'w_humanities_A2_12';

UPDATE words SET example_en_2 = 'Historical fiction is my favorite type of fiction.', example_ko_2 = '역사 소설은 제가 가장 좋아하는 허구 유형이에요.', example_en_3 = 'Fiction allows us to explore new worlds safely.', example_ko_3 = '소설은 우리가 안전하게 새로운 세계를 탐험하게 해줘요.', example_en_4 = 'She prefers fiction to non-fiction.', example_ko_4 = '그녀는 논픽션보다 소설을 더 좋아해요.', example_en_5 = 'Good fiction feels very close to real life.', example_ko_5 = '좋은 소설은 현실과 매우 가깝게 느껴져요.' WHERE id = 'w_humanities_A2_13';

