UPDATE words SET example_en_2 = 'The setting of the story is a small fishing village.', example_ko_2 = '이야기의 배경은 작은 어촌이에요.', example_en_3 = 'The setting plays an important role in the novel.', example_ko_3 = '배경은 소설에서 중요한 역할을 해요.', example_en_4 = 'Can you describe the setting in your own words?', example_ko_4 = '자신만의 말로 배경을 묘사해줄 수 있어요?', example_en_5 = 'The dark setting helps to create a mysterious mood.', example_ko_5 = '어두운 배경이 신비로운 분위기를 만드는 데 도움이 돼요.' WHERE id = 'w_humanities_A2_19';

