UPDATE words SET example_en_2 = 'Compare the two main characters and their choices.', example_ko_2 = '두 주인공과 그들의 선택을 비교해보세요.', example_en_3 = 'I like to compare different translations of the same poem.', example_ko_3 = '같은 시의 다른 번역들을 비교하는 걸 좋아해요.', example_en_4 = 'How does this novel compare to her earlier work?', example_ko_4 = '이 소설은 그녀의 이전 작품과 어떻게 비교되나요?', example_en_5 = 'It is interesting to compare myths from different cultures.', example_ko_5 = '다른 문화권의 신화들을 비교하는 건 흥미로워요.' WHERE id = 'w_humanities_A2_22';

