UPDATE words SET example_en_2 = 'Lord of the Flies functions as a political allegory.', example_ko_2 = '파리대왕은 정치적 알레고리로 기능해요.', example_en_3 = 'The allegory in the novel is complex and multi-layered.', example_ko_3 = '소설의 알레고리는 복잡하고 다층적이에요.', example_en_4 = 'She wrote an essay analyzing the allegory of the cave.', example_ko_4 = '그녀는 동굴의 알레고리를 분석하는 에세이를 썼어요.', example_en_5 = 'Reading a text as allegory can reveal its political critique.', example_ko_5 = '텍스트를 알레고리로 읽으면 정치적 비평을 드러낼 수 있어요.' WHERE id = 'w_humanities_B2_01';

UPDATE words SET example_en_2 = 'The trickster is a well-known archetype in folklore.', example_ko_2 = '트릭스터는 민담에서 잘 알려진 원형이에요.', example_en_3 = 'She analyzed the archetype of the mother figure in three novels.', example_ko_3 = '그녀는 세 편의 소설에서 어머니 상의 원형을 분석했어요.', example_en_4 = 'The archetype of the outcast appears across many cultures.', example_ko_4 = '아웃캐스트의 원형은 많은 문화에 걸쳐 나타나요.', example_en_5 = 'Understanding archetypes helps you identify patterns in storytelling.', example_ko_5 = '원형을 이해하면 이야기 방식에서 패턴을 찾는 데 도움이 돼요.' WHERE id = 'w_humanities_B2_02';

UPDATE words SET example_en_2 = 'The motif of the mirror appears in many Gothic novels.', example_ko_2 = '거울의 모티프는 많은 고딕 소설에 나타나요.', example_en_3 = 'Identify and explain one motif in the novel.', example_ko_3 = '소설에서 하나의 모티프를 찾아 설명해보세요.', example_en_4 = 'The journey motif is central to the bildungsroman tradition.', example_ko_4 = '여정 모티프는 성장 소설 전통의 중심이에요.', example_en_5 = 'She traced the motif of silence throughout the collection.', example_ko_5 = '그녀는 시집 전체에 걸쳐 침묵의 모티프를 추적했어요.' WHERE id = 'w_humanities_B2_03';

UPDATE words SET example_en_2 = 'The subtext of the conversation reveals a power struggle.', example_ko_2 = '대화의 서브텍스트는 권력 투쟁을 드러내요.', example_en_3 = 'She read the subtext of the scene as an expression of grief.', example_ko_3 = '그녀는 장면의 서브텍스트를 슬픔의 표현으로 읽었어요.', example_en_4 = 'The subtext is sometimes more important than the text itself.', example_ko_4 = '서브텍스트는 때로 텍스트 자체보다 더 중요해요.', example_en_5 = 'Look beneath the surface to find the subtext of the scene.', example_ko_5 = '장면의 서브텍스트를 찾기 위해 표면 아래를 들여다보세요.' WHERE id = 'w_humanities_B2_04';

UPDATE words SET example_en_2 = 'The irony of the story is that the hero causes the tragedy himself.', example_ko_2 = '이야기의 아이러니는 영웅 스스로가 비극을 일으킨다는 거예요.', example_en_3 = 'Dramatic irony occurs when the audience knows something the character does not.', example_ko_3 = '극적 아이러니는 관객이 등장인물이 모르는 무언가를 알 때 발생해요.', example_en_4 = 'She used irony to comment on the vanity of social ambition.', example_ko_4 = '그녀는 사회적 야망의 허영을 언급하기 위해 아이러니를 사용했어요.', example_en_5 = 'The irony becomes clear only when you reach the final chapter.', example_ko_5 = '아이러니는 마지막 챕터에 도달해야만 명확해져요.' WHERE id = 'w_humanities_B2_05';

UPDATE words SET example_en_2 = 'The poem presents a paradox: the more you know, the less you understand.', example_ko_2 = '시는 역설을 제시해요: 알면 알수록 덜 이해하게 된다는 거예요.', example_en_3 = 'Explore the paradox at the center of the character''s dilemma.', example_ko_3 = '등장인물의 딜레마 중심의 역설을 탐구해보세요.', example_en_4 = 'The paradox is that the author criticizes the very society she is part of.', example_ko_4 = '역설은 작가가 자신이 속한 바로 그 사회를 비판한다는 거예요.', example_en_5 = 'Beckett''s work thrives on paradox and contradiction.', example_ko_5 = '베케트의 작품은 역설과 모순 위에서 번성해요.' WHERE id = 'w_humanities_B2_06';

UPDATE words SET example_en_2 = 'She used satire to expose the hypocrisy of the ruling class.', example_ko_2 = '그녀는 지배 계층의 위선을 드러내기 위해 풍자를 사용했어요.', example_en_3 = 'Political satire is as relevant today as it was in the 18th century.', example_ko_3 = '정치 풍자는 18세기만큼 오늘날에도 여전히 유효해요.', example_en_4 = 'The satire in the novel targets social inequality.', example_ko_4 = '소설의 풍자는 사회적 불평등을 겨냥해요.', example_en_5 = 'Effective satire requires both wit and a serious moral purpose.', example_ko_5 = '효과적인 풍자는 재치와 진지한 도덕적 목적 모두를 필요로 해요.' WHERE id = 'w_humanities_B2_07';

UPDATE words SET example_en_2 = 'Great Expectations is often read as a bildungsroman.', example_ko_2 = '위대한 유산은 종종 성장 소설로 읽혀요.', example_en_3 = 'The bildungsroman traces the hero''s path from innocence to experience.', example_ko_3 = '성장 소설은 영웅이 순수함에서 경험으로 나아가는 길을 추적해요.', example_en_4 = 'She wrote her thesis on the Korean bildungsroman tradition.', example_ko_4 = '그녀는 한국 성장 소설 전통에 대한 논문을 썼어요.', example_en_5 = 'What makes this novel a classic bildungsroman?', example_ko_5 = '이 소설을 고전적인 성장 소설로 만드는 것은 무엇인가요?' WHERE id = 'w_humanities_B2_08';

UPDATE words SET example_en_2 = 'Modernism broke with traditional forms of storytelling.', example_ko_2 = '모더니즘은 전통적인 이야기 방식과 단절했어요.', example_en_3 = 'The stream of consciousness technique is a hallmark of literary modernism.', example_ko_3 = '의식의 흐름 기법은 문학 모더니즘의 특징이에요.', example_en_4 = 'She is writing a dissertation on modernism and trauma.', example_ko_4 = '그녀는 모더니즘과 트라우마에 관한 논문을 쓰고 있어요.', example_en_5 = 'Modernism challenged readers to engage more actively with texts.', example_ko_5 = '모더니즘은 독자들이 텍스트와 더 적극적으로 관계를 맺도록 도전했어요.' WHERE id = 'w_humanities_B2_09';

UPDATE words SET example_en_2 = 'Existentialism holds that humans create their own meaning.', example_ko_2 = '실존주의는 인간이 스스로 의미를 만든다고 주장해요.', example_en_3 = 'The novel is informed by existentialism and its ideas about freedom.', example_ko_3 = '소설은 실존주의와 자유에 대한 그 생각들에서 영향을 받았어요.', example_en_4 = 'He wrote a paper comparing Sartre''s and Camus'' approaches to existentialism.', example_ko_4 = '그는 실존주의에 대한 사르트르와 카뮈의 접근 방식을 비교하는 논문을 썼어요.', example_en_5 = 'Existentialism was a major influence on post-war European literature.', example_ko_5 = '실존주의는 전후 유럽 문학에 큰 영향을 미쳤어요.' WHERE id = 'w_humanities_B2_10';

UPDATE words SET example_en_2 = 'The allusion to Adam and Eve enriches the theme of innocence.', example_ko_2 = '아담과 이브에 대한 암시가 순수함의 주제를 풍부하게 해요.', example_en_3 = 'She identifies three allusions to classical mythology in the poem.', example_ko_3 = '그녀는 시에서 고전 신화에 대한 세 가지 암시를 찾아요.', example_en_4 = 'Recognizing an allusion requires broad cultural knowledge.', example_ko_4 = '암시를 인식하려면 넓은 문화적 지식이 필요해요.', example_en_5 = 'The allusion deepens the meaning without stating it directly.', example_ko_5 = '암시는 직접적으로 말하지 않고도 의미를 깊게 해요.' WHERE id = 'w_humanities_B2_11';

UPDATE words SET example_en_2 = 'The poem''s ambiguity invites many different readings.', example_ko_2 = '시의 모호함은 다양한 독해를 초대해요.', example_en_3 = 'The author uses ambiguity deliberately to keep the reader uncertain.', example_ko_3 = '작가는 독자를 불확실하게 유지하기 위해 의도적으로 모호함을 사용해요.', example_en_4 = 'The moral ambiguity of the hero makes him fascinating.', example_ko_4 = '영웅의 도덕적 모호함이 그를 매력적으로 만들어요.', example_en_5 = 'Critical debate around this poem centers on its central ambiguity.', example_ko_5 = '이 시에 대한 비평적 논의는 핵심 모호함을 중심으로 해요.' WHERE id = 'w_humanities_B2_12';

UPDATE words SET example_en_2 = 'The recurring dream is a form of foreshadowing.', example_ko_2 = '반복되는 꿈은 복선의 한 형태예요.', example_en_3 = 'She identified three instances of foreshadowing in the opening chapter.', example_ko_3 = '그녀는 첫 챕터에서 세 가지 복선을 찾아냈어요.', example_en_4 = 'Foreshadowing creates suspense and keeps the reader engaged.', example_ko_4 = '복선은 긴장감을 만들고 독자의 관심을 유지시켜요.', example_en_5 = 'The author uses foreshadowing subtly so the reader is surprised.', example_ko_5 = '작가는 독자가 놀랄 수 있도록 복선을 교묘하게 사용해요.' WHERE id = 'w_humanities_B2_13';

UPDATE words SET example_en_2 = 'Postmodernism rejects the idea of a single, fixed truth.', example_ko_2 = '포스트모더니즘은 단일하고 고정된 진실이라는 생각을 거부해요.', example_en_3 = 'Her work is considered a significant contribution to postmodernism.', example_ko_3 = '그녀의 작품은 포스트모더니즘에 대한 중요한 기여로 여겨져요.', example_en_4 = 'Postmodernism celebrates the mixing of high and low culture.', example_ko_4 = '포스트모더니즘은 고급 문화와 대중 문화의 혼합을 찬양해요.', example_en_5 = 'She explored how postmodernism shaped contemporary Korean fiction.', example_ko_5 = '그녀는 포스트모더니즘이 현대 한국 소설을 어떻게 형성했는지 탐구했어요.' WHERE id = 'w_humanities_B2_14';

UPDATE words SET example_en_2 = 'The narrator is unreliable because he consistently contradicts himself.', example_ko_2 = '화자는 끊임없이 자기 자신과 모순되기 때문에 믿을 수 없어요.', example_en_3 = 'Discuss why the narrator in this novel should be considered unreliable.', example_ko_3 = '이 소설의 화자가 왜 믿을 수 없다고 여겨져야 하는지 논의해보세요.', example_en_4 = 'The unreliable narrator challenges the reader to think critically.', example_ko_4 = '믿을 수 없는 화자는 독자가 비판적으로 생각하도록 도전해요.', example_en_5 = 'How do we know when a narrator is unreliable?', example_ko_5 = '화자가 믿을 수 없다는 것을 어떻게 알 수 있나요?' WHERE id = 'w_humanities_B2_15';

UPDATE words SET example_en_2 = 'The audience experiences catharsis through the hero''s suffering.', example_ko_2 = '관객은 영웅의 고통을 통해 카타르시스를 경험해요.', example_en_3 = 'Aristotle believed catharsis was the purpose of tragedy.', example_ko_3 = '아리스토텔레스는 카타르시스가 비극의 목적이라고 믿었어요.', example_en_4 = 'The novel offers a kind of catharsis to readers who have experienced loss.', example_ko_4 = '소설은 상실을 경험한 독자들에게 일종의 카타르시스를 제공해요.', example_en_5 = 'Do you think all great literature produces catharsis?', example_ko_5 = '모든 위대한 문학이 카타르시스를 만들어낸다고 생각해요?' WHERE id = 'w_humanities_B2_16';

UPDATE words SET example_en_2 = 'She wrote her dissertation on the aesthetic of minimalism in fiction.', example_ko_2 = '그녀는 소설에서 미니멀리즘의 미학에 대한 논문을 썼어요.', example_en_3 = 'The aesthetic of the novel is deeply influenced by Japanese literature.', example_ko_3 = '소설의 미학은 일본 문학에 깊이 영향을 받았어요.', example_en_4 = 'She has a refined aesthetic sensibility that shows in every sentence.', example_ko_4 = '그녀는 모든 문장에서 드러나는 세련된 미적 감수성이 있어요.', example_en_5 = 'The aesthetic choices of the author create a distinctive atmosphere.', example_ko_5 = '작가의 미적 선택이 독특한 분위기를 만들어요.' WHERE id = 'w_humanities_B2_17';

UPDATE words SET example_en_2 = 'Paradise Lost is the most famous English language epic.', example_ko_2 = '실낙원은 가장 유명한 영어 서사시예요.', example_en_3 = 'The journey is an epic one, spanning three continents.', example_ko_3 = '그 여정은 세 대륙에 걸친 장대한 것이에요.', example_en_4 = 'She compared the structure of the Odyssey to a modern epic novel.', example_ko_4 = '그녀는 오디세이의 구조를 현대 서사 소설과 비교했어요.', example_en_5 = 'The epic tradition shaped how Western cultures tell stories of war.', example_ko_5 = '서사시 전통은 서양 문화가 전쟁 이야기를 하는 방식을 형성했어요.' WHERE id = 'w_humanities_B2_18';

UPDATE words SET example_en_2 = 'The dialect used by the characters reveals their social class.', example_ko_2 = '등장인물들이 사용하는 방언이 그들의 사회 계층을 드러내요.', example_en_3 = 'She studied the literary use of dialect in 19th-century novels.', example_ko_3 = '그녀는 19세기 소설에서 방언의 문학적 사용을 연구했어요.', example_en_4 = 'Writers sometimes use dialect to challenge standard language hierarchies.', example_ko_4 = '작가들은 때로 표준 언어 위계에 도전하기 위해 방언을 사용해요.', example_en_5 = 'The dialect in this novel was difficult to understand at first.', example_ko_5 = '이 소설의 방언은 처음에 이해하기 어려웠어요.' WHERE id = 'w_humanities_B2_19';

UPDATE words SET example_en_2 = 'The characterization of the villain is surprisingly sympathetic.', example_ko_2 = '악당의 인물 묘사가 놀랍도록 공감가게 표현되어 있어요.', example_en_3 = 'Discuss how the author uses dialogue in her characterization.', example_ko_3 = '작가가 인물 묘사에서 대화를 어떻게 사용하는지 논의해보세요.', example_en_4 = 'The characterization of the minor characters is just as vivid as the hero.', example_ko_4 = '조연의 인물 묘사가 주인공만큼 생생해요.', example_en_5 = 'What techniques of characterization does the author rely on most?', example_ko_5 = '작가가 가장 많이 의존하는 인물 묘사 기법은 무엇인가요?' WHERE id = 'w_humanities_B2_20';

UPDATE words SET example_en_2 = 'The juxtaposition of wealth and poverty is central to the novel.', example_ko_2 = '부와 가난의 병치가 소설의 핵심이에요.', example_en_3 = 'She analyzed the juxtaposition of joy and despair in the poem.', example_ko_3 = '그녀는 시에서 기쁨과 절망의 병치를 분석했어요.', example_en_4 = 'Juxtaposition can make both elements of a comparison more vivid.', example_ko_4 = '병치는 비교의 두 요소를 모두 더 생생하게 만들 수 있어요.', example_en_5 = 'The author places comedy next to tragedy through juxtaposition.', example_ko_5 = '작가는 병치를 통해 희극 옆에 비극을 배치해요.' WHERE id = 'w_humanities_B2_21';

UPDATE words SET example_en_2 = 'The omniscient narrator knows every character''s thoughts and feelings.', example_ko_2 = '전지적 화자는 모든 등장인물의 생각과 감정을 알고 있어요.', example_en_3 = 'An omniscient point of view gives the author great freedom.', example_ko_3 = '전지적 관점은 작가에게 큰 자유를 줘요.', example_en_4 = 'Why do some authors choose not to use an omniscient narrator?', example_ko_4 = '왜 어떤 작가들은 전지적 화자를 사용하지 않는 건가요?', example_en_5 = 'The omniscient narrator in this novel is surprisingly judgmental.', example_ko_5 = '이 소설의 전지적 화자는 놀랍도록 판단을 많이 해요.' WHERE id = 'w_humanities_B2_22';

UPDATE words SET example_en_2 = 'Tolstoy is considered a master of literary realism.', example_ko_2 = '톨스토이는 문학 사실주의의 거장으로 여겨져요.', example_en_3 = 'Realism in literature aims to depict everyday life without idealization.', example_ko_3 = '문학에서 사실주의는 이상화 없이 일상을 묘사하는 것을 목표로 해요.', example_en_4 = 'She is writing a paper on social realism in Korean fiction.', example_ko_4 = '그녀는 한국 소설의 사회적 사실주의에 관한 논문을 쓰고 있어요.', example_en_5 = 'How does realism differ from naturalism in literature?', example_ko_5 = '문학에서 사실주의는 자연주의와 어떻게 다른가요?' WHERE id = 'w_humanities_B2_23';

UPDATE words SET example_en_2 = 'Romanticism valued feeling and imagination over reason.', example_ko_2 = '낭만주의는 이성보다 감정과 상상력을 중시했어요.', example_en_3 = 'She wrote about the influence of romanticism on modern poetry.', example_ko_3 = '그녀는 현대 시에 미친 낭만주의의 영향에 대해 썼어요.', example_en_4 = 'Romanticism was partly a reaction against the Industrial Revolution.', example_ko_4 = '낭만주의는 부분적으로 산업혁명에 대한 반작용이었어요.', example_en_5 = 'The most famous works of romanticism celebrate the power of nature.', example_ko_5 = '낭만주의의 가장 유명한 작품들은 자연의 힘을 찬양해요.' WHERE id = 'w_humanities_B2_24';

UPDATE words SET example_en_2 = 'The expansion of the literary canon is an ongoing debate.', example_ko_2 = '문학 캐논의 확장은 지속적인 논의 주제예요.', example_en_3 = 'Many non-Western authors are now included in the university canon.', example_ko_3 = '많은 비서구 작가들이 이제 대학 캐논에 포함돼요.', example_en_4 = 'She argues that the canon should reflect global literary traditions.', example_ko_4 = '그녀는 캐논이 세계 문학 전통을 반영해야 한다고 주장해요.', example_en_5 = 'Which novels do you think belong in the literary canon?', example_ko_5 = '어떤 소설들이 문학 캐논에 속한다고 생각해요?' WHERE id = 'w_humanities_B2_25';

UPDATE words SET example_en_2 = 'The author''s use of rhetoric is subtle but very effective.', example_ko_2 = '작가의 수사법 사용은 미묘하지만 매우 효과적이에요.', example_en_3 = 'She studied classical rhetoric to improve her essay writing.', example_ko_3 = '그녀는 에세이 쓰기를 향상시키기 위해 고전 수사학을 공부했어요.', example_en_4 = 'The rhetoric of the speech was designed to appeal to emotions.', example_ko_4 = '연설의 수사법은 감정에 호소하도록 설계됐어요.', example_en_5 = 'Rhetoric teaches us how language is used to persuade.', example_ko_5 = '수사학은 언어가 어떻게 설득에 사용되는지 가르쳐줘요.' WHERE id = 'w_humanities_B2_26';

UPDATE words SET example_en_2 = 'We can infer from the text that the character is lying.', example_ko_2 = '텍스트에서 그 인물이 거짓말을 하고 있다고 추론할 수 있어요.', example_en_3 = 'Infer the meaning of unfamiliar words from context.', example_ko_3 = '문맥에서 낯선 단어의 의미를 추론해보세요.', example_en_4 = 'What can we infer about the narrator from the first paragraph?', example_ko_4 = '첫 단락에서 화자에 대해 무엇을 추론할 수 있나요?', example_en_5 = 'She inferred the political message of the poem from its imagery.', example_ko_5 = '그녀는 시의 심상으로부터 정치적 메시지를 추론했어요.' WHERE id = 'w_humanities_B2_27';

UPDATE words SET example_en_2 = 'The novel explores how collective trauma shapes a community.', example_ko_2 = '소설은 집단 트라우마가 어떻게 공동체를 형성하는지 탐구해요.', example_en_3 = 'She reads the novel as a meditation on historical trauma.', example_ko_3 = '그녀는 소설을 역사적 트라우마에 대한 성찰로 읽어요.', example_en_4 = 'Trauma theory has become central to contemporary literary studies.', example_ko_4 = '트라우마 이론은 현대 문학 연구의 핵심이 됐어요.', example_en_5 = 'The imagery of wounds and scars reflects the character''s trauma.', example_ko_5 = '상처와 흉터의 심상은 인물의 트라우마를 반영해요.' WHERE id = 'w_humanities_B2_28';

UPDATE words SET example_en_2 = 'Brave New World is a famous example of dystopia fiction.', example_ko_2 = '멋진 신세계는 디스토피아 소설의 유명한 예예요.', example_en_3 = 'The dystopia in the novel reflects contemporary anxieties.', example_ko_3 = '소설의 디스토피아는 현대의 불안을 반영해요.', example_en_4 = 'She analyzed how dystopia is used to critique political power.', example_ko_4 = '그녀는 디스토피아가 정치 권력을 비판하기 위해 어떻게 사용되는지 분석했어요.', example_en_5 = 'What distinguishes a dystopia from a simply unpleasant world?', example_ko_5 = '디스토피아를 단순히 불쾌한 세상과 구분하는 것은 무엇인가요?' WHERE id = 'w_humanities_B2_29';

UPDATE words SET example_en_2 = 'Sir Thomas More described a utopia as an ideal island community.', example_ko_2 = '토마스 모어는 유토피아를 이상적인 섬 공동체로 묘사했어요.', example_en_3 = 'Every utopia contains the seeds of its own destruction.', example_ko_3 = '모든 유토피아는 자체적 파괴의 씨앗을 품고 있어요.', example_en_4 = 'The novel imagines a utopia based on cooperation rather than competition.', example_ko_4 = '소설은 경쟁이 아닌 협력에 기반한 유토피아를 상상해요.', example_en_5 = 'She analyzed the tension between utopia and reality in the text.', example_ko_5 = '그녀는 텍스트에서 유토피아와 현실 사이의 긴장감을 분석했어요.' WHERE id = 'w_humanities_B2_30';

UPDATE words SET example_en_2 = 'The novel raises complex questions about personal morality.', example_ko_2 = '소설은 개인적 도덕성에 대한 복잡한 질문들을 제기해요.', example_en_3 = 'Victorian fiction was often deeply concerned with morality.', example_ko_3 = '빅토리아 시대 소설은 종종 도덕성에 깊이 관심을 가졌어요.', example_en_4 = 'She explores the tension between morality and survival in the novel.', example_ko_4 = '그녀는 소설에서 도덕성과 생존 사이의 긴장감을 탐구해요.', example_en_5 = 'Good literature refuses to offer easy answers about morality.', example_ko_5 = '좋은 문학은 도덕성에 대한 쉬운 답변을 제시하기를 거부해요.' WHERE id = 'w_humanities_B2_31';

UPDATE words SET example_en_2 = 'The character''s ambivalence makes her impossible to judge simply.', example_ko_2 = '인물의 양가감정이 그녀를 단순하게 판단하기 불가능하게 만들어요.', example_en_3 = 'She reads the novel''s ending as an expression of ambivalence.', example_ko_3 = '그녀는 소설의 결말을 양가감정의 표현으로 읽어요.', example_en_4 = 'The speaker''s ambivalence toward home is central to the poem.', example_ko_4 = '화자의 고향에 대한 양가감정이 시의 핵심이에요.', example_en_5 = 'Ambivalence is a more honest emotion than simple love or hate.', example_ko_5 = '양가감정은 단순한 사랑이나 증오보다 더 솔직한 감정이에요.' WHERE id = 'w_humanities_B2_32';

UPDATE words SET example_en_2 = 'The stream of consciousness technique mimics the natural flow of consciousness.', example_ko_2 = '의식의 흐름 기법은 의식의 자연스러운 흐름을 모방해요.', example_en_3 = 'She analyzed how Joyce used consciousness as a narrative tool.', example_ko_3 = '그녀는 조이스가 의식을 서술 도구로 어떻게 사용했는지 분석했어요.', example_en_4 = 'The novel gives us direct access to the character''s consciousness.', example_ko_4 = '소설은 인물의 의식에 직접 접근하게 해줘요.', example_en_5 = 'Consciousness in this poem fragments as the speaker''s grief intensifies.', example_ko_5 = '이 시에서 화자의 슬픔이 깊어지면서 의식이 파편화돼요.' WHERE id = 'w_humanities_B2_33';

UPDATE words SET example_en_2 = 'The absurd humor in the novel makes its tragedy even more powerful.', example_ko_2 = '소설의 부조리한 유머가 그 비극을 더욱 강력하게 만들어요.', example_en_3 = 'The absurd situation highlights the futility of the character''s efforts.', example_ko_3 = '부조리한 상황이 인물의 노력의 무의미함을 부각시켜요.', example_en_4 = 'She writes about the absurd gap between language and experience.', example_ko_4 = '그녀는 언어와 경험 사이의 부조리한 간극에 대해 써요.', example_en_5 = 'Absurd literature often reveals the limits of rational thinking.', example_ko_5 = '부조리 문학은 종종 이성적 사고의 한계를 드러내요.' WHERE id = 'w_humanities_B2_34';

UPDATE words SET example_en_2 = 'She was invited to critique the manuscript before publication.', example_ko_2 = '그녀는 출판 전 원고를 비평해달라는 초대를 받았어요.', example_en_3 = 'To critique a text, you must first read it carefully.', example_ko_3 = '텍스트를 비평하려면 먼저 주의 깊게 읽어야 해요.', example_en_4 = 'He was asked to critique the essay using the rubric provided.', example_ko_4 = '그는 제공된 기준을 사용해 에세이를 비평해달라는 요청을 받았어요.', example_en_5 = 'It takes skill to critique a text without dismissing it entirely.', example_ko_5 = '텍스트를 완전히 부정하지 않고 비평하는 것은 기술이 필요해요.' WHERE id = 'w_humanities_B2_35';

