UPDATE words SET example_en_2 = 'Hermeneutics seeks to understand how we interpret meaning in texts.', example_ko_2 = '해석학은 우리가 텍스트에서 의미를 어떻게 해석하는지 이해하려고 해요.', example_en_3 = 'She applies a hermeneutic approach to the analysis of sacred texts.', example_ko_3 = '그녀는 신성한 텍스트 분석에 해석학적 접근을 적용해요.', example_en_4 = 'Gadamer''s hermeneutics challenges the idea of objective interpretation.', example_ko_4 = '가다머의 해석학은 객관적 해석이라는 생각에 도전해요.', example_en_5 = 'A hermeneutic circle describes how parts and the whole of a text inform each other.', example_ko_5 = '해석학적 순환은 텍스트의 부분과 전체가 서로에게 어떻게 정보를 제공하는지 설명해요.' WHERE id = 'w_humanities_C1_01';

UPDATE words SET example_en_2 = 'Semiotics allows us to read culture as a system of signs.', example_ko_2 = '기호학은 우리가 문화를 기호 시스템으로 읽을 수 있게 해줘요.', example_en_3 = 'She applied semiotics to analyze the imagery of the poem.', example_ko_3 = '그녀는 시의 심상을 분석하기 위해 기호학을 적용했어요.', example_en_4 = 'Ferdinand de Saussure is considered the founder of modern semiotics.', example_ko_4 = '페르디낭 드 소쉬르는 현대 기호학의 창시자로 여겨져요.', example_en_5 = 'Semiotics reveals how seemingly neutral images carry ideological meaning.', example_ko_5 = '기호학은 겉으로 중립적인 이미지가 어떻게 이데올로기적 의미를 담는지 드러내요.' WHERE id = 'w_humanities_C1_02';

UPDATE words SET example_en_2 = 'The novel''s intertextuality with Greek epic tradition is unmistakable.', example_ko_2 = '소설과 그리스 서사시 전통 사이의 상호텍스트성은 분명해요.', example_en_3 = 'She wrote a chapter on intertextuality and its implications for reading.', example_ko_3 = '그녀는 상호텍스트성과 독해에 대한 함의에 관한 챕터를 썼어요.', example_en_4 = 'Intertextuality challenges the idea of the original, autonomous text.', example_ko_4 = '상호텍스트성은 원본이고 자율적인 텍스트라는 생각에 도전해요.', example_en_5 = 'The poem''s intertextuality enriches its meaning for knowledgeable readers.', example_ko_5 = '시의 상호텍스트성은 해박한 독자들에게 의미를 풍부하게 해줘요.' WHERE id = 'w_humanities_C1_03';

UPDATE words SET example_en_2 = 'Deconstruction exposes the binary oppositions hidden in a text.', example_ko_2 = '해체주의는 텍스트에 숨겨진 이분법적 대립을 드러내요.', example_en_3 = 'She used deconstruction to challenge the novel''s apparent moral certainty.', example_ko_3 = '그녀는 소설의 명백한 도덕적 확신에 도전하기 위해 해체주의를 사용했어요.', example_en_4 = 'Deconstruction is not about destroying meaning but revealing its instability.', example_ko_4 = '해체주의는 의미를 파괴하는 것이 아니라 그 불안정성을 드러내는 거예요.', example_en_5 = 'Apply deconstruction to analyze how gender is constructed in the text.', example_ko_5 = '텍스트에서 젠더가 어떻게 구성되는지 분석하기 위해 해체주의를 적용해보세요.' WHERE id = 'w_humanities_C1_04';

UPDATE words SET example_en_2 = 'Poststructuralism emerged as a critique of structuralism''s fixed meanings.', example_ko_2 = '포스트구조주의는 구조주의의 고정된 의미에 대한 비판으로 등장했어요.', example_en_3 = 'She introduced poststructuralism to her students through Barthes'' essay on the death of the author.', example_ko_3 = '그녀는 바르트의 작가의 죽음에 대한 에세이를 통해 학생들에게 포스트구조주의를 소개했어요.', example_en_4 = 'Poststructuralism emphasizes the instability of language and meaning.', example_ko_4 = '포스트구조주의는 언어와 의미의 불안정성을 강조해요.', example_en_5 = 'Her work bridges poststructuralism and feminist literary theory.', example_ko_5 = '그녀의 작품은 포스트구조주의와 페미니즘 문학 이론을 연결해요.' WHERE id = 'w_humanities_C1_05';

UPDATE words SET example_en_2 = 'Phenomenology focuses on the lived experience of reading a text.', example_ko_2 = '현상학은 텍스트를 읽는 생생한 경험에 집중해요.', example_en_3 = 'She applied phenomenology to study how readers respond emotionally to fiction.', example_ko_3 = '그녀는 독자들이 소설에 감정적으로 어떻게 반응하는지 연구하기 위해 현상학을 적용했어요.', example_en_4 = 'Phenomenology asks what it feels like to encounter a text for the first time.', example_ko_4 = '현상학은 텍스트를 처음 접할 때 어떤 느낌인지 물어요.', example_en_5 = 'Her phenomenological reading of the poem reveals how time is experienced differently by the speaker.', example_ko_5 = '그녀의 시에 대한 현상학적 독해는 화자가 시간을 어떻게 다르게 경험하는지 드러내요.' WHERE id = 'w_humanities_C1_06';

UPDATE words SET example_en_2 = 'Hegel''s dialectic moves through thesis, antithesis, and synthesis.', example_ko_2 = '헤겔의 변증법은 정, 반, 합을 거쳐 나아가요.', example_en_3 = 'The dialectic between freedom and necessity runs through the novel.', example_ko_3 = '자유와 필연성 사이의 변증법이 소설을 관통해요.', example_en_4 = 'She applied a Marxist dialectic to analyze the class conflict in the text.', example_ko_4 = '그녀는 텍스트의 계급 갈등을 분석하기 위해 마르크스주의 변증법을 적용했어요.', example_en_5 = 'The dialectic between the individual and society is a recurring concern in the novel.', example_ko_5 = '개인과 사회 사이의 변증법이 소설에서 반복되는 관심사예요.' WHERE id = 'w_humanities_C1_07';

UPDATE words SET example_en_2 = 'The concept of mimesis was central to ancient Greek aesthetics.', example_ko_2 = '미메시스 개념은 고대 그리스 미학의 핵심이었어요.', example_en_3 = 'She examined mimesis in Aristotle''s Poetics and its legacy in Western drama.', example_ko_3 = '그녀는 아리스토텔레스의 시학에서 미메시스와 서양 드라마에 대한 그 유산을 검토했어요.', example_en_4 = 'The novel''s realism is grounded in a theory of mimesis.', example_ko_4 = '소설의 사실주의는 미메시스 이론에 근거해요.', example_en_5 = 'Does mimesis simply copy reality, or does it transform it?', example_ko_5 = '미메시스는 단순히 현실을 복사하는 건가요, 아니면 변형하는 건가요?' WHERE id = 'w_humanities_C1_08';

UPDATE words SET example_en_2 = 'The sublime in this landscape painting goes beyond mere beauty.', example_ko_2 = '이 풍경화의 숭고함은 단순한 아름다움을 넘어서요.', example_en_3 = 'Kant distinguished the beautiful from the sublime in his aesthetic theory.', example_ko_3 = '칸트는 미학 이론에서 아름다운 것과 숭고한 것을 구별했어요.', example_en_4 = 'She traces the concept of the sublime from Burke to contemporary ecocriticism.', example_ko_4 = '그녀는 버크에서 현대 생태비평까지 숭고 개념을 추적해요.', example_en_5 = 'The sublime is evoked when the speaker faces the vast ocean alone.', example_ko_5 = '화자가 드넓은 바다를 홀로 마주할 때 숭고함이 환기돼요.' WHERE id = 'w_humanities_C1_09';

UPDATE words SET example_en_2 = 'The essay ends in aporia, offering no resolution to its central question.', example_ko_2 = '에세이는 핵심 질문에 해결책을 제시하지 않고 아포리아로 끝나요.', example_en_3 = 'Deconstructive readings often locate aporia at the heart of canonical texts.', example_ko_3 = '해체주의적 독해는 종종 정전 텍스트의 핵심에서 아포리아를 찾아요.', example_en_4 = 'She argues that the novel''s ending is an intentional aporia.', example_ko_4 = '그녀는 소설의 결말이 의도적인 아포리아라고 주장해요.', example_en_5 = 'The concept of aporia reminds us that not all texts offer clear meaning.', example_ko_5 = '아포리아 개념은 모든 텍스트가 명확한 의미를 제공하지는 않는다는 것을 상기시켜줘요.' WHERE id = 'w_humanities_C1_10';

UPDATE words SET example_en_2 = 'Cultural hegemony works by making dominant values seem natural.', example_ko_2 = '문화적 헤게모니는 지배적 가치를 자연스럽게 보이게 함으로써 작동해요.', example_en_3 = 'She analyzed the hegemony of Western literary values in global publishing.', example_ko_3 = '그녀는 세계 출판에서 서양 문학 가치의 헤게모니를 분석했어요.', example_en_4 = 'The novel challenges the cultural hegemony of the colonizer.', example_ko_4 = '소설은 식민지배자의 문화적 헤게모니에 도전해요.', example_en_5 = 'Counter-hegemonic literature aims to give voice to marginalized perspectives.', example_ko_5 = '반헤게모니적 문학은 소외된 관점에 목소리를 주는 것을 목표로 해요.' WHERE id = 'w_humanities_C1_11';

UPDATE words SET example_en_2 = 'The novel''s ideology is revealed through what it leaves unsaid.', example_ko_2 = '소설의 이데올로기는 말하지 않은 것을 통해 드러나요.', example_en_3 = 'She reads the text against its dominant ideology.', example_ko_3 = '그녀는 지배적 이데올로기에 반하여 텍스트를 읽어요.', example_en_4 = 'All literary texts embed and reproduce a particular ideology.', example_ko_4 = '모든 문학 텍스트는 특정 이데올로기를 내장하고 재생산해요.', example_en_5 = 'Ideology is most powerful when it appears invisible.', example_ko_5 = '이데올로기는 보이지 않는 것처럼 보일 때 가장 강력해요.' WHERE id = 'w_humanities_C1_12';

UPDATE words SET example_en_2 = 'Foucault argued that discourse shapes what we can think and say.', example_ko_2 = '푸코는 담론이 우리가 생각하고 말할 수 있는 것을 형성한다고 주장했어요.', example_en_3 = 'The discourse of colonialism persists in unexpected ways in modern texts.', example_ko_3 = '식민주의 담론은 현대 텍스트에서 예상치 못한 방식으로 지속돼요.', example_en_4 = 'She analyzed the discourse of gender in nineteenth-century fiction.', example_ko_4 = '그녀는 19세기 소설에서 젠더의 담론을 분석했어요.', example_en_5 = 'Medical discourse and literary discourse intersect in this unusual novel.', example_ko_5 = '이 독특한 소설에서 의학 담론과 문학 담론이 교차해요.' WHERE id = 'w_humanities_C1_13';

UPDATE words SET example_en_2 = 'The polyphony of the text creates an effect of democratic pluralism.', example_ko_2 = '텍스트의 다성성은 민주적 다원주의의 효과를 만들어요.', example_en_3 = 'Bakhtin praised the polyphony of Dostoevsky over Tolstoy''s monologic style.', example_ko_3 = '바흐친은 톨스토이의 독자적 스타일보다 도스토옙스키의 다성성을 칭찬했어요.', example_en_4 = 'The polyphony of the novel resists a single authorial reading.', example_ko_4 = '소설의 다성성은 단일한 작가적 독해에 저항해요.', example_en_5 = 'She traced the polyphony of immigrant voices in contemporary American fiction.', example_ko_5 = '그녀는 현대 미국 소설에서 이민자 목소리의 다성성을 추적했어요.' WHERE id = 'w_humanities_C1_14';

UPDATE words SET example_en_2 = 'In metafiction, the narrator often acknowledges that the story is fiction.', example_ko_2 = '메타픽션에서 화자는 종종 이야기가 허구임을 인정해요.', example_en_3 = 'She analyzed how metafiction undermines realist conventions.', example_ko_3 = '그녀는 메타픽션이 어떻게 사실주의적 관습을 허무는지 분석했어요.', example_en_4 = 'Metafiction invites readers to question the nature of storytelling itself.', example_ko_4 = '메타픽션은 독자들이 이야기 자체의 본질을 의문시하도록 초대해요.', example_en_5 = 'The metafiction in this novel constantly reminds us we are reading a constructed text.', example_ko_5 = '이 소설의 메타픽션은 우리가 구성된 텍스트를 읽고 있다는 것을 계속 상기시켜줘요.' WHERE id = 'w_humanities_C1_15';

UPDATE words SET example_en_2 = 'Spivak asks whether the subaltern can truly represent themselves in dominant discourse.', example_ko_2 = '스피박은 서발턴이 지배적 담론에서 진정으로 자신을 대표할 수 있는지 물어요.', example_en_3 = 'She writes about the difficulty of giving voice to subaltern experience.', example_ko_3 = '그녀는 서발턴 경험에 목소리를 주는 것의 어려움에 대해 써요.', example_en_4 = 'The subaltern in this novel is denied a direct voice.', example_ko_4 = '이 소설의 서발턴은 직접적인 목소리를 빼앗겨요.', example_en_5 = 'Postcolonial studies often focuses on recovering the perspectives of the subaltern.', example_ko_5 = '포스트식민주의 연구는 종종 서발턴의 관점을 회복하는 데 집중해요.' WHERE id = 'w_humanities_C1_16';

UPDATE words SET example_en_2 = 'The canon reflects the power structures of the society that produced it.', example_ko_2 = '캐논은 그것을 만든 사회의 권력 구조를 반영해요.', example_en_3 = 'She argues for revising the canon to include more diverse voices.', example_ko_3 = '그녀는 더 다양한 목소리를 포함하기 위해 캐논을 수정해야 한다고 주장해요.', example_en_4 = 'The debate over the canon is also a debate about cultural authority.', example_ko_4 = '캐논에 관한 논쟁은 문화적 권위에 관한 논쟁이기도 해요.', example_en_5 = 'Including global literature in the canon changes how we read Western texts.', example_ko_5 = '세계 문학을 캐논에 포함시키면 서양 텍스트를 읽는 방식이 바뀌어요.' WHERE id = 'w_humanities_C1_17';

UPDATE words SET example_en_2 = 'Lévi-Strauss applied structuralism to the analysis of myth.', example_ko_2 = '레비-스트로스는 신화 분석에 구조주의를 적용했어요.', example_en_3 = 'Structuralism seeks the underlying rules that govern all narrative.', example_ko_3 = '구조주의는 모든 서사를 지배하는 기저 규칙을 찾으려 해요.', example_en_4 = 'She compared structuralism and poststructuralism in her seminar paper.', example_ko_4 = '그녀는 세미나 논문에서 구조주의와 포스트구조주의를 비교했어요.', example_en_5 = 'Structuralism assumes that meaning arises from differences within a system.', example_ko_5 = '구조주의는 의미가 시스템 내의 차이에서 발생한다고 가정해요.' WHERE id = 'w_humanities_C1_18';

UPDATE words SET example_en_2 = 'William Empson identified seven types of ambiguity in literary language.', example_ko_2 = '윌리엄 엠프슨은 문학 언어에서 일곱 가지 유형의 모호성을 찾아냈어요.', example_en_3 = 'The poem''s deliberate ambiguity opens it to multiple interpretations.', example_ko_3 = '시의 의도적인 모호성은 다양한 해석의 가능성을 열어요.', example_en_4 = 'She argues that the ambiguity of the ending is its greatest strength.', example_ko_4 = '그녀는 결말의 모호성이 그 가장 큰 강점이라고 주장해요.', example_en_5 = 'How does the author sustain ambiguity throughout the novel without losing the reader?', example_ko_5 = '작가는 독자를 잃지 않으면서 소설 전반에 걸쳐 어떻게 모호성을 유지하나요?' WHERE id = 'w_humanities_C1_19';

UPDATE words SET example_en_2 = 'The trickster is a well-worn trope across many cultural traditions.', example_ko_2 = '트릭스터는 많은 문화적 전통에 걸쳐 잘 알려진 트로프예요.', example_en_3 = 'She analyzed the trope of the fallen woman in Victorian fiction.', example_ko_3 = '그녀는 빅토리아 소설에서 타락한 여성의 트로프를 분석했어요.', example_en_4 = 'The author subverts the trope of the heroic quest.', example_ko_4 = '작가는 영웅적 탐구의 트로프를 전복시켜요.', example_en_5 = 'Tropes gain their power through repetition across texts and cultures.', example_ko_5 = '트로프는 텍스트와 문화에 걸친 반복을 통해 힘을 얻어요.' WHERE id = 'w_humanities_C1_20';

UPDATE words SET example_en_2 = 'Foucault''s episteme describes the hidden structure governing what counts as knowledge.', example_ko_2 = '푸코의 에피스테메는 무엇이 지식으로 여겨지는지를 지배하는 숨겨진 구조를 설명해요.', example_en_3 = 'She applied the concept of episteme to analyze shifts in critical theory.', example_ko_3 = '그녀는 비판 이론의 변화를 분석하기 위해 에피스테메 개념을 적용했어요.', example_en_4 = 'The novel itself becomes evidence of a particular historical episteme.', example_ko_4 = '소설 자체가 특정 역사적 에피스테메의 증거가 돼요.', example_en_5 = 'Understanding the episteme of an era helps explain why certain ideas were unthinkable.', example_ko_5 = '한 시대의 에피스테메를 이해하면 왜 특정 생각들이 생각할 수 없었는지 설명하는 데 도움이 돼요.' WHERE id = 'w_humanities_C1_21';

UPDATE words SET example_en_2 = 'Bakhtin''s concept of heteroglossia describes the dialogic nature of all language.', example_ko_2 = '바흐친의 헤테로글로시아 개념은 모든 언어의 대화적 본성을 설명해요.', example_en_3 = 'The novel embodies heteroglossia through its many competing narrative voices.', example_ko_3 = '소설은 경쟁하는 많은 서술 목소리를 통해 헤테로글로시아를 구현해요.', example_en_4 = 'She traced the heteroglossia of social class in nineteenth-century English fiction.', example_ko_4 = '그녀는 19세기 영국 소설에서 사회 계층의 헤테로글로시아를 추적했어요.', example_en_5 = 'Heteroglossia prevents any single voice from dominating the meaning of the text.', example_ko_5 = '헤테로글로시아는 어떤 단일 목소리도 텍스트의 의미를 지배하지 못하게 해요.' WHERE id = 'w_humanities_C1_22';

UPDATE words SET example_en_2 = 'Derrida''s critique of logocentrism challenges Western metaphysics.', example_ko_2 = '데리다의 로고스 중심주의 비판은 서양 형이상학에 도전해요.', example_en_3 = 'She analyzed the logocentrism embedded in the narrative structure of the novel.', example_ko_3 = '그녀는 소설의 서사 구조에 내재된 로고스 중심주의를 분석했어요.', example_en_4 = 'Logocentrism privileges rational speech over other forms of communication.', example_ko_4 = '로고스 중심주의는 다른 형태의 커뮤니케이션보다 이성적 언어를 특권화해요.', example_en_5 = 'Deconstructing logocentrism reveals the instability at the heart of Western thought.', example_ko_5 = '로고스 중심주의를 해체하면 서양 사상의 핵심에 있는 불안정성이 드러나요.' WHERE id = 'w_humanities_C1_23';

UPDATE words SET example_en_2 = 'The ontology of the fictional world differs from that of the real world.', example_ko_2 = '허구 세계의 존재론은 현실 세계의 것과 달라요.', example_en_3 = 'She explores ontology as it relates to questions of personal identity in the novel.', example_ko_3 = '그녀는 소설에서 개인적 정체성 문제와 관련하여 존재론을 탐구해요.', example_en_4 = 'The poem raises ontological questions about the nature of art itself.', example_ko_4 = '시는 예술 자체의 본질에 대한 존재론적 질문을 제기해요.', example_en_5 = 'Ontological uncertainty about what is real pervades this postmodern novel.', example_ko_5 = '무엇이 현실인지에 대한 존재론적 불확실성이 이 포스트모던 소설에 만연해요.' WHERE id = 'w_humanities_C1_24';

UPDATE words SET example_en_2 = 'The poem is deeply intertextual, weaving together references from multiple traditions.', example_ko_2 = '시는 여러 전통의 언급을 엮어 깊이 상호텍스트적이에요.', example_en_3 = 'She identified the intertextual relationship between the novel and a medieval text.', example_ko_3 = '그녀는 소설과 중세 텍스트 사이의 상호텍스트적 관계를 찾아냈어요.', example_en_4 = 'An intertextual reading of this poem reveals its debt to classical tradition.', example_ko_4 = '이 시에 대한 상호텍스트적 독해는 고전 전통에 대한 그 빚을 드러내요.', example_en_5 = 'The novel''s intertextual richness rewards readers with broad literary knowledge.', example_ko_5 = '소설의 상호텍스트적 풍부함은 폭넓은 문학 지식을 가진 독자들에게 보답해요.' WHERE id = 'w_humanities_C1_25';

UPDATE words SET example_en_2 = 'Ecocriticism asks how literature shapes our relationship with the natural world.', example_ko_2 = '생태비평은 문학이 우리와 자연 세계의 관계를 어떻게 형성하는지 물어요.', example_en_3 = 'She applied ecocriticism to analyze nature imagery in Romantic poetry.', example_ko_3 = '그녀는 낭만주의 시에서 자연 심상을 분석하기 위해 생태비평을 적용했어요.', example_en_4 = 'Ecocriticism has grown significantly as an approach since the environmental movement.', example_ko_4 = '생태비평은 환경 운동 이후 접근법으로서 상당히 성장했어요.', example_en_5 = 'She used ecocriticism to explore how place shapes identity in the novel.', example_ko_5 = '그녀는 소설에서 장소가 정체성을 어떻게 형성하는지 탐구하기 위해 생태비평을 사용했어요.' WHERE id = 'w_humanities_C1_26';

UPDATE words SET example_en_2 = 'Postcolonialism explores how colonial power shapes literary production.', example_ko_2 = '포스트식민주의는 식민지 권력이 어떻게 문학 생산을 형성하는지 탐구해요.', example_en_3 = 'She applies postcolonialism to analyze the representation of Africa in English novels.', example_ko_3 = '그녀는 영국 소설에서 아프리카의 표현을 분석하기 위해 포스트식민주의를 적용해요.', example_en_4 = 'Postcolonialism insists on hearing the voices that empire tried to silence.', example_ko_4 = '포스트식민주의는 제국이 침묵시키려 한 목소리를 듣는 데 고집해요.', example_en_5 = 'The field of postcolonialism was shaped by thinkers like Fanon, Said, and Bhabha.', example_ko_5 = '포스트식민주의 분야는 파농, 사이드, 바바 같은 사상가들에 의해 형성됐어요.' WHERE id = 'w_humanities_C1_27';

UPDATE words SET example_en_2 = 'A queer reading of the novel reveals subversive desires beneath its surface.', example_ko_2 = '소설에 대한 퀴어 독해는 표면 아래의 전복적 욕망을 드러내요.', example_en_3 = 'She introduced queer theory to her students through Judith Butler''s work.', example_ko_3 = '그녀는 주디스 버틀러의 작품을 통해 학생들에게 퀴어 이론을 소개했어요.', example_en_4 = 'Queer readings of Victorian fiction have transformed our understanding of the period.', example_ko_4 = '빅토리아 소설의 퀴어 독해는 그 시대에 대한 우리의 이해를 변화시켰어요.', example_en_5 = 'Queer theory challenges the naturalization of heterosexuality in canonical texts.', example_ko_5 = '퀴어 이론은 정전 텍스트에서 이성애의 자연화에 도전해요.' WHERE id = 'w_humanities_C1_28';

UPDATE words SET example_en_2 = 'Narratology distinguishes between the story and the way it is told.', example_ko_2 = '서사학은 이야기와 그것이 전달되는 방식을 구별해요.', example_en_3 = 'She studied narratology to better understand the techniques of modern fiction.', example_ko_3 = '그녀는 현대 소설의 기법을 더 잘 이해하기 위해 서사학을 공부했어요.', example_en_4 = 'Narratology provides a vocabulary for discussing how stories are structured.', example_ko_4 = '서사학은 이야기가 어떻게 구조화되는지 논의하기 위한 어휘를 제공해요.', example_en_5 = 'Applying narratology, she analyzed the sequence of events in the novel.', example_ko_5 = '서사학을 적용해 그녀는 소설의 사건 순서를 분석했어요.' WHERE id = 'w_humanities_C1_29';

UPDATE words SET example_en_2 = 'The lyric voice in this collection is intensely personal and confessional.', example_ko_2 = '이 시집의 서정적 목소리는 매우 개인적이고 고백적이에요.', example_en_3 = 'She analyzed how the lyric poem constructs an intimate relationship with the reader.', example_ko_3 = '그녀는 서정시가 독자와 친밀한 관계를 어떻게 구성하는지 분석했어요.', example_en_4 = 'The lyric tradition in Korean poetry has roots going back over a thousand years.', example_ko_4 = '한국 시의 서정 전통은 천 년이 넘는 뿌리를 가지고 있어요.', example_en_5 = 'In the lyric poem, time is compressed and emotion expanded.', example_ko_5 = '서정시에서 시간은 압축되고 감정은 확장돼요.' WHERE id = 'w_humanities_C1_30';

UPDATE words SET example_en_2 = 'The pathos of the scene is intensified by the simple, direct language.', example_ko_2 = '장면의 파토스는 단순하고 직접적인 언어에 의해 강화돼요.', example_en_3 = 'She analyzes how the author generates pathos without resorting to sentimentality.', example_ko_3 = '그녀는 작가가 감상성에 의존하지 않고 어떻게 파토스를 만들어내는지 분석해요.', example_en_4 = 'The pathos of the final letter moved readers across generations.', example_ko_4 = '마지막 편지의 파토스는 세대를 넘어 독자들을 감동시켰어요.', example_en_5 = 'Aristotle identified pathos as one of the three modes of rhetorical persuasion.', example_ko_5 = '아리스토텔레스는 파토스를 수사적 설득의 세 가지 방식 중 하나로 꼽았어요.' WHERE id = 'w_humanities_C1_31';

UPDATE words SET example_en_2 = 'The lacuna in the poem''s argument has puzzled critics for decades.', example_ko_2 = '시 논증의 공백은 수십 년간 비평가들을 혼란스럽게 했어요.', example_en_3 = 'She reads the lacuna as a deliberate strategic silence.', example_ko_3 = '그녀는 공백을 의도적인 전략적 침묵으로 읽어요.', example_en_4 = 'A textual lacuna can sometimes reveal as much as the text itself.', example_ko_4 = '텍스트적 공백은 때로 텍스트 자체만큼 많은 것을 드러낼 수 있어요.', example_en_5 = 'The historical lacuna in the archive shaped what stories could be told.', example_ko_5 = '기록물의 역사적 공백은 어떤 이야기를 할 수 있는지를 형성했어요.' WHERE id = 'w_humanities_C1_32';

UPDATE words SET example_en_2 = 'The Poetics of Aristotle remains the foundational text for drama theory.', example_ko_2 = '아리스토텔레스의 시학은 드라마 이론의 기초 텍스트로 남아 있어요.', example_en_3 = 'She developed her own poetics through years of writing and reflection.', example_ko_3 = '그녀는 수년간의 글쓰기와 성찰을 통해 자신만의 시학을 발전시켰어요.', example_en_4 = 'A poetics of space explores how physical settings shape literary experience.', example_ko_4 = '공간의 시학은 물리적 환경이 어떻게 문학적 경험을 형성하는지 탐구해요.', example_en_5 = 'Her poetics of silence is a major contribution to contemporary lyric theory.', example_ko_5 = '침묵의 시학은 현대 서정 이론에 대한 그녀의 주요 기여예요.' WHERE id = 'w_humanities_C1_33';

UPDATE words SET example_en_2 = 'Personal pronouns are a key form of deixis in lyric poetry.', example_ko_2 = '인칭 대명사는 서정시에서 직시 표현의 핵심 형태예요.', example_en_3 = 'She analyzed the function of spatial deixis in the dramatic monologue.', example_ko_3 = '그녀는 극적 독백에서 공간 직시의 기능을 분석했어요.', example_en_4 = 'Deixis roots a text in a particular time, place, and speaker.', example_ko_4 = '직시 표현은 텍스트를 특정 시간, 장소, 화자에 뿌리내리게 해요.', example_en_5 = 'The ambiguous deixis of the pronoun "we" raises questions of collective identity.', example_ko_5 = '"우리"라는 대명사의 모호한 직시 표현은 집단 정체성에 대한 질문을 제기해요.' WHERE id = 'w_humanities_C1_34';

UPDATE words SET example_en_2 = 'Ekphrasis transforms a visual work into language, making it available to readers.', example_ko_2 = '에크프라시스는 시각 작품을 언어로 변환하여 독자가 접근할 수 있게 해요.', example_en_3 = 'She wrote her dissertation on ekphrasis in contemporary American poetry.', example_ko_3 = '그녀는 현대 미국 시에서의 에크프라시스에 관한 논문을 썼어요.', example_en_4 = 'The ekphrasis in the novel describes a painting that becomes central to the plot.', example_ko_4 = '소설의 에크프라시스는 줄거리의 핵심이 되는 그림을 묘사해요.', example_en_5 = 'Ekphrasis raises questions about what language can and cannot capture.', example_ko_5 = '에크프라시스는 언어가 포착할 수 있는 것과 없는 것에 대한 질문을 제기해요.' WHERE id = 'w_humanities_C1_35';

-- ══════════════════════════════════════
-- C2 (최상급) — 35 words
-- ══════════════════════════════════════

UPDATE words SET example_en_2 = 'Logocentrism places the spoken word above writing as the source of truth.', example_ko_2 = '로고스 중심주의는 진리의 원천으로 문자보다 구어를 상위에 놓아요.', example_en_3 = 'She analyzed how logocentrism manifests in the structure of the canonical text.', example_ko_3 = '그녀는 로고스 중심주의가 정전 텍스트의 구조에서 어떻게 나타나는지 분석했어요.', example_en_4 = 'Deconstructing logocentrism reveals the suppressed role of writing in Western culture.', example_ko_4 = '로고스 중심주의를 해체하면 서양 문화에서 억압된 문자의 역할이 드러나요.', example_en_5 = 'Logocentrism, Derrida argues, cannot escape the very writing it tries to subordinate.', example_ko_5 = '데리다는 로고스 중심주의가 자신이 종속시키려는 바로 그 문자에서 벗어날 수 없다고 주장해요.' WHERE id = 'w_humanities_C2_01';

UPDATE words SET example_en_2 = 'Différance names the process by which meaning is always deferred and never fully present.', example_ko_2 = '디페랑스는 의미가 항상 유예되며 결코 완전히 현재에 있지 않은 과정을 명명해요.', example_en_3 = 'She traced the operation of différance in the ambiguous language of the poem.', example_ko_3 = '그녀는 시의 모호한 언어에서 디페랑스의 작동을 추적했어요.', example_en_4 = 'Différance shows that every sign refers only to other signs, never to a fixed presence.', example_ko_4 = '디페랑스는 모든 기호가 고정된 존재가 아닌 다른 기호만을 지시한다는 것을 보여줘요.', example_en_5 = 'Understanding différance requires accepting that language can never fully say what it means.', example_ko_5 = '디페랑스를 이해하려면 언어가 의미하는 것을 결코 완전히 말할 수 없다는 것을 받아들여야 해요.' WHERE id = 'w_humanities_C2_02';

UPDATE words SET example_en_2 = 'She reads the novel as a cultural palimpsest, tracing layers of colonial and indigenous history.', example_ko_2 = '그녀는 소설을 문화적 팔림프세스트로 읽으며, 식민지 및 토착 역사의 층위를 추적해요.', example_en_3 = 'The palimpsest metaphor captures the way past texts resurface in new writing.', example_ko_3 = '팔림프세스트 은유는 과거 텍스트가 새로운 글쓰기에서 어떻게 재등장하는지 포착해요.', example_en_4 = 'In archaeology and literature alike, the palimpsest reveals layered histories.', example_ko_4 = '고고학과 문학 모두에서 팔림프세스트는 층위로 된 역사들을 드러내요.', example_en_5 = 'The city in the novel functions as a palimpsest of forgotten voices and erased memories.', example_ko_5 = '소설의 도시는 잊혀진 목소리와 지워진 기억의 팔림프세스트로 기능해요.' WHERE id = 'w_humanities_C2_03';

UPDATE words SET example_en_2 = 'She analyzes postmodern bricolage as a strategy of cultural resistance.', example_ko_2 = '그녀는 포스트모던 브리콜라주를 문화적 저항의 전략으로 분석해요.', example_en_3 = 'The novel is a bricolage of myth, history, and popular culture.', example_ko_3 = '소설은 신화, 역사, 대중문화의 브리콜라주예요.', example_en_4 = 'Bricolage refuses the hierarchy between high art and everyday materials.', example_ko_4 = '브리콜라주는 고급 예술과 일상적 재료 사이의 위계를 거부해요.', example_en_5 = 'Lévi-Strauss first theorized bricolage in anthropology before it migrated to literary theory.', example_ko_5 = '레비-스트로스는 문학 이론으로 이전되기 전에 인류학에서 처음 브리콜라주를 이론화했어요.' WHERE id = 'w_humanities_C2_04';

UPDATE words SET example_en_2 = 'The heteroglossia of the market scene dramatizes the class divisions of the society.', example_ko_2 = '시장 장면의 헤테로글로시아는 사회의 계층 분열을 극화해요.', example_en_3 = 'She applied Bakhtin''s heteroglossia to examine the language politics of the novel.', example_ko_3 = '그녀는 소설의 언어 정치를 검토하기 위해 바흐친의 헤테로글로시아를 적용했어요.', example_en_4 = 'Heteroglossia ensures the novel resists ideological closure.', example_ko_4 = '헤테로글로시아는 소설이 이데올로기적 폐쇄에 저항하도록 보장해요.', example_en_5 = 'The heteroglossia of social media has become a new object of study for literary theorists.', example_ko_5 = '소셜 미디어의 헤테로글로시아는 문학 이론가들의 새로운 연구 대상이 됐어요.' WHERE id = 'w_humanities_C2_05';

UPDATE words SET example_en_2 = 'Bakhtin''s chronotope enables analysis of how genre shapes the experience of time.', example_ko_2 = '바흐친의 크로노토프는 장르가 시간 경험을 어떻게 형성하는지 분석할 수 있게 해줘요.', example_en_3 = 'She identified the castle chronotope as central to the Gothic novel.', example_ko_3 = '그녀는 성 크로노토프가 고딕 소설의 핵심이라고 밝혔어요.', example_en_4 = 'The chronotope of the prison creates a claustrophobic temporality in the novel.', example_ko_4 = '감옥의 크로노토프는 소설에서 폐쇄적 시간성을 만들어요.', example_en_5 = 'Analyzing the chronotope reveals how ideology is embedded in narrative form.', example_ko_5 = '크로노토프를 분석하면 이데올로기가 서사 형식에 어떻게 내재되어 있는지 드러나요.' WHERE id = 'w_humanities_C2_06';

UPDATE words SET example_en_2 = 'Shklovsky''s defamiliarization aims to restore the freshness of perception to language.', example_ko_2 = '슈클로프스키의 낯설게 하기는 언어에 지각의 신선함을 회복하는 것을 목표로 해요.', example_en_3 = 'She analyzes how Brecht''s alienation effect is a theatrical form of defamiliarization.', example_ko_3 = '그녀는 브레히트의 소외 효과가 낯설게 하기의 연극적 형태라고 분석해요.', example_en_4 = 'Defamiliarization forces readers to slow down and perceive the world anew.', example_ko_4 = '낯설게 하기는 독자들이 속도를 늦추고 세상을 새롭게 지각하도록 강제해요.', example_en_5 = 'She uses defamiliarization to argue that even the most familiar idioms carry hidden assumptions.', example_ko_5 = '그녀는 낯설게 하기를 사용하여 가장 친숙한 관용구도 숨겨진 가정을 담고 있다고 주장해요.' WHERE id = 'w_humanities_C2_07';

UPDATE words SET example_en_2 = 'Deleuze and Guattari''s rhizome challenges arboreal models of thought.', example_ko_2 = '들뢰즈와 가타리의 리좀은 수목형 사고 모델에 도전해요.', example_en_3 = 'She applies the rhizome concept to describe non-linear narrative structures.', example_ko_3 = '그녀는 비선형적 서사 구조를 설명하기 위해 리좀 개념을 적용해요.', example_en_4 = 'The rhizome, unlike the tree, has no beginning or end, only a middle.', example_ko_4 = '리좀은 나무와 달리 시작이나 끝이 없고 중간만 있어요.', example_en_5 = 'Reading the novel as rhizome opens multiple entry points into its meaning.', example_ko_5 = '소설을 리좀으로 읽으면 의미로의 다양한 진입 지점이 열려요.' WHERE id = 'w_humanities_C2_08';

UPDATE words SET example_en_2 = 'Hypertext fiction disrupts the traditional hierarchy between author and reader.', example_ko_2 = '하이퍼텍스트 소설은 작가와 독자 사이의 전통적 위계를 붕괴시켜요.', example_en_3 = 'She studied early hypertext fiction as a precursor to interactive digital narratives.', example_ko_3 = '그녀는 초기 하이퍼텍스트 소설을 인터랙티브 디지털 서사의 선구자로 연구했어요.', example_en_4 = 'The hypertext novel allows readers to determine the order of events.', example_ko_4 = '하이퍼텍스트 소설은 독자들이 사건의 순서를 결정할 수 있게 해줘요.', example_en_5 = 'The concept of hypertext challenges stable notions of the text as a bounded object.', example_ko_5 = '하이퍼텍스트 개념은 텍스트가 경계 있는 대상이라는 안정적인 개념에 도전해요.' WHERE id = 'w_humanities_C2_09';

UPDATE words SET example_en_2 = 'Each episteme, Foucault argues, makes certain statements possible and others unthinkable.', example_ko_2 = '푸코는 각 에피스테메가 특정 진술은 가능하게 하고 다른 것은 생각할 수 없게 만든다고 주장해요.', example_en_3 = 'She maps the shift in episteme from the Classical to the Modern in The Order of Things.', example_ko_3 = '그녀는 사물의 질서에서 고전에서 현대로의 에피스테메 전환을 그려요.', example_en_4 = 'The episteme of the Enlightenment privileged reason above all other forms of knowing.', example_ko_4 = '계몽주의의 에피스테메는 다른 모든 앎의 형식보다 이성을 특권화했어요.', example_en_5 = 'Our current episteme makes certain questions visible and renders others invisible.', example_ko_5 = '우리의 현재 에피스테메는 특정 질문들을 가시화하고 다른 것들은 보이지 않게 만들어요.' WHERE id = 'w_humanities_C2_10';

UPDATE words SET example_en_2 = 'She reads the monster in Gothic fiction as a figure of abjection.', example_ko_2 = '그녀는 고딕 소설의 괴물을 아브젝시옹의 형상으로 읽어요.', example_en_3 = 'Kristeva''s abjection describes the horror of the body''s instability.', example_ko_3 = '크리스테바의 아브젝시옹은 신체의 불안정성에 대한 공포를 설명해요.', example_en_4 = 'Abjection is located at the border between self and other, where identity becomes unstable.', example_ko_4 = '아브젝시옹은 정체성이 불안정해지는 자아와 타자의 경계에 위치해요.', example_en_5 = 'The novel exploits abjection to explore the fragility of national identity.', example_ko_5 = '소설은 민족 정체성의 취약성을 탐구하기 위해 아브젝시옹을 이용해요.' WHERE id = 'w_humanities_C2_11';

UPDATE words SET example_en_2 = 'She analyzes the pharmakon in Plato''s Phaedrus to challenge the opposition of speech and writing.', example_ko_2 = '그녀는 언어와 문자의 대립에 도전하기 위해 플라톤의 파이드로스에서 파르마콘을 분석해요.', example_en_3 = 'The pharmakon, as remedy and poison, resists the binary logic of Western philosophy.', example_ko_3 = '파르마콘은 치료제이자 독으로서 서양 철학의 이분법적 논리에 저항해요.', example_en_4 = 'Derrida uses the pharmakon to demonstrate the undecidability within Platonic philosophy.', example_ko_4 = '데리다는 플라톤 철학 내의 결정 불가능성을 보여주기 위해 파르마콘을 사용해요.', example_en_5 = 'The pharmakon concept opens up the possibility of reading Plato against himself.', example_ko_5 = '파르마콘 개념은 플라톤을 그 자신에 반하여 읽을 가능성을 열어줘요.' WHERE id = 'w_humanities_C2_12';

UPDATE words SET example_en_2 = 'She examines suture as the process by which ideology stitches subjects into position.', example_ko_2 = '그녀는 봉합을 이데올로기가 주체들을 위치에 꿰매는 과정으로 검토해요.', example_en_3 = 'The concept of suture was borrowed from Lacanian psychoanalysis.', example_ko_3 = '봉합 개념은 라캉의 정신분석학에서 빌려온 거예요.', example_en_4 = 'Suture describes how narratives interpellate readers as unified subjects.', example_ko_4 = '봉합은 서사가 독자들을 통합된 주체로 호명하는 방식을 설명해요.', example_en_5 = 'By analyzing the suture, she reveals how the text naturalizes a particular ideology.', example_ko_5 = '봉합을 분석함으로써 그녀는 텍스트가 특정 이데올로기를 자연화하는 방식을 드러내요.' WHERE id = 'w_humanities_C2_13';

UPDATE words SET example_en_2 = 'She warns that interpretive apophenia risks projecting meaning onto a resistant text.', example_ko_2 = '그녀는 해석적 아포페니아가 저항하는 텍스트에 의미를 투영할 위험이 있다고 경고해요.', example_en_3 = 'Apophenia in literary criticism occurs when readers over-interpret coincidental patterns.', example_ko_3 = '문학 비평의 아포페니아는 독자들이 우연한 패턴을 과잉 해석할 때 발생해요.', example_en_4 = 'She distinguishes between productive intertextual reading and apophenia.', example_ko_4 = '그녀는 생산적인 상호텍스트적 독해와 아포페니아를 구별해요.', example_en_5 = 'The charge of apophenia is sometimes used to silence unconventional readings.', example_ko_5 = '아포페니아의 비난은 때로 비관습적 독해를 침묵시키기 위해 사용돼요.' WHERE id = 'w_humanities_C2_14';

UPDATE words SET example_en_2 = 'The parataxis of Cormac McCarthy''s prose strips away subordinating logic.', example_ko_2 = '코맥 맥카시의 산문의 병렬 구문은 종속적 논리를 벗겨내요.', example_en_3 = 'She analyzed parataxis in biblical prose and its influence on English literature.', example_ko_3 = '그녀는 성경 산문의 병렬 구문과 영문학에 대한 그 영향을 분석했어요.', example_en_4 = 'Parataxis creates a sense of accumulation and urgency in the narrative.', example_ko_4 = '병렬 구문은 서사에서 축적과 긴박함의 감각을 만들어요.', example_en_5 = 'The switch from hypotaxis to parataxis marks a shift in the narrator''s emotional state.', example_ko_5 = '종속 구문에서 병렬 구문으로의 전환은 화자의 감정 상태 변화를 표시해요.' WHERE id = 'w_humanities_C2_15';

UPDATE words SET example_en_2 = 'She uses catachresis as a critical tool to expose the violence of colonial naming.', example_ko_2 = '그녀는 식민지 명명의 폭력을 드러내기 위한 비판적 도구로 카타크레시스를 사용해요.', example_en_3 = 'Catachresis occurs when a word is extended beyond its proper meaning.', example_ko_3 = '카타크레시스는 단어가 적절한 의미를 넘어 확장될 때 발생해요.', example_en_4 = 'In postcolonial theory, catachresis refers to the strategic appropriation of the master''s terms.', example_ko_4 = '포스트식민주의 이론에서 카타크레시스는 지배자의 용어를 전략적으로 전유하는 것을 말해요.', example_en_5 = 'The poet employs catachresis to create a startlingly unexpected metaphor.', example_ko_5 = '시인은 놀랍도록 예상치 못한 은유를 만들기 위해 카타크레시스를 사용해요.' WHERE id = 'w_humanities_C2_16';

UPDATE words SET example_en_2 = 'The opening paragraphs function as prolepsis, previewing the catastrophe to come.', example_ko_2 = '첫 단락들은 앞으로 올 재앙을 미리 보여주는 프롤렙시스로 기능해요.', example_en_3 = 'She analyzed prolepsis as a rhetorical device in political oratory.', example_ko_3 = '그녀는 정치적 웅변에서 수사적 장치로서의 프롤렙시스를 분석했어요.', example_en_4 = 'As a narrative technique, prolepsis creates dramatic irony and a sense of inevitability.', example_ko_4 = '서사 기법으로서 프롤렙시스는 극적 아이러니와 불가피성의 감각을 만들어요.', example_en_5 = 'The poet''s prolepsis addresses an audience not yet born.', example_ko_5 = '시인의 프롤렙시스는 아직 태어나지 않은 청중을 향해 말해요.' WHERE id = 'w_humanities_C2_17';

UPDATE words SET example_en_2 = 'She analyzed synecdoche to show how the part-for-whole relationship embeds ideology.', example_ko_2 = '그녀는 부분-전체 관계가 어떻게 이데올로기를 내재하는지 보여주기 위해 제유법을 분석했어요.', example_en_3 = 'The synecdoche of "the crown" for the monarchy condenses complex power into a single image.', example_ko_3 = '군주제를 나타내는 "왕관"의 제유법은 복잡한 권력을 하나의 이미지로 압축해요.', example_en_4 = 'Synecdoche works both as a local figure of speech and as a structural principle in narrative.', example_ko_4 = '제유법은 지역적 수사법으로도, 서사의 구조적 원리로도 작동해요.', example_en_5 = 'The poem''s synecdoche extends from an individual face to the whole of human suffering.', example_ko_5 = '시의 제유법은 한 개인의 얼굴에서 인류 전체의 고통으로 확장돼요.' WHERE id = 'w_humanities_C2_18';

UPDATE words SET example_en_2 = 'She distinguishes diegesis from mimesis in her analysis of narrative mode.', example_ko_2 = '그녀는 서사 양식 분석에서 디에게시스와 미메시스를 구별해요.', example_en_3 = 'The diegesis of the film expands to include a world the camera never shows us.', example_ko_3 = '영화의 디에게시스는 카메라가 결코 보여주지 않는 세계를 포함하도록 확장돼요.', example_en_4 = 'Genette''s theory of diegesis has been foundational for narratology.', example_ko_4 = '주네트의 디에게시스 이론은 서사학의 기초가 됐어요.', example_en_5 = 'The diegesis of the novel is interrupted when the narrator addresses the reader directly.', example_ko_5 = '소설의 디에게시스는 화자가 독자에게 직접 말할 때 중단돼요.' WHERE id = 'w_humanities_C2_19';

UPDATE words SET example_en_2 = 'The metalepsis of the final chapter collapses the boundary between fiction and reality.', example_ko_2 = '마지막 챕터의 메탈렙시스는 허구와 현실의 경계를 허물어요.', example_en_3 = 'She analyzes metalepsis as a self-conscious critique of narrative authority.', example_ko_3 = '그녀는 메탈렙시스를 서술 권위에 대한 자의식적 비판으로 분석해요.', example_en_4 = 'Metalepsis occurs when an author steps into the story to address the characters.', example_ko_4 = '메탈렙시스는 작가가 이야기 속으로 들어가 등장인물들에게 말할 때 발생해요.', example_en_5 = 'The metalepsis of the ending reveals the novel''s awareness of its own fictionality.', example_ko_5 = '결말의 메탈렙시스는 소설 자신의 허구성에 대한 인식을 드러내요.' WHERE id = 'w_humanities_C2_20';

UPDATE words SET example_en_2 = 'She argues that enargeia is not mere description but an act of imaginative re-creation.', example_ko_2 = '그녀는 에나르게이아가 단순한 묘사가 아니라 상상적 재창조 행위라고 주장해요.', example_en_3 = 'The enargeia of Homer''s battle descriptions sets the standard for vivid narration.', example_ko_3 = '호머의 전투 묘사의 에나르게이아는 생생한 서술의 기준을 설정해요.', example_en_4 = 'Rhetorical enargeia aims to make the listener see, not merely understand.', example_ko_4 = '수사적 에나르게이아는 청자가 단순히 이해하는 것이 아니라 보게 하는 것을 목표로 해요.', example_en_5 = 'The poet achieves enargeia through the accumulation of precise sensory details.', example_ko_5 = '시인은 정밀한 감각적 디테일의 축적을 통해 에나르게이아를 달성해요.' WHERE id = 'w_humanities_C2_21';

UPDATE words SET example_en_2 = 'Classical dispositio arranged speech into exordium, narratio, confirmatio, and peroratio.', example_ko_2 = '고전적 디스포지티오는 연설을 서론, 서술, 확인, 결론으로 배열했어요.', example_en_3 = 'She analyzes how the dispositio of the essay mirrors its argument about order.', example_ko_3 = '그녀는 에세이의 디스포지티오가 질서에 대한 그 주장을 어떻게 반영하는지 분석해요.', example_en_4 = 'A departure from classical dispositio signals the author''s ideological position.', example_ko_4 = '고전적 디스포지티오에서의 이탈은 작가의 이데올로기적 입장을 신호해요.', example_en_5 = 'The dispositio of the poem deliberately subverts the expectations of the ode form.', example_ko_5 = '시의 디스포지티오는 의도적으로 송시 형식의 기대를 전복해요.' WHERE id = 'w_humanities_C2_22';

UPDATE words SET example_en_2 = 'She traces the anagnorisis in the novel to a buried document discovered in the final chapter.', example_ko_2 = '그녀는 소설의 아나그노리시스가 마지막 챕터에서 발견된 매장된 문서로 이어진다고 추적해요.', example_en_3 = 'The anagnorisis is most powerful when the audience has anticipated it all along.', example_ko_3 = '아나그노리시스는 관객이 내내 예상해왔을 때 가장 강렬해요.', example_en_4 = 'Unlike simple surprise, anagnorisis involves a reversal of understanding.', example_ko_4 = '단순한 놀라움과 달리 아나그노리시스는 이해의 반전을 수반해요.', example_en_5 = 'The anagnorisis of the tragedy strikes the protagonist and audience simultaneously.', example_ko_5 = '비극의 아나그노리시스는 주인공과 관객을 동시에 강타해요.' WHERE id = 'w_humanities_C2_23';

UPDATE words SET example_en_2 = 'The peripeteia is prepared so carefully that it feels inevitable in retrospect.', example_ko_2 = '페리페테이아는 너무 신중하게 준비돼 있어서 회고해보면 불가피하게 느껴져요.', example_en_3 = 'She examines how peripeteia functions differently in comedy than in tragedy.', example_ko_3 = '그녀는 페리페테이아가 비극과 달리 희극에서 어떻게 다르게 기능하는지 검토해요.', example_en_4 = 'The peripeteia of the novel turns the hero from pursuer into the pursued.', example_ko_4 = '소설의 페리페테이아는 영웅을 추격자에서 추격당하는 자로 바꿔요.', example_en_5 = 'Aristotle considered peripeteia essential to the structure of the best tragedies.', example_ko_5 = '아리스토텔레스는 페리페테이아를 최고의 비극 구조에 필수적이라고 여겼어요.' WHERE id = 'w_humanities_C2_24';

UPDATE words SET example_en_2 = 'She argues that the deus ex machina reveals the ideological limits of the genre.', example_ko_2 = '그녀는 데우스 엑스 마키나가 장르의 이데올로기적 한계를 드러낸다고 주장해요.', example_en_3 = 'The deus ex machina was widely used in ancient Greek tragedy to resolve impossible situations.', example_ko_3 = '데우스 엑스 마키나는 불가능한 상황을 해결하기 위해 고대 그리스 비극에서 널리 사용됐어요.', example_en_4 = 'Modern readers tend to view deus ex machina as a sign of authorial failure.', example_ko_4 = '현대 독자들은 데우스 엑스 마키나를 작가적 실패의 신호로 보는 경향이 있어요.', example_en_5 = 'She rehabilitates the deus ex machina by showing how it functions ideologically.', example_ko_5 = '그녀는 데우스 엑스 마키나가 이데올로기적으로 어떻게 기능하는지 보여줌으로써 이를 재평가해요.' WHERE id = 'w_humanities_C2_25';

UPDATE words SET example_en_2 = 'The acousmatic narrator creates an uncanny sense of omnipresence.', example_ko_2 = '아쿠스마틱 화자는 편재의 섬뜩한 감각을 만들어요.', example_en_3 = 'She analyzed the acousmatic voice in radio drama and its literary equivalents.', example_ko_3 = '그녀는 라디오 드라마의 아쿠스마틱 목소리와 그것의 문학적 동등물을 분석했어요.', example_en_4 = 'The acousmatic voice in the novel never fully identifies itself.', example_ko_4 = '소설의 아쿠스마틱 목소리는 결코 완전히 자신을 밝히지 않아요.', example_en_5 = 'Chion''s concept of the acousmatic has migrated from film theory into narratology.', example_ko_5 = '숑의 아쿠스마틱 개념은 영화 이론에서 서사학으로 이전됐어요.' WHERE id = 'w_humanities_C2_26';

UPDATE words SET example_en_2 = 'Austin distinguishes locution from the intentions and effects attached to speech.', example_ko_2 = '오스틴은 발화 행위를 언어에 부착된 의도와 효과로부터 구별해요.', example_en_3 = 'She examines the locution of the court testimony to reveal its performative contradictions.', example_ko_3 = '그녀는 법정 증언의 발화 행위를 검토하여 수행적 모순을 드러내요.', example_en_4 = 'The locution of the promise is not enough; one must also intend to fulfill it.', example_ko_4 = '약속의 발화 행위만으로는 충분하지 않아요; 그것을 이행하려는 의도도 있어야 해요.', example_en_5 = 'Her analysis of locution foregrounds the gap between saying and meaning.', example_ko_5 = '발화 행위에 대한 그녀의 분석은 말하기와 의미하기 사이의 간극을 전면에 부각시켜요.' WHERE id = 'w_humanities_C2_27';

UPDATE words SET example_en_2 = 'She uses apophasis throughout the speech to suggest what she cannot safely say directly.', example_ko_2 = '그녀는 연설 전반에 걸쳐 직접 말하기 안전하지 않은 것을 암시하기 위해 아포파시스를 사용해요.', example_en_3 = 'Apophasis is particularly powerful in contexts of political censorship.', example_ko_3 = '아포파시스는 정치적 검열의 맥락에서 특히 강력해요.', example_en_4 = 'The poem''s apophasis builds tension by refusing to name what it circles around.', example_ko_4 = '시의 아포파시스는 그것이 맴도는 것을 명명하기를 거부함으로써 긴장감을 쌓아요.', example_en_5 = 'She analyzes apophasis as a strategy of silenced subjects speaking under constraint.', example_ko_5 = '그녀는 아포파시스를 제약 하에서 말하는 침묵된 주체들의 전략으로 분석해요.' WHERE id = 'w_humanities_C2_28';

UPDATE words SET example_en_2 = 'Her hypotaxis enacts the very complexity of thought it describes.', example_ko_2 = '그녀의 종속 구문은 그것이 묘사하는 사고의 복잡성을 그대로 수행해요.', example_en_3 = 'She compares the hypotaxis of Milton''s Paradise Lost to the parataxis of the King James Bible.', example_ko_3 = '그녀는 밀턴의 실낙원의 종속 구문을 흠정역 성경의 병렬 구문과 비교해요.', example_en_4 = 'Hypotaxis is the syntactic signature of classical rhetoric.', example_ko_4 = '종속 구문 배열은 고전 수사학의 통사적 특징이에요.', example_en_5 = 'The hypotaxis of the novel''s opening sentence signals an author who will not simplify.', example_ko_5 = '소설의 첫 문장 종속 구문 배열은 단순화하지 않을 작가를 신호해요.' WHERE id = 'w_humanities_C2_29';

UPDATE words SET example_en_2 = 'The cathartic power of the novel is felt long after the last page.', example_ko_2 = '소설의 카타르시스적 힘은 마지막 페이지를 넘긴 오랜 후에도 느껴져요.', example_en_3 = 'She analyzes how cathartic endings differ across cultural traditions.', example_ko_3 = '그녀는 문화적 전통에 따라 카타르시스적 결말이 어떻게 다른지 분석해요.', example_en_4 = 'The cathartic effect depends on the audience''s prior investment in the character.', example_ko_4 = '카타르시스적 효과는 관객의 사전 투자에 달려 있어요.', example_en_5 = 'She questions whether modern secular art can produce a truly cathartic experience.', example_ko_5 = '그녀는 현대 세속 예술이 진정으로 카타르시스적 경험을 만들 수 있는지 의문을 제기해요.' WHERE id = 'w_humanities_C2_30';

UPDATE words SET example_en_2 = 'She examines the anxious object status of the contemporary novel in a post-print world.', example_ko_2 = '그녀는 탈인쇄 세계에서 현대 소설의 불안한 대상 지위를 검토해요.', example_en_3 = 'The concept of the anxious object applies equally well to poetry and visual art.', example_ko_3 = '불안한 대상 개념은 시와 시각 예술에도 똑같이 잘 적용돼요.', example_en_4 = 'An anxious object is one that does not know if it deserves to be called art.', example_ko_4 = '불안한 대상은 예술이라고 불릴 자격이 있는지 스스로 모르는 것이에요.', example_en_5 = 'She reads the novel''s self-doubt as a mark of its status as an anxious object.', example_ko_5 = '그녀는 소설의 자기 의심을 불안한 대상으로서의 지위의 표시로 읽어요.' WHERE id = 'w_humanities_C2_31';

UPDATE words SET example_en_2 = 'The perlocution of the demagogue''s speech was to inflame the crowd.', example_ko_2 = '선동가 연설의 발화 효과는 군중을 자극하는 것이었어요.', example_en_3 = 'She distinguishes perlocution from illocution to show the unpredictability of language.', example_ko_3 = '그녀는 언어의 예측 불가능성을 보여주기 위해 발화 효과 행위를 발화 수반 행위와 구별해요.', example_en_4 = 'The perlocution of a poem cannot be controlled by the author.', example_ko_4 = '시의 발화 효과 행위는 작가에 의해 통제될 수 없어요.', example_en_5 = 'She analyzes perlocution to show how literature acts on readers beyond its stated meaning.', example_ko_5 = '그녀는 발화 효과 행위를 분석하여 문학이 명시된 의미를 넘어 독자에게 어떻게 작용하는지 보여줘요.' WHERE id = 'w_humanities_C2_32';

UPDATE words SET example_en_2 = 'She applies dialogism to argue that every text is a response to prior texts.', example_ko_2 = '그녀는 대화주의를 적용해 모든 텍스트가 이전 텍스트에 대한 응답이라고 주장해요.', example_en_3 = 'Bakhtin''s dialogism challenges the authority of the lone creative genius.', example_ko_3 = '바흐친의 대화주의는 고독한 창조적 천재의 권위에 도전해요.', example_en_4 = 'The dialogism of the novel is expressed through the clash of competing ideological voices.', example_ko_4 = '소설의 대화주의는 경쟁하는 이데올로기적 목소리들의 충돌을 통해 표현돼요.', example_en_5 = 'Dialogism implies that meaning emerges not from within a text but between texts.', example_ko_5 = '대화주의는 의미가 텍스트 안에서가 아니라 텍스트들 사이에서 나온다는 것을 함의해요.' WHERE id = 'w_humanities_C2_33';

UPDATE words SET example_en_2 = 'Keats believed negative capability separated the true poet from lesser versifiers.', example_ko_2 = '키츠는 부정적 수용 능력이 진정한 시인을 열등한 시인들과 구별한다고 믿었어요.', example_en_3 = 'She applies negative capability to argue for a more patient mode of literary criticism.', example_ko_3 = '그녀는 부정적 수용 능력을 적용해 더 인내 있는 문학 비평 방식을 주장해요.', example_en_4 = 'Negative capability asks us to resist premature closure in our reading of ambiguous texts.', example_ko_4 = '부정적 수용 능력은 모호한 텍스트 읽기에서 섣부른 종결에 저항할 것을 요구해요.', example_en_5 = 'The concept of negative capability has been extended beyond poetry to literary theory.', example_ko_5 = '부정적 수용 능력 개념은 시를 넘어 문학 이론으로 확장됐어요.' WHERE id = 'w_humanities_C2_34';

UPDATE words SET example_en_2 = 'Freud''s uncanny describes the anxiety caused by the return of the repressed.', example_ko_2 = '프로이트의 언캐니는 억압된 것의 귀환으로 인한 불안을 설명해요.', example_en_3 = 'She traces the uncanny through several Gothic short stories.', example_ko_3 = '그녀는 여러 고딕 단편 소설들을 통해 언캐니를 추적해요.', example_en_4 = 'The uncanny is located in the collapse of the distinction between animate and inanimate.', example_ko_4 = '언캐니는 생명체와 무생물 사이의 구분이 무너지는 데 위치해요.', example_en_5 = 'The uncanny effect of the novel depends on the reader''s own prior anxieties.', example_ko_5 = '소설의 언캐니 효과는 독자 자신의 사전 불안에 달려 있어요.' WHERE id = 'w_humanities_C2_35';

