UPDATE words SET example_en_2 = 'She uses her phone to check social media.', example_ko_2 = '그녀는 소셜 미디어를 확인하기 위해 스마트폰을 사용해요.', example_en_3 = 'My phone ran out of battery during the video call.', example_ko_3 = '영상 통화 중에 스마트폰 배터리가 없어졌어요.', example_en_4 = 'He left his phone at home by mistake.', example_ko_4 = '실수로 스마트폰을 집에 두고 왔어요.', example_en_5 = 'I always keep my phone on silent in class.', example_ko_5 = '수업 중에는 항상 스마트폰을 무음으로 해요.' WHERE id = 'w_media_A1_01';
UPDATE words SET example_en_2 = 'She watched a video about cooking on her phone.', example_ko_2 = '그녀는 스마트폰으로 요리 동영상을 봤어요.', example_en_3 = 'The video was very funny and went viral.', example_ko_3 = '그 동영상은 매우 재미있었고 바이럴됐어요.', example_en_4 = 'He recorded a short video of his dog.', example_ko_4 = '그는 강아지의 짧은 동영상을 찍었어요.', example_en_5 = 'We watched a travel video together last night.', example_ko_5 = '어젯밤에 함께 여행 동영상을 봤어요.' WHERE id = 'w_media_A1_02';
