UPDATE words SET example_en_2 = 'She reads the news every morning before work.', example_ko_2 = '그녀는 매일 아침 출근 전에 뉴스를 읽어요.', example_en_3 = 'The news about the storm spread quickly.', example_ko_3 = '태풍 관련 뉴스가 빠르게 퍼졌어요.', example_en_4 = 'He gets his news from a podcast.', example_ko_4 = '그는 팟캐스트를 통해 뉴스를 접해요.', example_en_5 = 'Breaking news appeared on every TV screen.', example_ko_5 = '모든 TV 화면에 속보가 나타났어요.' WHERE id = 'w_media_A1_04';
UPDATE words SET example_en_2 = 'She watched a movie on her tablet last night.', example_ko_2 = '그녀는 어젯밤에 태블릿으로 영화를 봤어요.', example_en_3 = 'He likes to watch cooking shows in the evening.', example_ko_3 = '그는 저녁에 요리 프로그램 보는 것을 좋아해요.', example_en_4 = 'We watched the game together on a big screen.', example_ko_4 = '큰 화면으로 함께 경기를 봤어요.', example_en_5 = 'She watches tutorials to learn new skills.', example_ko_5 = '그녀는 새로운 기술을 배우기 위해 튜토리얼을 봐요.' WHERE id = 'w_media_A1_05';
UPDATE words SET example_en_2 = 'She listens to music while exercising.', example_ko_2 = '그녀는 운동하면서 음악을 들어요.', example_en_3 = 'He likes to listen to podcasts on his commute.', example_ko_3 = '그는 출퇴근 중에 팟캐스트 듣는 것을 좋아해요.', example_en_4 = 'They listened to the live broadcast together.', example_ko_4 = '함께 생방송을 들었어요.', example_en_5 = 'You should listen to the instructions carefully.', example_ko_5 = '설명을 주의 깊게 들어야 해요.' WHERE id = 'w_media_A1_06';
UPDATE words SET example_en_2 = 'The screen of her phone cracked when it fell.', example_ko_2 = '스마트폰이 떨어지면서 화면이 깨졌어요.', example_en_3 = 'He increased the screen brightness to read outside.', example_ko_3 = '야외에서 읽기 위해 화면 밝기를 높였어요.', example_en_4 = 'The movie looks great on a big screen.', example_ko_4 = '큰 화면에서 보니 영화가 정말 멋있어요.', example_en_5 = 'She shares her screen during online meetings.', example_ko_5 = '온라인 회의 중에 화면을 공유해요.' WHERE id = 'w_media_A1_07';
UPDATE words SET example_en_2 = 'She sent a message to her friend on the app.', example_ko_2 = '그녀는 앱으로 친구에게 메시지를 보냈어요.', example_en_3 = 'He replied to her message right away.', example_ko_3 = '그는 그녀의 메시지에 바로 답장했어요.', example_en_4 = 'The message was too long to read on a small screen.', example_ko_4 = '메시지가 너무 길어서 작은 화면에서 읽기 어려웠어요.', example_en_5 = 'She left a message when he did not answer.', example_ko_5 = '그가 전화를 받지 않아서 메시지를 남겼어요.' WHERE id = 'w_media_A1_08';
UPDATE words SET example_en_2 = 'She missed the call because her phone was on silent.', example_ko_2 = '스마트폰이 무음 상태라 전화를 못 받았어요.', example_en_3 = 'He called her to say happy birthday.', example_ko_3 = '그는 생일 축하 인사를 하기 위해 전화를 걸었어요.', example_en_4 = 'They had a video call with their family.', example_ko_4 = '가족과 영상 통화를 했어요.', example_en_5 = 'The call dropped just when she started talking.', example_ko_5 = '그녀가 말을 시작하자마자 통화가 끊겼어요.' WHERE id = 'w_media_A1_09';
