UPDATE words SET example_en_2 = 'She uploaded a picture of her new room.', example_ko_2 = '그녀는 새 방 사진을 업로드했어요.', example_en_3 = 'The picture went viral after a famous account reposted it.', example_ko_3 = '유명 계정이 공유하면서 그 사진이 바이럴됐어요.', example_en_4 = 'He printed a picture from his phone.', example_ko_4 = '그는 스마트폰에서 사진을 출력했어요.', example_en_5 = 'She used the picture as her profile photo.', example_ko_5 = '그 사진을 프로필 사진으로 사용했어요.' WHERE id = 'w_media_A1_12';
