UPDATE words SET example_en_2 = 'The show has new episodes every Friday.', example_ko_2 = '그 프로그램은 매주 금요일에 새 에피소드가 나와요.', example_en_3 = 'She watches a cooking show to learn recipes.', example_ko_3 = '요리법을 배우기 위해 요리 프로그램을 봐요.', example_en_4 = 'The show went viral after the finale aired.', example_ko_4 = '최종화가 방영된 후 그 프로그램이 화제가 됐어요.', example_en_5 = 'He binged the entire show over the weekend.', example_ko_5 = '주말 동안 그 프로그램을 몰아봤어요.' WHERE id = 'w_media_A1_14';
UPDATE words SET example_en_2 = 'She texted her mom to say she arrived safely.', example_ko_2 = '그녀는 엄마에게 안전하게 도착했다는 문자를 보냈어요.', example_en_3 = 'He texts faster than he types on a keyboard.', example_ko_3 = '그는 키보드 타이핑보다 문자가 더 빨라요.', example_en_4 = 'She received a text about the package delivery.', example_ko_4 = '택배 배달에 대한 문자를 받았어요.', example_en_5 = 'He forgot to text back and she was worried.', example_ko_5 = '그가 답장을 깜빡해서 그녀가 걱정했어요.' WHERE id = 'w_media_A1_15';
