UPDATE words SET example_en_2 = 'The headline was clickbait and the article was disappointing.', example_ko_2 = '그 헤드라인은 낚시성이었고 기사 내용은 실망스러웠어요.', example_en_3 = 'She avoids websites that rely on clickbait.', example_ko_3 = '그녀는 낚시성 기사에 의존하는 웹사이트를 피해요.', example_en_4 = 'Clickbait titles often exaggerate the truth.', example_ko_4 = '낚시성 제목은 종종 진실을 과장해요.', example_en_5 = 'He learned not to click on obvious clickbait.', example_ko_5 = '그는 명백한 낚시성 기사를 클릭하지 않는 법을 배웠어요.' WHERE id = 'w_media_B2_03';
UPDATE words SET example_en_2 = 'The debate increased polarization between the two groups.', example_ko_2 = '그 논쟁은 두 집단 사이의 양극화를 심화시켰어요.', example_en_3 = 'She wrote about the political polarization in her country.', example_ko_3 = '그녀는 자국의 정치적 양극화에 대해 글을 썼어요.', example_en_4 = 'Media polarization makes it hard to find balanced news.', example_ko_4 = '미디어 양극화로 균형 잡힌 뉴스를 찾기가 어려워요.', example_en_5 = 'Reducing polarization requires listening to different viewpoints.', example_ko_5 = '양극화를 줄이려면 다양한 관점을 경청해야 해요.' WHERE id = 'w_media_B2_04';
