UPDATE words SET example_en_2 = 'Her post reached thousands of people overnight.', example_ko_2 = '그녀의 게시물이 하룻밤 사이에 수천 명에게 도달했어요.', example_en_3 = 'He paid for advertising to reach a larger audience.', example_ko_3 = '그는 더 많은 청중에게 도달하기 위해 광고비를 지불했어요.', example_en_4 = 'The campaign managed to reach voters in rural areas.', example_ko_4 = '그 캠페인은 농촌 지역의 유권자들에게 도달했어요.', example_en_5 = 'Good content naturally reaches more people.', example_ko_5 = '좋은 콘텐츠는 자연스럽게 더 많은 사람들에게 도달해요.' WHERE id = 'w_media_B2_10';
UPDATE words SET example_en_2 = 'She realized she was living in an echo chamber.', example_ko_2 = '그녀는 자신이 에코 챔버 안에 살고 있다는 것을 깨달았어요.', example_en_3 = 'He deliberately follows accounts with different opinions.', example_ko_3 = '그는 의도적으로 다른 의견을 가진 계정들을 팔로우해요.', example_en_4 = 'Echo chambers prevent people from seeing the full picture.', example_ko_4 = '에코 챔버는 사람들이 전체 그림을 보지 못하게 해요.', example_en_5 = 'Breaking out of the echo chamber can be eye-opening.', example_ko_5 = '에코 챔버에서 벗어나면 새로운 시각을 얻을 수 있어요.' WHERE id = 'w_media_B2_11';
UPDATE words SET example_en_2 = 'She tries to pop her filter bubble by reading different sources.', example_ko_2 = '그녀는 다양한 출처를 읽어 필터 버블을 깨려고 해요.', example_en_3 = 'The filter bubble made him unaware of opposing views.', example_ko_3 = '필터 버블 때문에 그는 반대 의견을 알지 못했어요.', example_en_4 = 'Algorithms create filter bubbles without users knowing.', example_ko_4 = '알고리즘은 사용자들이 모르는 사이에 필터 버블을 만들어요.', example_en_5 = 'Living in a filter bubble can distort your view of the world.', example_ko_5 = '필터 버블 안에서 살면 세상에 대한 시각이 왜곡될 수 있어요.' WHERE id = 'w_media_B2_12';
UPDATE words SET example_en_2 = 'She fact-checks every story before publishing.', example_ko_2 = '그녀는 발행하기 전에 모든 기사를 팩트체크해요.', example_en_3 = 'There are websites that fact-check viral claims.', example_ko_3 = '바이럴 주장을 팩트체크하는 웹사이트들이 있어요.', example_en_4 = 'He learned to fact-check news before sharing.', example_ko_4 = '그는 공유하기 전에 뉴스를 팩트체크하는 법을 배웠어요.', example_en_5 = 'Fact-checking takes more time but builds credibility.', example_ko_5 = '팩트체크는 시간이 더 걸리지만 신뢰성을 높여요.' WHERE id = 'w_media_B2_13';
UPDATE words SET example_en_2 = 'She taught her students the basics of media literacy.', example_ko_2 = '그녀는 학생들에게 미디어 리터러시의 기초를 가르쳤어요.', example_en_3 = 'Media literacy helps you spot fake news.', example_ko_3 = '미디어 리터러시는 가짜 뉴스를 발견하는 데 도움이 돼요.', example_en_4 = 'He improved his media literacy by taking an online course.', example_ko_4 = '그는 온라인 강좌를 수강해 미디어 리터러시를 향상시켰어요.', example_en_5 = 'Media literacy is a skill needed in the digital age.', example_ko_5 = '미디어 리터러시는 디지털 시대에 필요한 능력이에요.' WHERE id = 'w_media_B2_14';
UPDATE words SET example_en_2 = 'She discovered that algorithm bias affected her search results.', example_ko_2 = '그녀는 알고리즘 편향이 검색 결과에 영향을 미친다는 것을 발견했어요.', example_en_3 = 'Algorithm bias can unfairly limit whose content gets seen.', example_ko_3 = '알고리즘 편향은 불공평하게 누구의 콘텐츠가 보여지는지를 제한할 수 있어요.', example_en_4 = 'Researchers are working to reduce algorithm bias in AI.', example_ko_4 = '연구자들은 AI의 알고리즘 편향을 줄이기 위해 노력하고 있어요.', example_en_5 = 'He raised concerns about algorithm bias on the platform.', example_ko_5 = '그는 플랫폼의 알고리즘 편향에 대한 우려를 제기했어요.' WHERE id = 'w_media_B2_15';
UPDATE words SET example_en_2 = 'She built credibility by always citing her sources.', example_ko_2 = '그녀는 항상 출처를 인용해 신뢰성을 쌓았어요.', example_en_3 = 'A single mistake can damage a journalist''s credibility.', example_ko_3 = '한 번의 실수가 기자의 신뢰성을 손상시킬 수 있어요.', example_en_4 = 'He chose reliable sources to maintain his credibility.', example_ko_4 = '그는 신뢰성을 유지하기 위해 믿을 수 있는 출처를 선택했어요.', example_en_5 = 'Credibility is built over time through honest reporting.', example_ko_5 = '신뢰성은 정직한 보도를 통해 시간이 지나면서 쌓여요.' WHERE id = 'w_media_B2_16';
UPDATE words SET example_en_2 = 'She noticed a strong bias in the article''s tone.', example_ko_2 = '그녀는 기사의 톤에서 강한 편향을 발견했어요.', example_en_3 = 'Every journalist has some unconscious bias.', example_ko_3 = '모든 기자에게는 어느 정도 무의식적인 편향이 있어요.', example_en_4 = 'He tried to present the news without personal bias.', example_ko_4 = '그는 개인적 편향 없이 뉴스를 전달하려 했어요.', example_en_5 = 'Recognizing bias in media is an important skill.', example_ko_5 = '미디어의 편향을 인식하는 것은 중요한 능력이에요.' WHERE id = 'w_media_B2_17';
UPDATE words SET example_en_2 = 'She protested against internet censorship in her country.', example_ko_2 = '그녀는 자국의 인터넷 검열에 반대하는 시위에 참가했어요.', example_en_3 = 'Censorship of social media is controversial.', example_ko_3 = '소셜 미디어 검열은 논란이 많아요.', example_en_4 = 'He fled to another country to escape media censorship.', example_ko_4 = '그는 미디어 검열을 피해 다른 나라로 떠났어요.', example_en_5 = 'Censorship limits the flow of information in society.', example_ko_5 = '검열은 사회에서 정보의 흐름을 제한해요.' WHERE id = 'w_media_B2_18';
