UPDATE words SET example_en_2 = 'She partnered with a brand through influencer marketing.', example_ko_2 = '그녀는 인플루언서 마케팅을 통해 브랜드와 파트너십을 맺었어요.', example_en_3 = 'Influencer marketing reaches a more targeted audience.', example_ko_3 = '인플루언서 마케팅은 더 특정한 대상을 타깃으로 해요.', example_en_4 = 'He studied the ethics of influencer marketing in his class.', example_ko_4 = '그는 수업에서 인플루언서 마케팅의 윤리를 공부했어요.', example_en_5 = 'Influencer marketing has replaced traditional advertising for many brands.', example_ko_5 = '많은 브랜드에게 인플루언서 마케팅이 전통적인 광고를 대체했어요.' WHERE id = 'w_media_B2_20';
UPDATE words SET example_en_2 = 'She was shocked to see a deepfake of herself online.', example_ko_2 = '그녀는 온라인에서 자신의 딥페이크를 보고 충격받았어요.', example_en_3 = 'Deepfakes are becoming harder to detect.', example_ko_3 = '딥페이크를 탐지하는 것이 점점 더 어려워지고 있어요.', example_en_4 = 'He reported the deepfake video to the platform.', example_ko_4 = '그는 딥페이크 동영상을 플랫폼에 신고했어요.', example_en_5 = 'Technology to detect deepfakes is improving.', example_ko_5 = '딥페이크를 탐지하는 기술이 발전하고 있어요.' WHERE id = 'w_media_B2_21';
UPDATE words SET example_en_2 = 'She appreciated the transparency of the news outlet.', example_ko_2 = '그녀는 그 언론사의 투명성을 높이 평가했어요.', example_en_3 = 'More transparency in social media policies is needed.', example_ko_3 = '소셜 미디어 정책에서 더 많은 투명성이 필요해요.', example_en_4 = 'He called for greater transparency from the platform.', example_ko_4 = '그는 플랫폼에 더 높은 투명성을 요구했어요.', example_en_5 = 'Transparency builds trust between creators and their audience.', example_ko_5 = '투명성은 크리에이터와 청중 사이의 신뢰를 쌓아요.' WHERE id = 'w_media_B2_22';
UPDATE words SET example_en_2 = 'She improved her engagement rate by asking questions in posts.', example_ko_2 = '그녀는 게시물에 질문을 넣어 참여율을 높였어요.', example_en_3 = 'His engagement rate dropped after changing his content style.', example_ko_3 = '콘텐츠 스타일을 바꾼 후 참여율이 낮아졌어요.', example_en_4 = 'A high engagement rate shows that followers actively care.', example_ko_4 = '높은 참여율은 팔로워들이 적극적으로 관심을 가지고 있다는 것을 보여줘요.', example_en_5 = 'Brands look at engagement rate when choosing influencers.', example_ko_5 = '브랜드들은 인플루언서를 선택할 때 참여율을 봐요.' WHERE id = 'w_media_B2_23';
UPDATE words SET example_en_2 = 'She reported the harmful post and it was removed through content moderation.', example_ko_2 = '그녀는 유해한 게시물을 신고했고 콘텐츠 중재를 통해 삭제됐어요.', example_en_3 = 'Content moderation is a challenging job on large platforms.', example_ko_3 = '콘텐츠 중재는 대형 플랫폼에서 힘든 작업이에요.', example_en_4 = 'He thinks stricter content moderation would make the internet safer.', example_ko_4 = '그는 더 엄격한 콘텐츠 중재가 인터넷을 더 안전하게 만들 것이라 생각해요.', example_en_5 = 'AI is increasingly used to help with content moderation.', example_ko_5 = '콘텐츠 중재를 돕기 위해 AI가 점점 더 많이 활용되고 있어요.' WHERE id = 'w_media_B2_24';
UPDATE words SET example_en_2 = 'The video''s virality surprised everyone on the team.', example_ko_2 = '그 동영상의 바이럴성은 팀원 모두를 놀라게 했어요.', example_en_3 = 'She analyzed the virality of successful posts.', example_ko_3 = '그녀는 성공한 게시물들의 바이럴성을 분석했어요.', example_en_4 = 'Virality can bring both opportunities and unwanted attention.', example_ko_4 = '바이럴성은 기회와 원치 않는 관심을 동시에 가져올 수 있어요.', example_en_5 = 'Predicting virality is difficult even for experts.', example_ko_5 = '바이럴성을 예측하는 것은 전문가에게도 어려운 일이에요.' WHERE id = 'w_media_B2_25';
UPDATE words SET example_en_2 = 'She wrote an essay on the effects of cancel culture.', example_ko_2 = '그녀는 캔슬 컬처의 영향에 관한 에세이를 썼어요.', example_en_3 = 'The debate about cancel culture is ongoing online.', example_ko_3 = '캔슬 컬처에 대한 논쟁이 온라인에서 계속되고 있어요.', example_en_4 = 'He believes cancel culture sometimes goes too far.', example_ko_4 = '그는 캔슬 컬처가 때로는 지나치다고 생각해요.', example_en_5 = 'Cancel culture can have real consequences for careers.', example_ko_5 = '캔슬 컬처는 경력에 실질적인 결과를 가져올 수 있어요.' WHERE id = 'w_media_B2_26';
UPDATE words SET example_en_2 = 'She enabled comment moderation to keep her space safe.', example_ko_2 = '그녀는 자신의 공간을 안전하게 유지하기 위해 댓글 관리를 활성화했어요.', example_en_3 = 'Comment moderation helped reduce harassment on the page.', example_ko_3 = '댓글 관리는 페이지의 괴롭힘을 줄이는 데 도움이 됐어요.', example_en_4 = 'He reviewed all comments manually through strict moderation.', example_ko_4 = '그는 엄격한 중재를 통해 모든 댓글을 직접 검토했어요.', example_en_5 = 'Good comment moderation creates a positive community.', example_ko_5 = '좋은 댓글 관리는 긍정적인 커뮤니티를 만들어요.' WHERE id = 'w_media_B2_27';
UPDATE words SET example_en_2 = 'Our social media feeds are now entirely algorithm-driven.', example_ko_2 = '우리의 소셜 미디어 피드는 이제 완전히 알고리즘 기반이에요.', example_en_3 = 'She prefers curated content over algorithm-driven recommendations.', example_ko_3 = '그녀는 알고리즘 기반 추천보다 직접 큐레이션된 콘텐츠를 선호해요.', example_en_4 = 'The algorithm-driven system sometimes shows irrelevant content.', example_ko_4 = '알고리즘 기반 시스템이 때로는 관련 없는 콘텐츠를 보여줘요.', example_en_5 = 'An algorithm-driven approach personalizes the user experience.', example_ko_5 = '알고리즘 기반 접근 방식은 사용자 경험을 개인화해요.' WHERE id = 'w_media_B2_28';
UPDATE words SET example_en_2 = 'She noticed that the story faded after the news cycle moved on.', example_ko_2 = '그녀는 뉴스 사이클이 이동하면서 그 이야기가 사라지는 것을 알아챘어요.', example_en_3 = 'The fast news cycle makes it hard to fact-check everything.', example_ko_3 = '빠른 뉴스 사이클은 모든 것을 팩트체크하기 어렵게 만들어요.', example_en_4 = 'He waited for the news cycle to calm before commenting.', example_ko_4 = '그는 댓글을 달기 전에 뉴스 사이클이 잠잠해지기를 기다렸어요.', example_en_5 = 'Short-form content thrives in the modern news cycle.', example_ko_5 = '짧은 형식의 콘텐츠는 현대의 뉴스 사이클에서 잘 어울려요.' WHERE id = 'w_media_B2_29';
UPDATE words SET example_en_2 = 'She built her career within the platform economy.', example_ko_2 = '그녀는 플랫폼 경제 안에서 자신의 경력을 쌓았어요.', example_en_3 = 'The platform economy has created new types of jobs.', example_ko_3 = '플랫폼 경제는 새로운 종류의 직업을 만들어냈어요.', example_en_4 = 'He studied how the platform economy affects small businesses.', example_ko_4 = '그는 플랫폼 경제가 소규모 사업에 미치는 영향을 연구했어요.', example_en_5 = 'The platform economy continues to grow rapidly worldwide.', example_ko_5 = '플랫폼 경제는 전 세계적으로 빠르게 성장하고 있어요.' WHERE id = 'w_media_B2_30';
UPDATE words SET example_en_2 = 'She read the privacy policy to understand how her data is used.', example_ko_2 = '그녀는 자신의 데이터가 어떻게 사용되는지 이해하기 위해 개인정보 정책을 읽었어요.', example_en_3 = 'Data privacy laws vary greatly between countries.', example_ko_3 = '데이터 프라이버시 법은 국가마다 크게 달라요.', example_en_4 = 'He changed his settings to improve his data privacy.', example_ko_4 = '그는 데이터 프라이버시를 개선하기 위해 설정을 변경했어요.', example_en_5 = 'Data privacy is a growing concern for digital users.', example_ko_5 = '데이터 프라이버시는 디지털 사용자들에게 점점 더 중요한 문제가 되고 있어요.' WHERE id = 'w_media_B2_31';
UPDATE words SET example_en_2 = 'She criticized the sensationalism in the headline.', example_ko_2 = '그녀는 헤드라인의 선정주의를 비판했어요.', example_en_3 = 'Sensationalism attracts clicks but damages trust in media.', example_ko_3 = '선정주의는 클릭을 유도하지만 미디어에 대한 신뢰를 해쳐요.', example_en_4 = 'He avoided sensationalism when writing his article.', example_ko_4 = '그는 기사를 쓸 때 선정주의를 피했어요.', example_en_5 = 'Good journalism avoids sensationalism and focuses on facts.', example_ko_5 = '좋은 저널리즘은 선정주의를 피하고 사실에 집중해요.' WHERE id = 'w_media_B2_32';
UPDATE words SET example_en_2 = 'She surveys public opinion for her research project.', example_ko_2 = '그녀는 연구 프로젝트를 위해 여론 조사를 해요.', example_en_3 = 'Public opinion shifted after the documentary was released.', example_ko_3 = '다큐멘터리가 공개된 후 여론이 바뀌었어요.', example_en_4 = 'He believes the media has too much influence over public opinion.', example_ko_4 = '그는 미디어가 여론에 너무 많은 영향을 미친다고 생각해요.', example_en_5 = 'Social media can shift public opinion very quickly.', example_ko_5 = '소셜 미디어는 여론을 매우 빠르게 바꿀 수 있어요.' WHERE id = 'w_media_B2_33';
UPDATE words SET example_en_2 = 'She wrote an editorial criticizing the new policy.', example_ko_2 = '그녀는 새 정책을 비판하는 사설을 썼어요.', example_en_3 = 'The editorial expressed the newspaper''s official position.', example_ko_3 = '그 사설은 신문사의 공식 입장을 표현했어요.', example_en_4 = 'He read the editorial to understand the paper''s perspective.', example_ko_4 = '그는 신문의 관점을 이해하기 위해 사설을 읽었어요.', example_en_5 = 'A well-written editorial can influence public debate.', example_ko_5 = '잘 쓰인 사설은 공개 토론에 영향을 미칠 수 있어요.' WHERE id = 'w_media_B2_34';
UPDATE words SET example_en_2 = 'She joined a protest to defend press freedom.', example_ko_2 = '그녀는 언론의 자유를 지키기 위한 시위에 참가했어요.', example_en_3 = 'Press freedom rankings show which countries support journalists.', example_ko_3 = '언론의 자유 순위는 어떤 국가가 기자들을 지지하는지 보여줘요.', example_en_4 = 'He documented the dangers faced by journalists where press freedom is limited.', example_ko_4 = '그는 언론의 자유가 제한된 곳에서 기자들이 직면하는 위험을 기록했어요.', example_en_5 = 'Protecting press freedom is essential for a healthy democracy.', example_ko_5 = '언론의 자유를 보호하는 것은 건강한 민주주의에 필수적이에요.' WHERE id = 'w_media_B2_35';

