UPDATE words SET example_en_2 = 'She developed a curriculum to teach media literacy to teenagers.', example_ko_2 = '그녀는 청소년에게 미디어 리터러시를 가르치기 위한 교육 과정을 개발했어요.', example_en_3 = 'Media literacy goes beyond just reading—it includes critical evaluation.', example_ko_3 = '미디어 리터러시는 단순히 읽는 것을 넘어 비판적 평가를 포함해요.', example_en_4 = 'He argues that media literacy should be compulsory in schools.', example_ko_4 = '그는 미디어 리터러시가 학교에서 필수 과목이 되어야 한다고 주장해요.', example_en_5 = 'Advanced media literacy allows people to analyze framing and bias.', example_ko_5 = '높은 수준의 미디어 리터러시는 프레이밍과 편향을 분석할 수 있게 해줘요.' WHERE id = 'w_media_C1_01';
UPDATE words SET example_en_2 = 'She studied how wartime propaganda shaped public sentiment.', example_ko_2 = '그녀는 전시 선전이 여론을 어떻게 형성했는지 연구했어요.', example_en_3 = 'Propaganda uses emotional language to bypass rational thinking.', example_ko_3 = '선전은 감정적인 언어를 사용해 이성적 사고를 우회해요.', example_en_4 = 'He analyzed historical propaganda posters for his thesis.', example_ko_4 = '그는 논문을 위해 역사적인 선전 포스터를 분석했어요.', example_en_5 = 'Recognizing propaganda helps protect against manipulation.', example_ko_5 = '선전을 인식하면 조작에 대한 저항력을 키울 수 있어요.' WHERE id = 'w_media_C1_02';
UPDATE words SET example_en_2 = 'She raised concerns about the surveillance of journalists.', example_ko_2 = '그녀는 기자들에 대한 감시에 우려를 표했어요.', example_en_3 = 'Digital surveillance has expanded dramatically in the last decade.', example_ko_3 = '디지털 감시는 지난 10년 동안 크게 확대됐어요.', example_en_4 = 'He researched the ethics of government surveillance.', example_ko_4 = '그는 정부 감시의 윤리를 연구했어요.', example_en_5 = 'Surveillance capitalism profits from monitoring user behavior.', example_ko_5 = '감시 자본주의는 사용자 행동을 모니터링해 이익을 창출해요.' WHERE id = 'w_media_C1_03';
UPDATE words SET example_en_2 = 'She investigated how censorship silences marginalized voices.', example_ko_2 = '그녀는 검열이 소외된 목소리를 어떻게 침묵시키는지 조사했어요.', example_en_3 = 'Internet censorship blocks access to information in some regions.', example_ko_3 = '인터넷 검열은 일부 지역에서 정보 접근을 차단해요.', example_en_4 = 'He wrote about the historical role of censorship in media.', example_ko_4 = '그는 미디어에서 검열의 역사적 역할에 대해 글을 썼어요.', example_en_5 = 'Fighting censorship is central to press freedom movements.', example_ko_5 = '검열에 맞서는 것은 언론 자유 운동의 핵심이에요.' WHERE id = 'w_media_C1_04';
UPDATE words SET example_en_2 = 'She explored the epistemology behind how we trust news sources.', example_ko_2 = '그녀는 뉴스 소스를 신뢰하는 방식의 바탕이 되는 인식론을 탐구했어요.', example_en_3 = 'Epistemology asks how we know what we know.', example_ko_3 = '인식론은 우리가 아는 것을 어떻게 아는지를 묻는 학문이에요.', example_en_4 = 'He applied epistemology to question the reliability of media claims.', example_ko_4 = '그는 미디어 주장의 신뢰성에 의문을 제기하는 데 인식론을 적용했어요.', example_en_5 = 'Digital media has created new epistemological challenges.', example_ko_5 = '디지털 미디어는 새로운 인식론적 도전을 만들어냈어요.' WHERE id = 'w_media_C1_05';
UPDATE words SET example_en_2 = 'She analyzed the dominant discourse in climate change reporting.', example_ko_2 = '그녀는 기후 변화 보도에서 지배적인 담론을 분석했어요.', example_en_3 = 'Media discourse shapes how we think about social issues.', example_ko_3 = '미디어 담론은 우리가 사회적 문제를 생각하는 방식을 형성해요.', example_en_4 = 'He traced how the discourse around immigration has shifted.', example_ko_4 = '그는 이민에 관한 담론이 어떻게 변화했는지를 추적했어요.', example_en_5 = 'Changing the discourse requires consistent effort and visibility.', example_ko_5 = '담론을 바꾸려면 지속적인 노력과 가시성이 필요해요.' WHERE id = 'w_media_C1_06';
UPDATE words SET example_en_2 = 'She argued that media hegemony reinforces dominant power structures.', example_ko_2 = '그녀는 미디어 헤게모니가 지배적인 권력 구조를 강화한다고 주장했어요.', example_en_3 = 'Cultural hegemony is maintained partly through media narratives.', example_ko_3 = '문화적 헤게모니는 부분적으로 미디어 서사를 통해 유지돼요.', example_en_4 = 'He studied how Western media hegemony affects global storytelling.', example_ko_4 = '그는 서구 미디어 헤게모니가 전 세계 스토리텔링에 미치는 영향을 연구했어요.', example_en_5 = 'Challenging media hegemony involves amplifying diverse voices.', example_ko_5 = '미디어 헤게모니에 도전하는 것은 다양한 목소리를 높이는 것을 포함해요.' WHERE id = 'w_media_C1_07';
UPDATE words SET example_en_2 = 'She wrote about how editors perform a gatekeeping role.', example_ko_2 = '그녀는 편집자들이 게이트키핑 역할을 수행하는 방법에 대해 썼어요.', example_en_3 = 'Social media has disrupted traditional gatekeeping in journalism.', example_ko_3 = '소셜 미디어는 저널리즘에서의 전통적인 게이트키핑을 방해했어요.', example_en_4 = 'He criticized the gatekeeping that excluded minority voices.', example_ko_4 = '그는 소수자의 목소리를 배제하는 게이트키핑을 비판했어요.', example_en_5 = 'Gatekeeping determines what stories reach the public.', example_ko_5 = '게이트키핑은 어떤 이야기가 대중에게 전달되는지를 결정해요.' WHERE id = 'w_media_C1_08';
UPDATE words SET example_en_2 = 'She explained how framing influences public perception of events.', example_ko_2 = '그녀는 프레이밍이 사건에 대한 대중의 인식에 어떤 영향을 미치는지 설명했어요.', example_en_3 = 'The framing of a headline can completely change its meaning.', example_ko_3 = '헤드라인의 프레이밍은 의미를 완전히 바꿀 수 있어요.', example_en_4 = 'He analyzed the framing of immigration in two newspapers.', example_ko_4 = '그는 두 신문의 이민 관련 기사에서 프레이밍을 분석했어요.', example_en_5 = 'Critical readers can identify the framing behind news stories.', example_ko_5 = '비판적인 독자는 뉴스 이야기 뒤의 프레이밍을 파악할 수 있어요.' WHERE id = 'w_media_C1_09';
UPDATE words SET example_en_2 = 'She studied the agenda-setting power of major news networks.', example_ko_2 = '그녀는 주요 뉴스 네트워크의 의제 설정 권력을 연구했어요.', example_en_3 = 'Agenda-setting theory says the media tells us what to think about.', example_ko_3 = '의제 설정 이론은 미디어가 무엇을 생각해야 하는지 알려준다고 해요.', example_en_4 = 'He explored how social media has changed agenda-setting dynamics.', example_ko_4 = '그는 소셜 미디어가 의제 설정 역학을 어떻게 변화시켰는지 탐구했어요.', example_en_5 = 'Agenda-setting shapes public priorities without people realizing it.', example_ko_5 = '의제 설정은 사람들이 깨닫지 못하는 사이에 대중의 우선순위를 형성해요.' WHERE id = 'w_media_C1_10';
UPDATE words SET example_en_2 = 'She referenced Chomsky''s concept of manufactured consent in her essay.', example_ko_2 = '그녀는 에세이에서 촘스키의 ''제조된 동의'' 개념을 언급했어요.', example_en_3 = 'Manufactured consent suggests that public opinion can be engineered.', example_ko_3 = '''제조된 동의''는 여론을 조작할 수 있다고 시사해요.', example_en_4 = 'He explored how advertising contributes to manufactured consent.', example_ko_4 = '그는 광고가 어떻게 ''제조된 동의''에 기여하는지 탐구했어요.', example_en_5 = 'Recognizing manufactured consent requires media literacy skills.', example_ko_5 = '''제조된 동의''를 인식하려면 미디어 리터러시 능력이 필요해요.' WHERE id = 'w_media_C1_11';
UPDATE words SET example_en_2 = 'She reported on how disinformation warfare is used geopolitically.', example_ko_2 = '그녀는 허위 정보 전쟁이 지정학적으로 어떻게 사용되는지를 보도했어요.', example_en_3 = 'Disinformation warfare targets elections and public trust.', example_ko_3 = '허위 정보 전쟁은 선거와 대중의 신뢰를 타깃으로 해요.', example_en_4 = 'He studied how countries defend against disinformation warfare.', example_ko_4 = '그는 국가들이 어떻게 허위 정보 전쟁에 대응하는지를 연구했어요.', example_en_5 = 'Identifying disinformation warfare requires advanced media skills.', example_ko_5 = '허위 정보 전쟁을 식별하려면 고급 미디어 능력이 필요해요.' WHERE id = 'w_media_C1_12';
UPDATE words SET example_en_2 = 'She advocates for participatory media to give communities a voice.', example_ko_2 = '그녀는 커뮤니티에 목소리를 주기 위해 참여형 미디어를 지지해요.', example_en_3 = 'Blogs and podcasts are popular forms of participatory media.', example_ko_3 = '블로그와 팟캐스트는 참여형 미디어의 대표적인 형태예요.', example_en_4 = 'He studied how participatory media empowers underrepresented groups.', example_ko_4 = '그는 참여형 미디어가 과소 대표된 집단에 힘을 주는 방법을 연구했어요.', example_en_5 = 'Participatory media shifts the role of the audience to co-creator.', example_ko_5 = '참여형 미디어는 청중의 역할을 공동 창작자로 바꿔요.' WHERE id = 'w_media_C1_13';
UPDATE words SET example_en_2 = 'She warned about the dangers of algorithmic amplification of hate speech.', example_ko_2 = '그녀는 혐오 발언의 알고리즘 증폭 위험에 대해 경고했어요.', example_en_3 = 'Algorithmic amplification can spread controversial content rapidly.', example_ko_3 = '알고리즘 증폭은 논란이 되는 콘텐츠를 빠르게 확산시킬 수 있어요.', example_en_4 = 'He studied how algorithmic amplification affects public discourse.', example_ko_4 = '그는 알고리즘 증폭이 공공 담론에 어떤 영향을 미치는지 연구했어요.', example_en_5 = 'Reducing harmful algorithmic amplification is a key policy challenge.', example_ko_5 = '유해한 알고리즘 증폭을 줄이는 것은 핵심 정책 과제예요.' WHERE id = 'w_media_C1_14';
UPDATE words SET example_en_2 = 'She explained how media convergence blends print, digital, and broadcast.', example_ko_2 = '그녀는 미디어 융합이 인쇄, 디지털, 방송을 어떻게 결합하는지 설명했어요.', example_en_3 = 'Media convergence has created new opportunities for storytelling.', example_ko_3 = '미디어 융합은 스토리텔링에 새로운 기회를 만들었어요.', example_en_4 = 'He studied the business impact of media convergence.', example_ko_4 = '그는 미디어 융합의 사업적 영향을 연구했어요.', example_en_5 = 'Media convergence means one story can appear across many platforms.', example_ko_5 = '미디어 융합은 하나의 이야기가 여러 플랫폼에 걸쳐 나타날 수 있다는 것을 의미해요.' WHERE id = 'w_media_C1_15';
UPDATE words SET example_en_2 = 'She tracked the spread of the infodemic alongside the pandemic.', example_ko_2 = '그녀는 전염병과 함께 인포데믹의 확산을 추적했어요.', example_en_3 = 'An infodemic can be as dangerous as a disease itself.', example_ko_3 = '인포데믹은 질병 그 자체만큼 위험할 수 있어요.', example_en_4 = 'He worked to counter the infodemic by sharing verified facts.', example_ko_4 = '그는 검증된 사실을 공유해 인포데믹에 대응했어요.', example_en_5 = 'Managing an infodemic requires coordinated global communication.', example_ko_5 = '인포데믹을 관리하려면 전 세계적으로 조율된 소통이 필요해요.' WHERE id = 'w_media_C1_16';
UPDATE words SET example_en_2 = 'She argued for stronger international platform governance standards.', example_ko_2 = '그녀는 더 강력한 국제적 플랫폼 거버넌스 기준을 주장했어요.', example_en_3 = 'Platform governance determines the rules for content and behavior.', example_ko_3 = '플랫폼 거버넌스는 콘텐츠와 행동에 대한 규칙을 정해요.', example_en_4 = 'He criticized the lack of transparency in platform governance decisions.', example_ko_4 = '그는 플랫폼 거버넌스 결정의 투명성 부족을 비판했어요.', example_en_5 = 'Effective platform governance balances freedom with safety.', example_ko_5 = '효과적인 플랫폼 거버넌스는 자유와 안전을 균형 있게 유지해요.' WHERE id = 'w_media_C1_17';
UPDATE words SET example_en_2 = 'She analyzed how entertainment exports are a form of soft power.', example_ko_2 = '그녀는 엔터테인먼트 수출이 소프트 파워의 한 형태라고 분석했어요.', example_en_3 = 'Soft power influences through culture rather than force.', example_ko_3 = '소프트 파워는 힘이 아닌 문화를 통해 영향력을 행사해요.', example_en_4 = 'He explored how media companies project national soft power globally.', example_ko_4 = '그는 미디어 기업들이 어떻게 국가 소프트 파워를 전 세계적으로 투사하는지 탐구했어요.', example_en_5 = 'K-pop is often cited as a major example of cultural soft power.', example_ko_5 = 'K-pop은 종종 문화적 소프트 파워의 주요 사례로 언급돼요.' WHERE id = 'w_media_C1_18';
UPDATE words SET example_en_2 = 'She wrote about how the attention economy rewards outrage.', example_ko_2 = '그녀는 주의 경제가 어떻게 분노를 보상하는지에 대해 썼어요.', example_en_3 = 'In the attention economy, our focus becomes the product.', example_ko_3 = '주의 경제에서 우리의 집중력이 상품이 돼요.', example_en_4 = 'He studies how the attention economy affects mental health.', example_ko_4 = '그는 주의 경제가 정신 건강에 어떤 영향을 미치는지 연구해요.', example_en_5 = 'Understanding the attention economy helps users make conscious choices.', example_ko_5 = '주의 경제를 이해하면 사용자가 의식적인 선택을 하는 데 도움이 돼요.' WHERE id = 'w_media_C1_19';
UPDATE words SET example_en_2 = 'She argued that dominant tech platforms represent a form of digital colonialism.', example_ko_2 = '그녀는 지배적인 기술 플랫폼이 디지털 식민주의의 한 형태라고 주장했어요.', example_en_3 = 'Digital colonialism raises questions about data sovereignty.', example_ko_3 = '디지털 식민주의는 데이터 주권에 대한 의문을 제기해요.', example_en_4 = 'He researched how digital colonialism affects developing nations.', example_ko_4 = '그는 디지털 식민주의가 개발도상국에 어떤 영향을 미치는지 연구했어요.', example_en_5 = 'Critics warn that digital colonialism replicates old power imbalances.', example_ko_5 = '비평가들은 디지털 식민주의가 기존의 권력 불균형을 재현한다고 경고해요.' WHERE id = 'w_media_C1_20';
UPDATE words SET example_en_2 = 'She created a counter-narrative to challenge the official story.', example_ko_2 = '그녀는 공식적인 이야기에 도전하는 대항 서사를 만들었어요.', example_en_3 = 'Counter-narratives are essential in resisting propaganda.', example_ko_3 = '대항 서사는 선전에 저항하는 데 필수적이에요.', example_en_4 = 'He helped marginalized communities build their own counter-narrative.', example_ko_4 = '그는 소외된 커뮤니티가 자신들의 대항 서사를 구축하도록 도왔어요.', example_en_5 = 'Building an effective counter-narrative requires consistent messaging.', example_ko_5 = '효과적인 대항 서사를 구축하려면 일관된 메시지가 필요해요.' WHERE id = 'w_media_C1_21';
UPDATE words SET example_en_2 = 'She studied how media pluralism supports democratic debate.', example_ko_2 = '그녀는 미디어 다원주의가 민주주의적 토론을 어떻게 지지하는지 연구했어요.', example_en_3 = 'Media pluralism requires both diversity of ownership and content.', example_ko_3 = '미디어 다원주의는 소유권과 콘텐츠 모두의 다양성을 필요로 해요.', example_en_4 = 'He evaluated the state of media pluralism in different countries.', example_ko_4 = '그는 다양한 국가에서 미디어 다원주의의 상태를 평가했어요.', example_en_5 = 'Promoting media pluralism helps prevent monopolies of information.', example_ko_5 = '미디어 다원주의를 증진하면 정보 독점을 방지하는 데 도움이 돼요.' WHERE id = 'w_media_C1_22';
UPDATE words SET example_en_2 = 'She questioned the techno-optimism that sees technology as solving all problems.', example_ko_2 = '그녀는 기술이 모든 문제를 해결한다고 보는 기술 낙관주의에 의문을 가졌어요.', example_en_3 = 'Techno-optimism can lead people to overlook social and ethical risks.', example_ko_3 = '기술 낙관주의는 사람들이 사회적, 윤리적 위험을 간과하게 만들 수 있어요.', example_en_4 = 'He criticized techno-optimism in Silicon Valley culture.', example_ko_4 = '그는 실리콘밸리 문화의 기술 낙관주의를 비판했어요.', example_en_5 = 'Balancing techno-optimism with caution leads to better outcomes.', example_ko_5 = '기술 낙관주의와 신중함을 균형 있게 유지하면 더 좋은 결과를 낳아요.' WHERE id = 'w_media_C1_23';
UPDATE words SET example_en_2 = 'She reported on communities left behind as news deserts expand.', example_ko_2 = '그녀는 뉴스 사막이 확장되면서 소외되는 커뮤니티에 대해 보도했어요.', example_en_3 = 'News deserts are areas with little or no local journalism coverage.', example_ko_3 = '뉴스 사막은 지역 저널리즘 취재가 거의 없거나 전혀 없는 지역이에요.', example_en_4 = 'He studied how news deserts affect civic engagement.', example_ko_4 = '그는 뉴스 사막이 시민 참여에 어떤 영향을 미치는지 연구했어요.', example_en_5 = 'Solving the news desert problem requires new funding models.', example_ko_5 = '뉴스 사막 문제를 해결하려면 새로운 자금 조달 모델이 필요해요.' WHERE id = 'w_media_C1_24';
UPDATE words SET example_en_2 = 'She analyzed how the media triggered a moral panic about video games.', example_ko_2 = '그녀는 미디어가 어떻게 비디오 게임에 대한 도덕적 공황을 촉발시켰는지 분석했어요.', example_en_3 = 'Moral panics often result in rushed or disproportionate policy responses.', example_ko_3 = '도덕적 공황은 종종 성급하거나 과도한 정책 대응을 초래해요.', example_en_4 = 'He traced the history of moral panics in broadcasting history.', example_ko_4 = '그는 방송 역사에서 도덕적 공황의 역사를 추적했어요.', example_en_5 = 'A moral panic can unfairly stigmatize entire groups.', example_ko_5 = '도덕적 공황은 특정 집단 전체를 불공평하게 낙인찍을 수 있어요.' WHERE id = 'w_media_C1_25';
UPDATE words SET example_en_2 = 'She partnered with her followers in a co-creation process.', example_ko_2 = '그녀는 공동 창작 과정에서 팔로워들과 파트너십을 맺었어요.', example_en_3 = 'Co-creation gives audiences more investment in the final product.', example_ko_3 = '공동 창작은 청중이 최종 결과물에 더 많이 참여하게 해요.', example_en_4 = 'He used co-creation to build a community-driven news site.', example_ko_4 = '그는 공동 창작을 사용해 커뮤니티 주도의 뉴스 사이트를 만들었어요.', example_en_5 = 'Co-creation in media involves the audience in the storytelling process.', example_ko_5 = '미디어에서 공동 창작은 청중을 스토리텔링 과정에 참여시켜요.' WHERE id = 'w_media_C1_26';
UPDATE words SET example_en_2 = 'She developed a cross-platform strategy to reach diverse audiences.', example_ko_2 = '그녀는 다양한 청중에게 도달하기 위한 크로스 플랫폼 전략을 개발했어요.', example_en_3 = 'A cross-platform strategy ensures consistent messaging everywhere.', example_ko_3 = '크로스 플랫폼 전략은 모든 곳에서 일관된 메시지를 보장해요.', example_en_4 = 'He adapted each post for its platform as part of a cross-platform strategy.', example_ko_4 = '그는 크로스 플랫폼 전략의 일환으로 각 게시물을 해당 플랫폼에 맞게 조정했어요.', example_en_5 = 'Brands rely on cross-platform strategies to maximize visibility.', example_ko_5 = '브랜드들은 가시성을 극대화하기 위해 크로스 플랫폼 전략에 의존해요.' WHERE id = 'w_media_C1_27';
UPDATE words SET example_en_2 = 'She studied how mediatization has changed political communication.', example_ko_2 = '그녀는 미디어화가 정치적 소통을 어떻게 바꿨는지 연구했어요.', example_en_3 = 'Mediatization describes how media logic shapes modern society.', example_ko_3 = '미디어화는 미디어 논리가 현대 사회를 어떻게 형성하는지를 설명해요.', example_en_4 = 'He argued that mediatization has altered how institutions operate.', example_ko_4 = '그는 미디어화가 기관들의 운영 방식을 변화시켰다고 주장했어요.', example_en_5 = 'Mediatization is an ongoing process accelerated by digital technology.', example_ko_5 = '미디어화는 디지털 기술에 의해 가속화된 지속적인 과정이에요.' WHERE id = 'w_media_C1_28';
UPDATE words SET example_en_2 = 'She practices networked journalism by collaborating with citizen reporters.', example_ko_2 = '그녀는 시민 기자들과 협력하는 네트워크 저널리즘을 실천해요.', example_en_3 = 'Networked journalism connects professional reporters with online communities.', example_ko_3 = '네트워크 저널리즘은 전문 기자들을 온라인 커뮤니티와 연결시켜요.', example_en_4 = 'He studied how networked journalism improves local reporting.', example_ko_4 = '그는 네트워크 저널리즘이 지역 보도를 어떻게 개선하는지 연구했어요.', example_en_5 = 'Networked journalism gives readers a role in the news process.', example_ko_5 = '네트워크 저널리즘은 독자들에게 뉴스 과정에서 역할을 부여해요.' WHERE id = 'w_media_C1_29';
UPDATE words SET example_en_2 = 'She explored how the digital public sphere enables global conversations.', example_ko_2 = '그녀는 디지털 공론장이 어떻게 전 세계적 대화를 가능하게 하는지 탐구했어요.', example_en_3 = 'The digital public sphere is often fragmented by algorithms.', example_ko_3 = '디지털 공론장은 알고리즘에 의해 종종 분열돼요.', example_en_4 = 'He studied Habermas''s ideas in relation to the digital public sphere.', example_ko_4 = '그는 디지털 공론장과 관련해 하버마스의 아이디어를 연구했어요.', example_en_5 = 'Protecting the digital public sphere requires thoughtful platform governance.', example_ko_5 = '디지털 공론장을 보호하려면 사려 깊은 플랫폼 거버넌스가 필요해요.' WHERE id = 'w_media_C1_30';
UPDATE words SET example_en_2 = 'She wrote a critique of surveillance capitalism and user data.', example_ko_2 = '그녀는 감시 자본주의와 사용자 데이터에 대한 비판을 썼어요.', example_en_3 = 'Surveillance capitalism profits by predicting and modifying behavior.', example_ko_3 = '감시 자본주의는 행동을 예측하고 수정해 이익을 창출해요.', example_en_4 = 'He explored Shoshana Zuboff''s theory of surveillance capitalism.', example_ko_4 = '그는 쇼샤나 주보프의 감시 자본주의 이론을 탐구했어요.', example_en_5 = 'Understanding surveillance capitalism helps users protect their privacy.', example_ko_5 = '감시 자본주의를 이해하면 사용자가 개인 정보를 보호하는 데 도움이 돼요.' WHERE id = 'w_media_C1_31';
UPDATE words SET example_en_2 = 'She documented how weaponized information destabilized the election.', example_ko_2 = '그녀는 무기화된 정보가 선거를 어떻게 불안정하게 만들었는지를 기록했어요.', example_en_3 = 'Weaponized information is designed to cause social and political harm.', example_ko_3 = '무기화된 정보는 사회적, 정치적 피해를 주기 위해 설계돼요.', example_en_4 = 'He studied the tactics used in weaponized information campaigns.', example_ko_4 = '그는 무기화된 정보 캠페인에서 사용되는 전술을 연구했어요.', example_en_5 = 'Resisting weaponized information requires strong fact-checking systems.', example_ko_5 = '무기화된 정보에 저항하려면 강력한 팩트체크 시스템이 필요해요.' WHERE id = 'w_media_C1_32';
UPDATE words SET example_en_2 = 'She analyzed what credibility cues make news sites trustworthy.', example_ko_2 = '그녀는 뉴스 사이트를 신뢰할 수 있게 만드는 신뢰성 단서가 무엇인지 분석했어요.', example_en_3 = 'Credibility cues include author bylines, citations, and design quality.', example_ko_3 = '신뢰성 단서에는 저자 이름, 인용문, 디자인 품질 등이 포함돼요.', example_en_4 = 'He taught students how to identify credibility cues online.', example_ko_4 = '그는 학생들에게 온라인에서 신뢰성 단서를 파악하는 방법을 가르쳤어요.', example_en_5 = 'Credibility cues help readers distinguish real journalism from misinformation.', example_ko_5 = '신뢰성 단서는 독자들이 진짜 저널리즘과 잘못된 정보를 구별하는 데 도움이 돼요.' WHERE id = 'w_media_C1_33';
UPDATE words SET example_en_2 = 'She praised the platform for publishing detailed transparency reporting.', example_ko_2 = '그녀는 플랫폼이 상세한 투명성 보고서를 발행한 것을 칭찬했어요.', example_en_3 = 'Transparency reporting shows how often governments request user data.', example_ko_3 = '투명성 보고는 정부가 얼마나 자주 사용자 데이터를 요청하는지를 보여줘요.', example_en_4 = 'He called for more comprehensive transparency reporting from tech companies.', example_ko_4 = '그는 기술 기업들에 더 포괄적인 투명성 보고를 요구했어요.', example_en_5 = 'Transparency reporting builds public trust in digital platforms.', example_ko_5 = '투명성 보고는 디지털 플랫폼에 대한 대중의 신뢰를 쌓아요.' WHERE id = 'w_media_C1_34';
UPDATE words SET example_en_2 = 'She defended the editorial independence of her newspaper.', example_ko_2 = '그녀는 자신의 신문사의 편집 독립성을 지켰어요.', example_en_3 = 'Editorial independence ensures that advertising does not influence content.', example_ko_3 = '편집 독립성은 광고가 콘텐츠에 영향을 미치지 않도록 보장해요.', example_en_4 = 'He resigned to protect editorial independence from political pressure.', example_ko_4 = '그는 정치적 압력으로부터 편집 독립성을 지키기 위해 사임했어요.', example_en_5 = 'Editorial independence is a cornerstone of responsible journalism.', example_ko_5 = '편집 독립성은 책임감 있는 저널리즘의 초석이에요.' WHERE id = 'w_media_C1_35';

-- C2
UPDATE words SET example_en_2 = 'She applied semiotics to analyze the symbols in political advertising.', example_ko_2 = '그녀는 기호학을 적용해 정치 광고의 상징을 분석했어요.', example_en_3 = 'Semiotics examines how meaning is constructed through signs.', example_ko_3 = '기호학은 기호를 통해 의미가 어떻게 구성되는지를 살펴봐요.', example_en_4 = 'He studied the semiotics of social media images.', example_ko_4 = '그는 소셜 미디어 이미지의 기호학을 연구했어요.', example_en_5 = 'Understanding semiotics enriches the analysis of media texts.', example_ko_5 = '기호학을 이해하면 미디어 텍스트 분석이 더 풍부해져요.' WHERE id = 'w_media_C2_01';
UPDATE words SET example_en_2 = 'She argued that the commodification of attention is a modern crisis.', example_ko_2 = '그녀는 주의의 상품화가 현대적 위기라고 주장했어요.', example_en_3 = 'Commodification of user data raises serious ethical questions.', example_ko_3 = '사용자 데이터의 상품화는 심각한 윤리적 의문을 제기해요.', example_en_4 = 'He explored how content itself becomes a commodity in the platform economy.', example_ko_4 = '그는 플랫폼 경제에서 콘텐츠 자체가 어떻게 상품이 되는지를 탐구했어요.', example_en_5 = 'The commodification of culture can strip it of its original meaning.', example_ko_5 = '문화의 상품화는 본래의 의미를 빼앗을 수 있어요.' WHERE id = 'w_media_C2_02';
UPDATE words SET example_en_2 = 'She argued that social media feeds have created a state of hyperreality.', example_ko_2 = '그녀는 소셜 미디어 피드가 초현실의 상태를 만들었다고 주장했어요.', example_en_3 = 'Hyperreality blurs the line between image and reality.', example_ko_3 = '초현실은 이미지와 현실 사이의 경계를 흐리게 해요.', example_en_4 = 'He referenced Baudrillard''s concept of hyperreality in his essay.', example_ko_4 = '그는 에세이에서 보드리야르의 초현실 개념을 언급했어요.', example_en_5 = 'In a state of hyperreality, simulations feel more real than reality itself.', example_ko_5 = '초현실 상태에서는 시뮬레이션이 현실 그 자체보다 더 실제처럼 느껴져요.' WHERE id = 'w_media_C2_03';
UPDATE words SET example_en_2 = 'She described influencer culture as a vast simulacrum.', example_ko_2 = '그녀는 인플루언서 문화를 거대한 시뮬라크럼으로 묘사했어요.', example_en_3 = 'A simulacrum is a copy without an original.', example_ko_3 = '시뮬라크럼은 원본 없는 복제예요.', example_en_4 = 'He explored how the news can function as a simulacrum of reality.', example_ko_4 = '그는 뉴스가 어떻게 현실의 시뮬라크럼으로 기능할 수 있는지 탐구했어요.', example_en_5 = 'Baudrillard argued that modern culture is dominated by simulacra.', example_ko_5 = '보드리야르는 현대 문화가 시뮬라크라에 의해 지배된다고 주장했어요.' WHERE id = 'w_media_C2_04';
UPDATE words SET example_en_2 = 'She criticized the rise of technocracy in global governance.', example_ko_2 = '그녀는 세계 거버넌스에서 기술관료주의의 부상을 비판했어요.', example_en_3 = 'A technocracy values expertise and data above democratic debate.', example_ko_3 = '기술관료주의는 민주적 토론보다 전문성과 데이터를 중시해요.', example_en_4 = 'He analyzed how Silicon Valley promotes a form of technocracy.', example_ko_4 = '그는 실리콘밸리가 기술관료주의의 한 형태를 어떻게 촉진하는지 분석했어요.', example_en_5 = 'Critics argue that technocracy undermines public participation.', example_ko_5 = '비평가들은 기술관료주의가 공공 참여를 약화시킨다고 주장해요.' WHERE id = 'w_media_C2_05';
UPDATE words SET example_en_2 = 'She wrote about living in a post-truth media environment.', example_ko_2 = '그녀는 탈진실 미디어 환경에서 살아가는 것에 대해 글을 썼어요.', example_en_3 = 'In a post-truth world, emotions often outweigh evidence.', example_ko_3 = '탈진실 세계에서는 감정이 종종 증거보다 우선시돼요.', example_en_4 = 'He studied how post-truth politics changed journalism.', example_ko_4 = '그는 탈진실 정치가 저널리즘을 어떻게 변화시켰는지 연구했어요.', example_en_5 = 'Combating post-truth culture requires a commitment to facts.', example_ko_5 = '탈진실 문화에 맞서려면 사실에 대한 헌신이 필요해요.' WHERE id = 'w_media_C2_06';
UPDATE words SET example_en_2 = 'She described the digital media ecosystem as a global infosphere.', example_ko_2 = '그녀는 디지털 미디어 생태계를 전 세계적인 인포스피어로 묘사했어요.', example_en_3 = 'The infosphere includes all forms of information and communication.', example_ko_3 = '인포스피어는 모든 형태의 정보와 소통을 포함해요.', example_en_4 = 'He argued that navigating the infosphere requires new cognitive skills.', example_ko_4 = '그는 인포스피어를 탐색하려면 새로운 인지 능력이 필요하다고 주장했어요.', example_en_5 = 'Our lives are increasingly embedded within the infosphere.', example_ko_5 = '우리의 삶은 점점 더 인포스피어 안에 깊이 자리잡고 있어요.' WHERE id = 'w_media_C2_07';
UPDATE words SET example_en_2 = 'She critiqued the lack of accountability in algorithmic governance.', example_ko_2 = '그녀는 알고리즘 거버넌스의 책임감 부재를 비판했어요.', example_en_3 = 'Algorithmic governance affects who sees what information online.', example_ko_3 = '알고리즘 거버넌스는 누가 온라인에서 어떤 정보를 보는지에 영향을 미쳐요.', example_en_4 = 'He studied the legal frameworks emerging around algorithmic governance.', example_ko_4 = '그는 알고리즘 거버넌스를 둘러싸고 부상하는 법적 틀을 연구했어요.', example_en_5 = 'Algorithmic governance requires transparency and public oversight.', example_ko_5 = '알고리즘 거버넌스는 투명성과 공공 감시를 필요로 해요.' WHERE id = 'w_media_C2_08';
UPDATE words SET example_en_2 = 'She explored how deepfake epistemics challenges our trust in visual evidence.', example_ko_2 = '그녀는 딥페이크 인식론이 시각적 증거에 대한 신뢰를 어떻게 도전하는지 탐구했어요.', example_en_3 = 'Deepfake epistemics questions whether we can trust any recorded image.', example_ko_3 = '딥페이크 인식론은 우리가 기록된 이미지를 신뢰할 수 있는지를 의심해요.', example_en_4 = 'He argued that deepfake epistemics demands new frameworks for truth verification.', example_ko_4 = '그는 딥페이크 인식론이 진실 검증을 위한 새로운 틀을 요구한다고 주장했어요.', example_en_5 = 'Understanding deepfake epistemics is vital for modern media education.', example_ko_5 = '딥페이크 인식론을 이해하는 것은 현대 미디어 교육에 매우 중요해요.' WHERE id = 'w_media_C2_09';
UPDATE words SET example_en_2 = 'She used a Habermasian framework to analyze public debate online.', example_ko_2 = '그녀는 온라인 공론을 분석하기 위해 하버마스적 틀을 사용했어요.', example_en_3 = 'A Habermasian approach values rational discourse and deliberation.', example_ko_3 = '하버마스적 접근법은 합리적 담론과 숙의를 중시해요.', example_en_4 = 'He critiqued social media from a Habermasian perspective.', example_ko_4 = '그는 하버마스적 관점에서 소셜 미디어를 비판했어요.', example_en_5 = 'Habermasian theory remains influential in media and democracy studies.', example_ko_5 = '하버마스 이론은 미디어와 민주주의 연구에서 여전히 영향력이 있어요.' WHERE id = 'w_media_C2_10';
UPDATE words SET example_en_2 = 'She analyzed how media disruption threatens ontological security.', example_ko_2 = '그녀는 미디어 혼란이 존재론적 안전을 어떻게 위협하는지 분석했어요.', example_en_3 = 'Ontological security refers to the sense of stability in our identity.', example_ko_3 = '존재론적 안전은 우리의 정체성에 대한 안정감을 말해요.', example_en_4 = 'He explored how fake news erodes ontological security.', example_ko_4 = '그는 가짜 뉴스가 어떻게 존재론적 안전을 침식하는지 탐구했어요.', example_en_5 = 'Maintaining ontological security in the digital age is increasingly difficult.', example_ko_5 = '디지털 시대에 존재론적 안전을 유지하는 것은 점점 더 어려워지고 있어요.' WHERE id = 'w_media_C2_11';
UPDATE words SET example_en_2 = 'She studied Foucault''s concept of discursive formation in media.', example_ko_2 = '그녀는 미디어에서 푸코의 담론 형성 개념을 연구했어요.', example_en_3 = 'A discursive formation determines what can and cannot be said.', example_ko_3 = '담론 형성은 무엇이 말해질 수 있고 없는지를 결정해요.', example_en_4 = 'He traced the discursive formation around the concept of privacy.', example_ko_4 = '그는 프라이버시 개념을 둘러싼 담론 형성을 추적했어요.', example_en_5 = 'Understanding discursive formation helps reveal hidden power structures.', example_ko_5 = '담론 형성을 이해하면 숨겨진 권력 구조를 드러내는 데 도움이 돼요.' WHERE id = 'w_media_C2_12';
UPDATE words SET example_en_2 = 'She applied Althusser''s concept of the ideological state apparatus to media.', example_ko_2 = '그녀는 알튀세르의 이데올로기적 국가기구 개념을 미디어에 적용했어요.', example_en_3 = 'The ideological state apparatus transmits dominant values through culture.', example_ko_3 = '이데올로기적 국가기구는 문화를 통해 지배적인 가치를 전달해요.', example_en_4 = 'He argued that media functions as an ideological state apparatus.', example_ko_4 = '그는 미디어가 이데올로기적 국가기구로 기능한다고 주장했어요.', example_en_5 = 'Identifying the ideological state apparatus is key to critical media theory.', example_ko_5 = '이데올로기적 국가기구를 파악하는 것은 비판적 미디어 이론의 핵심이에요.' WHERE id = 'w_media_C2_13';
UPDATE words SET example_en_2 = 'She argued that mediatized politics prioritizes spectacle over substance.', example_ko_2 = '그녀는 미디어화된 정치가 실질보다 구경거리를 우선시한다고 주장했어요.', example_en_3 = 'Mediatized politics shapes how politicians communicate with the public.', example_ko_3 = '미디어화된 정치는 정치인들이 대중과 소통하는 방식을 형성해요.', example_en_4 = 'He studied how social media accelerates mediatized politics.', example_ko_4 = '그는 소셜 미디어가 어떻게 미디어화된 정치를 가속화하는지 연구했어요.', example_en_5 = 'Mediatized politics requires politicians to be media-savvy.', example_ko_5 = '미디어화된 정치는 정치인들이 미디어에 능숙해야 함을 요구해요.' WHERE id = 'w_media_C2_14';
UPDATE words SET example_en_2 = 'She described modern social life as characterized by networked individualism.', example_ko_2 = '그녀는 현대의 사회적 삶을 네트워크화된 개인주의로 특징지었어요.', example_en_3 = 'Networked individualism means people connect based on interests, not geography.', example_ko_3 = '네트워크화된 개인주의는 사람들이 지리가 아닌 관심사에 따라 연결됨을 의미해요.', example_en_4 = 'He studied Wellman''s theory of networked individualism.', example_ko_4 = '그는 웰먼의 네트워크화된 개인주의 이론을 연구했어요.', example_en_5 = 'Social media enables networked individualism on a global scale.', example_ko_5 = '소셜 미디어는 글로벌 규모에서 네트워크화된 개인주의를 가능하게 해요.' WHERE id = 'w_media_C2_15';
UPDATE words SET example_en_2 = 'She studied how attention fragmentation affects deep reading.', example_ko_2 = '그녀는 주의 분산이 심층 독서에 어떻게 영향을 미치는지 연구했어요.', example_en_3 = 'Attention fragmentation results from constant switching between apps.', example_ko_3 = '주의 분산은 앱 사이의 끊임없는 전환에서 비롯돼요.', example_en_4 = 'He argued that attention fragmentation harms democratic deliberation.', example_ko_4 = '그는 주의 분산이 민주적 숙의를 해친다고 주장했어요.', example_en_5 = 'Reducing attention fragmentation requires deliberate digital habits.', example_ko_5 = '주의 분산을 줄이려면 의도적인 디지털 습관이 필요해요.' WHERE id = 'w_media_C2_16';
UPDATE words SET example_en_2 = 'She developed a parasocial relationship with her favorite podcast host.', example_ko_2 = '그녀는 가장 좋아하는 팟캐스트 진행자와 유사사회적 관계를 형성했어요.', example_en_3 = 'Parasocial relationships feel real but are one-sided.', example_ko_3 = '유사사회적 관계는 실제처럼 느껴지지만 일방적이에요.', example_en_4 = 'He studied how streamers cultivate parasocial relationships with fans.', example_ko_4 = '그는 스트리머들이 팬들과 어떻게 유사사회적 관계를 형성하는지 연구했어요.', example_en_5 = 'Parasocial relationships can fill social needs for isolated individuals.', example_ko_5 = '유사사회적 관계는 고립된 개인의 사회적 필요를 채울 수 있어요.' WHERE id = 'w_media_C2_17';
UPDATE words SET example_en_2 = 'She challenged technodeterminism by showing human agency in media use.', example_ko_2 = '그녀는 미디어 사용에서 인간의 주체성을 보여줌으로써 기술결정론에 도전했어요.', example_en_3 = 'Technodeterminism suggests technology drives social change independently.', example_ko_3 = '기술결정론은 기술이 독립적으로 사회 변화를 이끈다고 시사해요.', example_en_4 = 'He argued that technodeterminism oversimplifies human-technology interaction.', example_ko_4 = '그는 기술결정론이 인간과 기술의 상호작용을 지나치게 단순화한다고 주장했어요.', example_en_5 = 'Avoiding technodeterminism means recognizing human choices in tech design.', example_ko_5 = '기술결정론을 피하려면 기술 설계에서 인간의 선택을 인정해야 해요.' WHERE id = 'w_media_C2_18';
UPDATE words SET example_en_2 = 'She argued that platform imperialism concentrates global media power.', example_ko_2 = '그녀는 플랫폼 제국주의가 세계 미디어 권력을 집중시킨다고 주장했어요.', example_en_3 = 'Platform imperialism benefits a few countries at the expense of many.', example_ko_3 = '플랫폼 제국주의는 소수의 국가에 이익을 주고 많은 나라들에 손해를 끼쳐요.', example_en_4 = 'He studied how platform imperialism limits local media cultures.', example_ko_4 = '그는 플랫폼 제국주의가 지역 미디어 문화를 어떻게 제한하는지 연구했어요.', example_en_5 = 'Challenging platform imperialism requires supporting local digital ecosystems.', example_ko_5 = '플랫폼 제국주의에 도전하려면 지역 디지털 생태계를 지원해야 해요.' WHERE id = 'w_media_C2_19';
UPDATE words SET example_en_2 = 'She worked to improve the signal-to-noise ratio in her newsletter.', example_ko_2 = '그녀는 뉴스레터의 신호 대 잡음비를 개선하기 위해 노력했어요.', example_en_3 = 'A high noise-to-signal ratio makes it hard to find reliable information.', example_ko_3 = '높은 잡음 대 신호 비율은 신뢰할 수 있는 정보를 찾기 어렵게 만들어요.', example_en_4 = 'He used the noise-to-signal metaphor to describe social media overload.', example_ko_4 = '그는 소셜 미디어 과부하를 설명하기 위해 잡음 대 신호 비율 비유를 사용했어요.', example_en_5 = 'Reducing the noise-to-signal ratio is a key goal of media curation.', example_ko_5 = '잡음 대 신호 비율을 줄이는 것은 미디어 큐레이션의 핵심 목표예요.' WHERE id = 'w_media_C2_20';
UPDATE words SET example_en_2 = 'She studied second-order media effects on political participation.', example_ko_2 = '그녀는 정치 참여에 대한 2차 미디어 효과를 연구했어요.', example_en_3 = 'Second-order media effects include long-term changes in social norms.', example_ko_3 = '2차 미디어 효과에는 사회 규범의 장기적인 변화가 포함돼요.', example_en_4 = 'He explored how second-order media effects shape cultural identity.', example_ko_4 = '그는 2차 미디어 효과가 문화적 정체성을 어떻게 형성하는지 탐구했어요.', example_en_5 = 'Analyzing second-order media effects requires longitudinal research.', example_ko_5 = '2차 미디어 효과를 분석하려면 종단 연구가 필요해요.' WHERE id = 'w_media_C2_21';
UPDATE words SET example_en_2 = 'She identified a performative contradiction in the platform''s privacy claims.', example_ko_2 = '그녀는 플랫폼의 프라이버시 주장에서 수행적 모순을 발견했어요.', example_en_3 = 'A performative contradiction occurs when an action undermines its stated goal.', example_ko_3 = '수행적 모순은 행동이 명시된 목표를 훼손할 때 발생해요.', example_en_4 = 'He argued that censoring debate about censorship is a performative contradiction.', example_ko_4 = '그는 검열에 대한 토론을 검열하는 것이 수행적 모순이라고 주장했어요.', example_en_5 = 'Pointing out performative contradictions can challenge media institutions.', example_ko_5 = '수행적 모순을 지적하면 미디어 기관에 도전할 수 있어요.' WHERE id = 'w_media_C2_22';
UPDATE words SET example_en_2 = 'She applied digital hermeneutics to analyze online political texts.', example_ko_2 = '그녀는 디지털 해석학을 적용해 온라인 정치 텍스트를 분석했어요.', example_en_3 = 'Digital hermeneutics asks how we interpret meaning in digital contexts.', example_ko_3 = '디지털 해석학은 디지털 맥락에서 의미를 어떻게 해석하는지를 묻는 학문이에요.', example_en_4 = 'He used digital hermeneutics to study meme culture.', example_ko_4 = '그는 디지털 해석학을 사용해 밈 문화를 연구했어요.', example_en_5 = 'Digital hermeneutics blends traditional text analysis with digital methods.', example_ko_5 = '디지털 해석학은 전통적인 텍스트 분석과 디지털 방법을 결합해요.' WHERE id = 'w_media_C2_23';
UPDATE words SET example_en_2 = 'She argued that social media has triggered an epistemic crisis.', example_ko_2 = '그녀는 소셜 미디어가 인식론적 위기를 촉발했다고 주장했어요.', example_en_3 = 'An epistemic crisis occurs when shared frameworks for truth break down.', example_ko_3 = '인식론적 위기는 진실에 대한 공유된 틀이 붕괴될 때 발생해요.', example_en_4 = 'He studied institutional responses to the current epistemic crisis.', example_ko_4 = '그는 현재의 인식론적 위기에 대한 기관들의 대응을 연구했어요.', example_en_5 = 'Resolving an epistemic crisis requires rebuilding trust in shared knowledge.', example_ko_5 = '인식론적 위기를 해결하려면 공유된 지식에 대한 신뢰를 재건해야 해요.' WHERE id = 'w_media_C2_24';
UPDATE words SET example_en_2 = 'She critiqued communicative capitalism for absorbing dissent.', example_ko_2 = '그녀는 이견을 흡수하는 소통 자본주의를 비판했어요.', example_en_3 = 'Communicative capitalism turns political speech into circulation.', example_ko_3 = '소통 자본주의는 정치적 발언을 유통으로 전환시켜요.', example_en_4 = 'He used Jodi Dean''s concept of communicative capitalism in his research.', example_ko_4 = '그는 연구에서 조디 딘의 소통 자본주의 개념을 활용했어요.', example_en_5 = 'Understanding communicative capitalism explains why online activism often fails.', example_ko_5 = '소통 자본주의를 이해하면 온라인 행동주의가 종종 실패하는 이유를 설명할 수 있어요.' WHERE id = 'w_media_C2_25';
UPDATE words SET example_en_2 = 'She applied the concept of ideological interpellation to advertising.', example_ko_2 = '그녀는 이데올로기적 호명 개념을 광고에 적용했어요.', example_en_3 = 'Ideological interpellation is how ideology calls individuals into subject positions.', example_ko_3 = '이데올로기적 호명은 이데올로기가 개인을 주체 위치로 부르는 방식이에요.', example_en_4 = 'He studied Althusser''s notion of ideological interpellation and media.', example_ko_4 = '그는 알튀세르의 이데올로기적 호명 개념과 미디어를 연구했어요.', example_en_5 = 'Media advertising relies on ideological interpellation to create consumers.', example_ko_5 = '미디어 광고는 소비자를 만들기 위해 이데올로기적 호명에 의존해요.' WHERE id = 'w_media_C2_26';
UPDATE words SET example_en_2 = 'She described Hollywood''s global dominance as a form of cultural hegemony.', example_ko_2 = '그녀는 할리우드의 세계적 지배력을 문화적 헤게모니의 한 형태로 묘사했어요.', example_en_3 = 'Cultural hegemony is maintained through consent rather than force.', example_ko_3 = '문화적 헤게모니는 강제가 아닌 동의를 통해 유지돼요.', example_en_4 = 'He explored Gramsci''s concept of cultural hegemony in modern media.', example_ko_4 = '그는 현대 미디어에서 그람시의 문화적 헤게모니 개념을 탐구했어요.', example_en_5 = 'Counter-cultural movements challenge cultural hegemony.', example_ko_5 = '반문화 운동은 문화적 헤게모니에 도전해요.' WHERE id = 'w_media_C2_27';
UPDATE words SET example_en_2 = 'She used media ecology theory to study how different media interact.', example_ko_2 = '그녀는 미디어 생태학 이론을 사용해 서로 다른 미디어가 어떻게 상호작용하는지 연구했어요.', example_en_3 = 'Media ecology examines how communication technologies shape environments.', example_ko_3 = '미디어 생태학은 소통 기술이 어떻게 환경을 형성하는지를 살펴봐요.', example_en_4 = 'He studied McLuhan''s contribution to the field of media ecology.', example_ko_4 = '그는 미디어 생태학 분야에 대한 맥루한의 공헌을 연구했어요.', example_en_5 = 'Media ecology helps us see technology as a shaping force in society.', example_ko_5 = '미디어 생태학은 기술을 사회의 형성 요인으로 보는 데 도움이 돼요.' WHERE id = 'w_media_C2_28';
UPDATE words SET example_en_2 = 'She explored how the internet enables a kind of semiotic democracy.', example_ko_2 = '그녀는 인터넷이 어떻게 일종의 기호론적 민주주의를 가능하게 하는지 탐구했어요.', example_en_3 = 'Semiotic democracy allows everyone to participate in making meaning.', example_ko_3 = '기호론적 민주주의는 모든 사람이 의미 생성에 참여할 수 있도록 해요.', example_en_4 = 'He critiqued whether semiotic democracy truly empowers ordinary users.', example_ko_4 = '그는 기호론적 민주주의가 실제로 일반 사용자에게 권한을 부여하는지를 비판적으로 검토했어요.', example_en_5 = 'Semiotic democracy challenges top-down models of communication.', example_ko_5 = '기호론적 민주주의는 하향식 소통 모델에 도전해요.' WHERE id = 'w_media_C2_29';
UPDATE words SET example_en_2 = 'She warned about the risks of hyper-personalization in news delivery.', example_ko_2 = '그녀는 뉴스 전달에서 초개인화의 위험성에 대해 경고했어요.', example_en_3 = 'Hyper-personalization uses AI to tailor every aspect of the user experience.', example_ko_3 = '초개인화는 AI를 사용해 사용자 경험의 모든 측면을 맞춤화해요.', example_en_4 = 'He studied how hyper-personalization limits exposure to diverse content.', example_ko_4 = '그는 초개인화가 다양한 콘텐츠에 대한 노출을 어떻게 제한하는지 연구했어요.', example_en_5 = 'Hyper-personalization raises important questions about autonomy and manipulation.', example_ko_5 = '초개인화는 자율성과 조작에 관한 중요한 의문을 제기해요.' WHERE id = 'w_media_C2_30';
UPDATE words SET example_en_2 = 'She advocated for digital sovereignty to protect citizens'' data rights.', example_ko_2 = '그녀는 시민의 데이터 권리를 보호하기 위해 디지털 주권을 지지했어요.', example_en_3 = 'Digital sovereignty involves controlling one''s own digital infrastructure.', example_ko_3 = '디지털 주권은 자신의 디지털 인프라를 통제하는 것을 포함해요.', example_en_4 = 'He studied how the EU pursues digital sovereignty through regulation.', example_ko_4 = '그는 EU가 규제를 통해 어떻게 디지털 주권을 추구하는지 연구했어요.', example_en_5 = 'Digital sovereignty is becoming a central issue in global tech policy.', example_ko_5 = '디지털 주권은 세계 기술 정책의 핵심 이슈가 되고 있어요.' WHERE id = 'w_media_C2_31';
UPDATE words SET example_en_2 = 'She criticized technological solutionism for ignoring social root causes.', example_ko_2 = '그녀는 기술 솔루션주의가 사회적 근본 원인을 무시한다고 비판했어요.', example_en_3 = 'Technological solutionism assumes every problem has a technological fix.', example_ko_3 = '기술 솔루션주의는 모든 문제에 기술적인 해결책이 있다고 가정해요.', example_en_4 = 'He referenced Morozov''s critique of technological solutionism.', example_ko_4 = '그는 모로조프의 기술 솔루션주의 비판을 인용했어요.', example_en_5 = 'Avoiding technological solutionism requires asking political and social questions.', example_ko_5 = '기술 솔루션주의를 피하려면 정치적, 사회적 질문을 던져야 해요.' WHERE id = 'w_media_C2_32';
UPDATE words SET example_en_2 = 'She contributed to critical data studies by examining bias in datasets.', example_ko_2 = '그녀는 데이터셋의 편향을 검토해 비판적 데이터 연구에 기여했어요.', example_en_3 = 'Critical data studies challenges the idea that data is objective.', example_ko_3 = '비판적 데이터 연구는 데이터가 객관적이라는 생각에 도전해요.', example_en_4 = 'He used critical data studies to analyze surveillance algorithms.', example_ko_4 = '그는 비판적 데이터 연구를 사용해 감시 알고리즘을 분석했어요.', example_en_5 = 'Critical data studies examines who collects data and why.', example_ko_5 = '비판적 데이터 연구는 누가 데이터를 수집하고 그 이유는 무엇인지를 살펴봐요.' WHERE id = 'w_media_C2_33';
UPDATE words SET example_en_2 = 'She explored what creativity means in a post-digital world.', example_ko_2 = '그녀는 탈디지털 세계에서 창의성이 무엇을 의미하는지 탐구했어요.', example_en_3 = 'Post-digital art blurs the boundaries between digital and physical.', example_ko_3 = '탈디지털 예술은 디지털과 물리적 경계를 흐리게 해요.', example_en_4 = 'He argued that we are moving into a post-digital media era.', example_ko_4 = '그는 우리가 탈디지털 미디어 시대로 이동하고 있다고 주장했어요.', example_en_5 = 'In a post-digital age, digital and physical media are deeply intertwined.', example_ko_5 = '탈디지털 시대에 디지털과 물리적 미디어는 깊이 얽혀 있어요.' WHERE id = 'w_media_C2_34';
UPDATE words SET example_en_2 = 'She argued that fake news has contributed to a legitimation crisis.', example_ko_2 = '그녀는 가짜 뉴스가 정당성 위기에 기여했다고 주장했어요.', example_en_3 = 'A legitimation crisis occurs when institutions lose public trust.', example_ko_3 = '정당성 위기는 기관들이 대중의 신뢰를 잃을 때 발생해요.', example_en_4 = 'He studied Habermas''s concept of legitimation crisis in digital media.', example_ko_4 = '그는 디지털 미디어에서 하버마스의 정당성 위기 개념을 연구했어요.', example_en_5 = 'Overcoming a legitimation crisis requires transparency and accountability.', example_ko_5 = '정당성 위기를 극복하려면 투명성과 책임이 필요해요.' WHERE id = 'w_media_C2_35';
