UPDATE words SET example_en_2 = 'What do you want to change in the contract?', example_ko_2 = '계약서에서 무엇을 바꾸고 싶으세요?', example_en_3 = 'I want a lower price for this order.', example_ko_3 = '이 주문에 더 낮은 가격을 원해요.', example_en_4 = 'Do you want to meet again tomorrow?', example_ko_4 = '내일 다시 만나고 싶으세요?', example_en_5 = 'We want the deal to be fair for both sides.', example_ko_5 = '양쪽 모두에게 공정한 거래를 원해요.' WHERE id = 'w_negotiation_A1_01';
