UPDATE words SET example_en_2 = 'Can you give us a longer payment period?', example_ko_2 = '더 긴 지불 기간을 주실 수 있나요?', example_en_3 = 'We will give you our answer by Friday.', example_ko_3 = '금요일까지 답변을 드릴게요.', example_en_4 = 'Give me a moment to check the numbers.', example_ko_4 = '숫자를 확인할 잠깐의 시간을 주세요.', example_en_5 = 'She gave the other side a small concession.', example_ko_5 = '그녀는 상대방에게 작은 양보를 해줬어요.' WHERE id = 'w_negotiation_A1_03';
