UPDATE words SET example_en_2 = 'That sounds like a good deal to us.', example_ko_2 = '그것은 우리에게 좋은 거래처럼 들려요.', example_en_3 = 'This is a good starting point for talks.', example_ko_3 = '이것은 협상의 좋은 출발점이에요.', example_en_4 = 'The working relationship has been very good.', example_ko_4 = '업무 관계가 매우 좋았어요.', example_en_5 = 'Good communication prevents misunderstandings.', example_ko_5 = '좋은 의사소통이 오해를 방지해요.' WHERE id = 'w_negotiation_A1_25';
