UPDATE words SET example_en_2 = 'The terms are okay but we want better.', example_ko_2 = '조건은 괜찮지만 더 좋은 것을 원해요.', example_en_3 = 'Is the timeline okay with your team?', example_ko_3 = '타임라인이 귀사 팀에게 괜찮은가요?', example_en_4 = 'The first draft is okay — let us refine it.', example_ko_4 = '첫 번째 초안은 괜찮아요 — 다듬어 봐요.', example_en_5 = 'Are you okay with a 30-day payment term?', example_ko_5 = '30일 지불 조건이 괜찮으신가요?' WHERE id = 'w_negotiation_A1_27';
UPDATE words SET example_en_2 = 'We need to change the delivery schedule.', example_ko_2 = '납품 일정을 바꿔야 해요.', example_en_3 = 'Can we change the meeting to next week?', example_ko_3 = '회의를 다음 주로 바꿀 수 있나요?', example_en_4 = 'The price did not change after negotiation.', example_ko_4 = '협상 후에도 가격이 바뀌지 않았어요.', example_en_5 = 'Please tell us if anything needs to change.', example_ko_5 = '바꿔야 할 것이 있으면 알려주세요.' WHERE id = 'w_negotiation_A1_28';
UPDATE words SET example_en_2 = 'Let us stop and take a short break.', example_ko_2 = '멈추고 짧은 휴식을 취해요.', example_en_3 = 'We had to stop when no progress was made.', example_ko_3 = '진전이 없을 때 멈춰야 했어요.', example_en_4 = 'Stop here and confirm what we agreed on.', example_ko_4 = '여기서 멈추고 합의한 내용을 확인해요.', example_en_5 = 'They stopped the talks and asked for more time.', example_ko_5 = '그들은 협상을 멈추고 더 많은 시간을 요청했어요.' WHERE id = 'w_negotiation_A1_29';
UPDATE words SET example_en_2 = 'Let us start with the most urgent issue.', example_ko_2 = '가장 시급한 문제부터 시작해요.', example_en_3 = 'We will start the contract review tomorrow.', example_ko_3 = '내일 계약서 검토를 시작할게요.', example_en_4 = 'Start with small agreements to build trust.', example_ko_4 = '신뢰를 쌓기 위해 작은 합의부터 시작하세요.', example_en_5 = 'They started the meeting on a positive note.', example_ko_5 = '그들은 긍정적인 분위기로 회의를 시작했어요.' WHERE id = 'w_negotiation_A1_30';
UPDATE words SET example_en_2 = 'Are both parties ready to sign today?', example_ko_2 = '양 당사자 모두 오늘 서명할 준비가 됐나요?', example_en_3 = 'We are ready to move forward now.', example_ko_3 = '이제 앞으로 나아갈 준비가 됐어요.', example_en_4 = 'Is your team ready to accept the new terms?', example_ko_4 = '귀사 팀이 새 조건을 받아들일 준비가 됐나요?', example_en_5 = 'Get ready — the final decision is today.', example_ko_5 = '준비하세요 — 오늘 최종 결정을 내려요.' WHERE id = 'w_negotiation_A1_31';
UPDATE words SET example_en_2 = 'We are open to revising the terms.', example_ko_2 = '조건을 수정하는 것에 열려 있어요.', example_en_3 = 'Is your company open to a partnership?', example_ko_3 = '귀사는 파트너십에 열려 있나요?', example_en_4 = 'She was open to discussing all options.', example_ko_4 = '그녀는 모든 옵션을 논의하는 것에 열려 있었어요.', example_en_5 = 'Keep an open mind during the negotiation.', example_ko_5 = '협상 중에 열린 마음을 유지하세요.' WHERE id = 'w_negotiation_A1_32';
UPDATE words SET example_en_2 = 'Is this the right time to discuss the price?', example_ko_2 = '가격을 논의하기에 적절한 시기인가요?', example_en_3 = 'We need the right information to decide.', example_ko_3 = '결정을 내리려면 올바른 정보가 필요해요.', example_en_4 = 'She asked the right questions at every stage.', example_ko_4 = '그녀는 모든 단계에서 올바른 질문을 했어요.', example_en_5 = 'Let us find the right balance for both sides.', example_ko_5 = '양쪽 모두에게 적절한 균형을 찾아봐요.' WHERE id = 'w_negotiation_A1_33';
UPDATE words SET example_en_2 = 'This solution can work if we act fast.', example_ko_2 = '빠르게 행동하면 이 솔루션이 효과가 있을 거예요.', example_en_3 = 'Does the new schedule work for your team?', example_ko_3 = '새 일정이 귀사 팀에게 효과가 있나요?', example_en_4 = 'We want an arrangement that works long-term.', example_ko_4 = '장기적으로 효과 있는 협정을 원해요.', example_en_5 = 'Their proposal could work if costs are reduced.', example_ko_5 = '비용이 줄어들면 그들의 제안이 효과가 있을 거예요.' WHERE id = 'w_negotiation_A1_34';
UPDATE words SET example_en_2 = 'Let me think about it and call you back.', example_ko_2 = '생각해 보고 다시 전화드릴게요.', example_en_3 = 'Think carefully before accepting any offer.', example_ko_3 = '어떤 제안을 받아들이기 전에 신중하게 생각하세요.', example_en_4 = 'We need time to think about the proposal.', example_ko_4 = '제안에 대해 생각할 시간이 필요해요.', example_en_5 = 'He thought about it overnight and agreed.', example_ko_5 = '그는 하룻밤 생각하고 동의했어요.' WHERE id = 'w_negotiation_A1_35';

