UPDATE words SET example_en_2 = 'The total includes shipping and handling.', example_ko_2 = '총액에는 배송 및 취급 비용이 포함돼요.', example_en_3 = 'What is the total cost including taxes?', example_ko_3 = '세금 포함 총 비용이 얼마인가요?', example_en_4 = 'Please confirm the total before invoicing.', example_ko_4 = '청구 전에 총액을 확인해 주세요.', example_en_5 = 'The total was higher than we expected.', example_ko_5 = '총액이 우리가 예상했던 것보다 높았어요.' WHERE id = 'w_negotiation_A2_15';
UPDATE words SET example_en_2 = 'Are you flexible on the start date?', example_ko_2 = '시작 날짜에 유연성이 있나요?', example_en_3 = 'We need a flexible contract for this project.', example_ko_3 = '이 프로젝트에는 유연한 계약이 필요해요.', example_en_4 = 'Being flexible on small points helps close deals.', example_ko_4 = '작은 부분에서 유연하면 거래를 마무리하는 데 도움이 돼요.', example_en_5 = 'She was flexible and willing to meet halfway.', example_ko_5 = '그녀는 유연하고 절충점을 찾으려고 했어요.' WHERE id = 'w_negotiation_A2_16';
UPDATE words SET example_en_2 = 'There are three options on the table now.', example_ko_2 = '지금 테이블에 세 가지 옵션이 있어요.', example_en_3 = 'Which option works best for your timeline?', example_ko_3 = '어느 옵션이 귀사 타임라인에 가장 잘 맞나요?', example_en_4 = 'Consider all options before making a decision.', example_ko_4 = '결정을 내리기 전에 모든 옵션을 고려하세요.', example_en_5 = 'Option B is the most cost-effective choice.', example_ko_5 = '옵션 B가 가장 비용 효율적인 선택이에요.' WHERE id = 'w_negotiation_A2_17';
UPDATE words SET example_en_2 = 'The cost of maintenance should be included.', example_ko_2 = '유지 비용이 포함되어야 해요.', example_en_3 = 'Can you break down the total cost for us?', example_ko_3 = '총 비용을 항목별로 나눠주실 수 있나요?', example_en_4 = 'The cost goes up if the order is small.', example_ko_4 = '주문이 작으면 비용이 올라가요.', example_en_5 = 'We need to reduce the cost by at least 15%.', example_ko_5 = '비용을 최소 15%는 줄여야 해요.' WHERE id = 'w_negotiation_A2_18';
UPDATE words SET example_en_2 = 'I have a question about the penalty clause.', example_ko_2 = '위약금 조항에 대해 질문이 있어요.', example_en_3 = 'The question of ownership needs to be settled.', example_ko_3 = '소유권 문제를 해결해야 해요.', example_en_4 = 'Can I ask a question about the timeline?', example_ko_4 = '타임라인에 대해 질문해도 될까요?', example_en_5 = 'Her question led to a better contract clause.', example_ko_5 = '그녀의 질문이 더 나은 계약 조항으로 이어졌어요.' WHERE id = 'w_negotiation_A2_19';
UPDATE words SET example_en_2 = 'We are asking you to reduce the price by 5%.', example_ko_2 = '가격을 5% 낮춰주시기를 요청해요.', example_en_3 = 'Can you reduce the lead time to two weeks?', example_ko_3 = '리드 타임을 2주로 줄여주실 수 있나요?', example_en_4 = 'Reducing the scope will reduce the price too.', example_ko_4 = '범위를 줄이면 가격도 낮아질 거예요.', example_en_5 = 'We need to reduce delivery costs significantly.', example_ko_5 = '배송 비용을 크게 줄여야 해요.' WHERE id = 'w_negotiation_A2_20';
UPDATE words SET example_en_2 = 'We will increase the order if the price is right.', example_ko_2 = '가격이 맞으면 주문을 늘릴게요.', example_en_3 = 'Can you increase the warranty to three years?', example_ko_3 = '보증을 3년으로 늘려주실 수 있나요?', example_en_4 = 'They increased their offer by 10% after talks.', example_ko_4 = '협상 후에 그들은 제안을 10% 높였어요.', example_en_5 = 'We hope to increase our orders next quarter.', example_ko_5 = '다음 분기에 주문을 늘리기를 바라요.' WHERE id = 'w_negotiation_A2_21';
UPDATE words SET example_en_2 = 'Does the price include setup and training?', example_ko_2 = '가격에 설정과 교육이 포함되나요?', example_en_3 = 'All fees should be included in the final quote.', example_ko_3 = '모든 수수료는 최종 견적에 포함되어야 해요.', example_en_4 = 'The package includes a 12-month support plan.', example_ko_4 = '패키지에는 12개월 지원 플랜이 포함돼요.', example_en_5 = 'Please confirm what is included in this offer.', example_ko_5 = '이 제안에 무엇이 포함되는지 확인해 주세요.' WHERE id = 'w_negotiation_A2_22';
UPDATE words SET example_en_2 = 'Please consider our revised budget proposal.', example_ko_2 = '수정된 예산 제안을 고려해 주세요.', example_en_3 = 'They are considering a longer contract term.', example_ko_3 = '그들은 더 긴 계약 기간을 고려하고 있어요.', example_en_4 = 'Consider offering a volume discount to close.', example_ko_4 = '마무리하기 위해 물량 할인 제공을 고려하세요.', example_en_5 = 'We will consider the offer and respond by Monday.', example_ko_5 = '제안을 고려하고 월요일까지 응답할게요.' WHERE id = 'w_negotiation_A2_23';
UPDATE words SET example_en_2 = 'We would like to test a sample first.', example_ko_2 = '먼저 샘플을 테스트하고 싶어요.', example_en_3 = 'Can you provide a sample at no cost?', example_ko_3 = '무료로 샘플을 제공해 주실 수 있나요?', example_en_4 = 'The sample quality will determine our decision.', example_ko_4 = '샘플 품질이 우리의 결정을 결정할 거예요.', example_en_5 = 'Send the sample before the proposal deadline.', example_ko_5 = '제안 마감일 전에 샘플을 보내주세요.' WHERE id = 'w_negotiation_A2_24';
UPDATE words SET example_en_2 = 'Can we set a schedule for the next steps?', example_ko_2 = '다음 단계에 대한 일정을 정할 수 있나요?', example_en_3 = 'The schedule for delivery needs to be confirmed.', example_ko_3 = '납품 일정을 확인해야 해요.', example_en_4 = 'She sent the updated schedule to all parties.', example_ko_4 = '그녀는 업데이트된 일정을 모든 당사자에게 보냈어요.', example_en_5 = 'A clear schedule prevents misunderstandings.', example_ko_5 = '명확한 일정이 오해를 방지해요.' WHERE id = 'w_negotiation_A2_25';
UPDATE words SET example_en_2 = 'Please confirm the order quantity by Thursday.', example_ko_2 = '목요일까지 주문 수량을 확인해 주세요.', example_en_3 = 'We will confirm the deal once terms are finalized.', example_ko_3 = '조건이 최종 확정되면 거래를 확인할게요.', example_en_4 = 'Can you confirm receipt of our proposal?', example_ko_4 = '우리 제안서 수령을 확인해 주실 수 있나요?', example_en_5 = 'She confirmed everything via email that day.', example_ko_5 = '그녀는 그날 이메일로 모든 것을 확인했어요.' WHERE id = 'w_negotiation_A2_26';
UPDATE words SET example_en_2 = 'We will cancel if the quality does not improve.', example_ko_2 = '품질이 개선되지 않으면 취소할 거예요.', example_en_3 = 'They cancelled due to a change in budget.', example_ko_3 = '그들은 예산 변경으로 취소했어요.', example_en_4 = 'Please cancel only if absolutely necessary.', example_ko_4 = '절대적으로 필요한 경우에만 취소해 주세요.', example_en_5 = 'The cancellation fee is stated in clause five.', example_ko_5 = '취소 수수료가 5조에 명시되어 있어요.' WHERE id = 'w_negotiation_A2_27';
UPDATE words SET example_en_2 = 'We were charged extra for the urgent delivery.', example_ko_2 = '긴급 납품에 대해 추가 요금이 청구됐어요.', example_en_3 = 'No extra charges should apply without notice.', example_ko_3 = '사전 통보 없이 추가 요금이 부과되어서는 안 돼요.', example_en_4 = 'Is there an extra fee for international shipping?', example_ko_4 = '국제 배송에 추가 요금이 있나요?', example_en_5 = 'Extra services should be priced separately.', example_ko_5 = '추가 서비스는 별도로 가격이 책정되어야 해요.' WHERE id = 'w_negotiation_A2_28';
UPDATE words SET example_en_2 = 'There is a strict limit on the budget this year.', example_ko_2 = '올해 예산에 엄격한 한도가 있어요.', example_en_3 = 'What is the limit on order quantity per month?', example_ko_3 = '월별 주문 수량 한도가 얼마인가요?', example_en_4 = 'We cannot go beyond the agreed price limit.', example_ko_4 = '합의된 가격 한도를 초과할 수 없어요.', example_en_5 = 'Please clarify the liability limit in the contract.', example_ko_5 = '계약서의 책임 한도를 명확히 해주세요.' WHERE id = 'w_negotiation_A2_29';
UPDATE words SET example_en_2 = 'We expect the order to ship by next week.', example_ko_2 = '다음 주까지 주문이 배송되기를 기대해요.', example_en_3 = 'They expect a reply within 48 hours.', example_ko_3 = '그들은 48시간 내에 답변을 기대해요.', example_en_4 = 'We expected a better offer at this stage.', example_ko_4 = '이 단계에서 더 나은 제안을 기대했어요.', example_en_5 = 'Expect some back-and-forth before a final deal.', example_ko_5 = '최종 거래 전에 어느 정도 주고받음을 기대하세요.' WHERE id = 'w_negotiation_A2_30';
UPDATE words SET example_en_2 = 'Let me check the contract terms again.', example_ko_2 = '계약 조건을 다시 확인할게요.', example_en_3 = 'Check the figures before you send the invoice.', example_ko_3 = '청구서를 보내기 전에 수치를 확인하세요.', example_en_4 = 'She checked every clause before signing.', example_ko_4 = '그녀는 서명하기 전에 모든 조항을 확인했어요.', example_en_5 = 'Always check the fine print before agreeing.', example_ko_5 = '동의하기 전에 항상 세부 조항을 확인하세요.' WHERE id = 'w_negotiation_A2_31';
UPDATE words SET example_en_2 = 'The invoice was incorrect and needed a fix.', example_ko_2 = '청구서가 잘못되어 수정이 필요했어요.', example_en_3 = 'Can you send the invoice with a breakdown?', example_ko_3 = '항목별 내역이 있는 청구서를 보내주실 수 있나요?', example_en_4 = 'Pay the invoice within thirty days of receipt.', example_ko_4 = '청구서 수령 후 30일 이내에 지불하세요.', example_en_5 = 'She disputed the invoice and asked for a revision.', example_ko_5 = '그녀는 청구서에 이의를 제기하고 수정을 요청했어요.' WHERE id = 'w_negotiation_A2_32';
UPDATE words SET example_en_2 = 'We need a guarantee that stock will be available.', example_ko_2 = '재고가 확보된다는 보장이 필요해요.', example_en_3 = 'Can you guarantee the agreed quality level?', example_ko_3 = '합의된 품질 수준을 보장해 주실 수 있나요?', example_en_4 = 'The guarantee is valid for two years.', example_ko_4 = '보증은 2년간 유효해요.', example_en_5 = 'A money-back guarantee builds buyer confidence.', example_ko_5 = '환불 보장이 구매자 신뢰를 구축해요.' WHERE id = 'w_negotiation_A2_33';
UPDATE words SET example_en_2 = 'We will review and respond within two days.', example_ko_2 = '2일 이내에 검토하고 응답할게요.', example_en_3 = 'Please review the draft contract carefully.', example_ko_3 = '초안 계약서를 꼼꼼히 검토해 주세요.', example_en_4 = 'The legal team reviewed each clause.', example_ko_4 = '법무팀이 각 조항을 검토했어요.', example_en_5 = 'Review before signing — never skip this step.', example_ko_5 = '서명 전에 검토하세요 — 이 단계를 절대 건너뛰지 마세요.' WHERE id = 'w_negotiation_A2_34';
UPDATE words SET example_en_2 = 'Can we schedule a follow-up meeting next week?', example_ko_2 = '다음 주에 후속 회의를 예약할 수 있나요?', example_en_3 = 'The meeting ran longer than expected.', example_ko_3 = '회의가 예상보다 길어졌어요.', example_en_4 = 'She prepared a clear agenda for the meeting.', example_ko_4 = '그녀는 회의를 위해 명확한 안건을 준비했어요.', example_en_5 = 'Every meeting should end with clear action items.', example_ko_5 = '모든 회의는 명확한 실행 항목으로 끝나야 해요.' WHERE id = 'w_negotiation_A2_35';

