UPDATE words SET example_en_2 = 'Arbitration is faster and less costly than court.', example_ko_2 = '중재는 법원보다 빠르고 비용이 적게 들어요.', example_en_3 = 'Both parties agreed to binding arbitration.', example_ko_3 = '양 당사자는 구속력 있는 중재에 동의했어요.', example_en_4 = 'The arbitration panel issued its ruling last week.', example_ko_4 = '중재 패널이 지난주에 판정을 내렸어요.', example_en_5 = 'Include an arbitration clause in every major contract.', example_ko_5 = '모든 주요 계약에 중재 조항을 포함하세요.' WHERE id = 'w_negotiation_B2_01';
UPDATE words SET example_en_2 = 'Mediation helped the two sides reach a deal.', example_ko_2 = '조정이 양측이 거래에 도달하는 데 도움을 줬어요.', example_en_3 = 'A professional mediator was brought in.', example_ko_3 = '전문 조정인이 참여했어요.', example_en_4 = 'They chose mediation over costly litigation.', example_ko_4 = '그들은 비용이 많이 드는 소송 대신 조정을 선택했어요.', example_en_5 = 'Mediation preserves the business relationship.', example_ko_5 = '조정이 비즈니스 관계를 보존해요.' WHERE id = 'w_negotiation_B2_02';
UPDATE words SET example_en_2 = 'Litigation costs too much and takes too long.', example_ko_2 = '소송은 비용이 너무 많이 들고 시간이 너무 오래 걸려요.', example_en_3 = 'She settled before litigation to save costs.', example_ko_3 = '그녀는 비용 절감을 위해 소송 전에 합의했어요.', example_en_4 = 'The threat of litigation moved the negotiation forward.', example_ko_4 = '소송 위협이 협상을 앞으로 진전시켰어요.', example_en_5 = 'Both sides wanted to avoid lengthy litigation.', example_ko_5 = '양측 모두 장기 소송을 피하고 싶었어요.' WHERE id = 'w_negotiation_B2_03';
UPDATE words SET example_en_2 = 'We must cap our liability at the contract value.', example_ko_2 = '계약 금액으로 책임을 제한해야 해요.', example_en_3 = 'The liability clause needs careful review.', example_ko_3 = '책임 조항은 신중한 검토가 필요해요.', example_en_4 = 'She negotiated a lower liability cap successfully.', example_ko_4 = '그녀는 더 낮은 책임 한도를 성공적으로 협상했어요.', example_en_5 = 'Unlimited liability is a red flag in any contract.', example_ko_5 = '무제한 책임은 모든 계약에서 경고 신호예요.' WHERE id = 'w_negotiation_B2_04';
UPDATE words SET example_en_2 = 'We require a full indemnity for IP infringement.', example_ko_2 = 'IP 침해에 대한 완전한 면책이 필요해요.', example_en_3 = 'The indemnity clause was the hardest to agree on.', example_ko_3 = '면책 조항이 가장 합의하기 어려웠어요.', example_en_4 = 'Indemnity protects us from unexpected claims.', example_ko_4 = '면책이 예상치 못한 청구로부터 우리를 보호해요.', example_en_5 = 'Negotiate the scope of indemnity carefully.', example_ko_5 = '면책 범위를 신중하게 협상하세요.' WHERE id = 'w_negotiation_B2_05';
UPDATE words SET example_en_2 = 'We need a 24-month warranty on all parts.', example_ko_2 = '모든 부품에 24개월 보증이 필요해요.', example_en_3 = 'The warranty does not cover accidental damage.', example_ko_3 = '보증은 우발적 손상을 다루지 않아요.', example_en_4 = 'She extended the warranty to 36 months in the deal.', example_ko_4 = '그녀는 거래에서 보증을 36개월로 연장했어요.', example_en_5 = 'Read the warranty terms before you sign.', example_ko_5 = '서명하기 전에 보증 조건을 읽으세요.' WHERE id = 'w_negotiation_B2_06';
UPDATE words SET example_en_2 = 'The payment was held in escrow until delivery.', example_ko_2 = '납품 때까지 지불금이 에스크로에 보관됐어요.', example_en_3 = 'An escrow account protects both buyer and seller.', example_ko_3 = '에스크로 계좌가 구매자와 판매자 모두를 보호해요.', example_en_4 = 'She insisted on escrow for the first large payment.', example_ko_4 = '그녀는 첫 번째 대금 지불에 에스크로를 고집했어요.', example_en_5 = 'Use escrow for high-value international transactions.', example_ko_5 = '고가의 국제 거래에는 에스크로를 사용하세요.' WHERE id = 'w_negotiation_B2_07';
UPDATE words SET example_en_2 = 'Build a contingency budget into every deal.', example_ko_2 = '모든 거래에 예비 예산을 포함하세요.', example_en_3 = 'The contingency clause was invoked due to the delay.', example_ko_3 = '지연으로 인해 예비 조항이 발동됐어요.', example_en_4 = 'A good contingency plan prevents panic later.', example_ko_4 = '좋은 비상 계획이 나중의 당황을 예방해요.', example_en_5 = 'She negotiated a detailed contingency provision.', example_ko_5 = '그녀는 상세한 예비 조항을 협상했어요.' WHERE id = 'w_negotiation_B2_08';
UPDATE words SET example_en_2 = 'Both boards must ratify the deal this week.', example_ko_2 = '양 이사회가 이번 주에 거래를 공식 승인해야 해요.', example_en_3 = 'The shareholders ratified the merger agreement.', example_ko_3 = '주주들이 합병 합의를 공식 승인했어요.', example_en_4 = 'We need one more day to ratify internally.', example_ko_4 = '내부 공식 승인을 위해 하루가 더 필요해요.', example_en_5 = 'The contract takes effect once both sides ratify.', example_ko_5 = '양측이 공식 승인하면 계약이 발효돼요.' WHERE id = 'w_negotiation_B2_09';
UPDATE words SET example_en_2 = 'A contract signed under duress may be void.', example_ko_2 = '강요 하에 서명된 계약은 무효일 수 있어요.', example_en_3 = 'The clause was deemed void by the court.', example_ko_3 = '조항이 법원에 의해 무효로 판결됐어요.', example_en_4 = 'Check that no clause is void before you sign.', example_ko_4 = '서명 전에 무효인 조항이 없는지 확인하세요.', example_en_5 = 'A void agreement provides no legal protection.', example_ko_5 = '무효 합의는 법적 보호를 제공하지 않아요.' WHERE id = 'w_negotiation_B2_10';
UPDATE words SET example_en_2 = 'The pandemic triggered the force majeure clause.', example_ko_2 = '팬데믹이 불가항력 조항을 발동시켰어요.', example_en_3 = 'Define force majeure events very precisely.', example_ko_3 = '불가항력 사태를 매우 정확하게 정의하세요.', example_en_4 = 'Both sides invoked force majeure during the crisis.', example_ko_4 = '위기 동안 양측 모두 불가항력을 발동했어요.', example_en_5 = 'A force majeure clause must be carefully drafted.', example_ko_5 = '불가항력 조항은 신중하게 작성되어야 해요.' WHERE id = 'w_negotiation_B2_11';
UPDATE words SET example_en_2 = 'We require a signed confidentiality agreement first.', example_ko_2 = '먼저 서명된 기밀 유지 계약서가 필요해요.', example_en_3 = 'Confidentiality is critical in merger talks.', example_ko_3 = '기밀성은 합병 협상에서 매우 중요해요.', example_en_4 = 'The breach of confidentiality led to litigation.', example_ko_4 = '기밀성 위반이 소송으로 이어졌어요.', example_en_5 = 'Protect confidentiality in all written communications.', example_ko_5 = '모든 서면 의사소통에서 기밀성을 보호하세요.' WHERE id = 'w_negotiation_B2_12';
UPDATE words SET example_en_2 = 'We need to agree on the governing jurisdiction.', example_ko_2 = '준거 관할권에 합의해야 해요.', example_en_3 = 'Jurisdiction determines which law applies.', example_ko_3 = '관할권이 어느 법이 적용되는지를 결정해요.', example_en_4 = 'She negotiated for a neutral jurisdiction.', example_ko_4 = '그녀는 중립 관할권을 위해 협상했어요.', example_en_5 = 'Jurisdiction clauses matter in cross-border deals.', example_ko_5 = '관할권 조항은 국경을 초월한 거래에서 중요해요.' WHERE id = 'w_negotiation_B2_13';
UPDATE words SET example_en_2 = 'We propose an amendment to reduce the liability cap.', example_ko_2 = '책임 한도를 낮추기 위한 수정안을 제안해요.', example_en_3 = 'The amendment clarified the force majeure clause.', example_ko_3 = '수정안이 불가항력 조항을 명확히 했어요.', example_en_4 = 'Any amendment must be signed by both parties.', example_ko_4 = '모든 수정안은 양 당사자가 서명해야 해요.', example_en_5 = 'She submitted an amendment to the delivery terms.', example_ko_5 = '그녀는 납품 조건에 대한 수정안을 제출했어요.' WHERE id = 'w_negotiation_B2_14';
UPDATE words SET example_en_2 = 'The late delivery was a breach of contract.', example_ko_2 = '납품 지연은 계약 위반이었어요.', example_en_3 = 'A breach triggers the penalty clause immediately.', example_ko_3 = '위반은 즉시 위약금 조항을 발동시켜요.', example_en_4 = 'She documented every breach for future legal action.', example_ko_4 = '그녀는 향후 법적 조치를 위해 모든 위반을 문서화했어요.', example_en_5 = 'Cure the breach within seven days to avoid penalties.', example_ko_5 = '위약금을 피하려면 7일 이내에 위반을 시정하세요.' WHERE id = 'w_negotiation_B2_15';
UPDATE words SET example_en_2 = 'The clause is enforceable in Korean courts.', example_ko_2 = '조항은 한국 법원에서 집행 가능해요.', example_en_3 = 'Not all penalty clauses are legally enforceable.', example_ko_3 = '모든 위약금 조항이 법적으로 집행 가능한 것은 아니에요.', example_en_4 = 'She confirmed the clause was enforceable by law.', example_ko_4 = '그녀는 조항이 법에 의해 집행 가능하다고 확인했어요.', example_en_5 = 'An enforceable agreement protects both parties.', example_ko_5 = '집행 가능한 합의가 양 당사자를 보호해요.' WHERE id = 'w_negotiation_B2_16';
UPDATE words SET example_en_2 = 'We both signed a non-disclosure agreement today.', example_ko_2 = '오늘 우리 둘 다 비밀 유지 계약서에 서명했어요.', example_en_3 = 'The non-disclosure prevents leaks to competitors.', example_ko_3 = '비공개가 경쟁사에 대한 정보 유출을 방지해요.', example_en_4 = 'All attendees must sign the non-disclosure form.', example_ko_4 = '모든 참석자는 비공개 양식에 서명해야 해요.', example_en_5 = 'Breaching a non-disclosure carries serious penalties.', example_ko_5 = '비공개 위반은 심각한 위약금을 수반해요.' WHERE id = 'w_negotiation_B2_17';
UPDATE words SET example_en_2 = 'We agree to indemnify you against third-party suits.', example_ko_2 = '제3자 소송에 대해 귀사를 면책해 드리기로 동의해요.', example_en_3 = 'They refused to indemnify us for supply delays.', example_ko_3 = '그들은 공급 지연에 대해 우리를 면책하기를 거부했어요.', example_en_4 = 'The contract requires us to indemnify the client.', example_ko_4 = '계약은 우리가 고객을 면책해야 함을 요구해요.', example_en_5 = 'Indemnify carefully — broad language is risky.', example_ko_5 = '면책은 신중하게 — 광범위한 표현은 위험해요.' WHERE id = 'w_negotiation_B2_18';
UPDATE words SET example_en_2 = 'Each milestone triggers a payment release.', example_ko_2 = '각 이정표가 지불 해제를 발동시켜요.', example_en_3 = 'We missed the first milestone due to staffing.', example_ko_3 = '인원 문제로 첫 번째 이정표를 놓쳤어요.', example_en_4 = 'She tied the bonuses to specific project milestones.', example_ko_4 = '그녀는 보너스를 특정 프로젝트 이정표에 연동시켰어요.', example_en_5 = 'Define milestones clearly before you start work.', example_ko_5 = '작업을 시작하기 전에 이정표를 명확하게 정의하세요.' WHERE id = 'w_negotiation_B2_19';
UPDATE words SET example_en_2 = 'Exclusivity in the region gave us a big advantage.', example_ko_2 = '지역에서의 독점권이 우리에게 큰 이점을 줬어요.', example_en_3 = 'We are seeking exclusivity for three years.', example_ko_3 = '3년간의 독점권을 추구하고 있어요.', example_en_4 = 'Exclusivity agreements must state the territory clearly.', example_ko_4 = '독점 계약은 영역을 명확하게 명시해야 해요.', example_en_5 = 'She negotiated exclusivity in exchange for higher volume.', example_ko_5 = '그녀는 더 높은 물량 대가로 독점권을 협상했어요.' WHERE id = 'w_negotiation_B2_20';
UPDATE words SET example_en_2 = 'The contract includes a 90-day termination clause.', example_ko_2 = '계약에 90일 해지 조항이 포함되어 있어요.', example_en_3 = 'Termination must be given in writing, 30 days ahead.', example_ko_3 = '해지는 서면으로 30일 전에 통보해야 해요.', example_en_4 = 'She negotiated a shorter termination notice period.', example_ko_4 = '그녀는 더 짧은 해지 통보 기간을 협상했어요.', example_en_5 = 'Understand the termination rights before you sign.', example_ko_5 = '서명하기 전에 해지권을 이해하세요.' WHERE id = 'w_negotiation_B2_21';
UPDATE words SET example_en_2 = 'Their representations were later proven false.', example_ko_2 = '그들의 진술이 나중에 거짓으로 밝혀졌어요.', example_en_3 = 'Each representation must be accurate at signing.', example_ko_3 = '각 진술은 서명 시점에 정확해야 해요.', example_en_4 = 'She challenged the warranty representations in court.', example_ko_4 = '그녀는 법원에서 보증 진술에 이의를 제기했어요.', example_en_5 = 'Misrepresentation can void the entire contract.', example_ko_5 = '허위 진술은 전체 계약을 무효화할 수 있어요.' WHERE id = 'w_negotiation_B2_22';
UPDATE words SET example_en_2 = 'We must complete due diligence before any payment.', example_ko_2 = '어떤 지불 전에도 실사를 완료해야 해요.', example_en_3 = 'Due diligence revealed some financial concerns.', example_ko_3 = '실사에서 몇 가지 재무적 우려가 드러났어요.', example_en_4 = 'She ran due diligence on all three suppliers.', example_ko_4 = '그녀는 세 공급업체 모두에 대해 실사를 진행했어요.', example_en_5 = 'Never skip due diligence on a major acquisition.', example_ko_5 = '주요 인수에서는 실사를 절대 건너뛰지 마세요.' WHERE id = 'w_negotiation_B2_23';
UPDATE words SET example_en_2 = 'The indemnification clause is too broad as written.', example_ko_2 = '면책 조항이 작성된 대로는 너무 광범위해요.', example_en_3 = 'She negotiated a mutual indemnification provision.', example_ko_3 = '그녀는 상호 면책 조항을 협상했어요.', example_en_4 = 'Indemnification for negligence was excluded.', example_ko_4 = '과실에 대한 면책은 제외됐어요.', example_en_5 = 'Review the indemnification scope with your lawyer.', example_ko_5 = '변호사와 함께 면책 범위를 검토하세요.' WHERE id = 'w_negotiation_B2_24';
UPDATE words SET example_en_2 = 'The governing law is specified as Korean law.', example_ko_2 = '준거법은 한국법으로 명시되어 있어요.', example_en_3 = 'She insisted on a neutral governing law.', example_ko_3 = '그녀는 중립 준거법을 고집했어요.', example_en_4 = 'Agreeing on governing law avoids future disputes.', example_ko_4 = '준거법에 합의하면 향후 분쟁을 피할 수 있어요.', example_en_5 = 'The governing law clause was the last to be agreed.', example_ko_5 = '준거법 조항이 마지막으로 합의됐어요.' WHERE id = 'w_negotiation_B2_25';
UPDATE words SET example_en_2 = 'Valid consideration is required for a binding deal.', example_ko_2 = '구속력 있는 거래에는 유효한 대가가 필요해요.', example_en_3 = 'Without consideration, the promise is not enforceable.', example_ko_3 = '대가 없이는 약속이 집행될 수 없어요.', example_en_4 = 'She confirmed that adequate consideration was present.', example_ko_4 = '그녀는 적절한 대가가 존재함을 확인했어요.', example_en_5 = 'The consideration clause defines the exchange of value.', example_ko_5 = '대가 조항이 가치 교환을 정의해요.' WHERE id = 'w_negotiation_B2_26';
UPDATE words SET example_en_2 = 'The severability clause saved the contract.', example_ko_2 = '분리 가능성 조항이 계약을 살렸어요.', example_en_3 = 'A severability clause is standard in most contracts.', example_ko_3 = '분리 가능성 조항은 대부분의 계약에서 표준이에요.', example_en_4 = 'She requested a severability clause early in talks.', example_ko_4 = '그녀는 협상 초반에 분리 가능성 조항을 요청했어요.', example_en_5 = 'Always include a severability clause as protection.', example_ko_5 = '보호 장치로 항상 분리 가능성 조항을 포함하세요.' WHERE id = 'w_negotiation_B2_27';
UPDATE words SET example_en_2 = 'The contractor posted a performance bond upfront.', example_ko_2 = '계약자가 선불로 이행 보증금을 예치했어요.', example_en_3 = 'We require a performance bond for all new vendors.', example_ko_3 = '모든 새 공급업체에 이행 보증금이 필요해요.', example_en_4 = 'The performance bond was released upon completion.', example_ko_4 = '완료 시 이행 보증금이 해제됐어요.', example_en_5 = 'A performance bond ensures the work gets done.', example_ko_5 = '이행 보증금이 작업이 완료되도록 보장해요.' WHERE id = 'w_negotiation_B2_28';
UPDATE words SET example_en_2 = 'Act in good faith at every stage of negotiation.', example_ko_2 = '협상의 모든 단계에서 선의로 행동하세요.', example_en_3 = 'Both parties are expected to negotiate in good faith.', example_ko_3 = '양 당사자가 선의로 협상할 것을 기대해요.', example_en_4 = 'She accused them of not acting in good faith.', example_ko_4 = '그녀는 그들이 선의로 행동하지 않는다고 비난했어요.', example_en_5 = 'Good faith dealings lead to better long-term outcomes.', example_ko_5 = '선의 거래가 더 나은 장기적 결과로 이어져요.' WHERE id = 'w_negotiation_B2_29';
UPDATE words SET example_en_2 = 'Sixty days late is a material breach here.', example_ko_2 = '60일 지연은 여기서 중대 위반이에요.', example_en_3 = 'A material breach allows termination immediately.', example_ko_3 = '중대 위반은 즉시 해지를 허용해요.', example_en_4 = 'She proved a material breach and won the dispute.', example_ko_4 = '그녀는 중대 위반을 증명하고 분쟁에서 이겼어요.', example_en_5 = 'Not all breaches are material — context matters.', example_ko_5 = '모든 위반이 중대한 것은 아니에요 — 맥락이 중요해요.' WHERE id = 'w_negotiation_B2_30';
UPDATE words SET example_en_2 = 'Their counterpart agreed to the revised schedule.', example_ko_2 = '상대방이 수정된 일정에 동의했어요.', example_en_3 = 'She worked closely with her legal counterpart.', example_ko_3 = '그녀는 법무 상대방과 긴밀하게 협력했어요.', example_en_4 = 'Know your counterpart''s priorities before the meeting.', example_ko_4 = '회의 전에 상대방의 우선순위를 파악하세요.', example_en_5 = 'The counterpart signed the deal ahead of schedule.', example_ko_5 = '상대방이 일정보다 일찍 거래에 서명했어요.' WHERE id = 'w_negotiation_B2_31';
UPDATE words SET example_en_2 = 'She signed the waiver before the inspection.', example_ko_2 = '그녀는 검사 전에 권리 포기서에 서명했어요.', example_en_3 = 'A waiver cannot be implied — it must be explicit.', example_ko_3 = '권리 포기는 묵시적일 수 없어요 — 명시적이어야 해요.', example_en_4 = 'He agreed to a limited waiver of liability.', example_ko_4 = '그는 제한적 책임 포기에 동의했어요.', example_en_5 = 'Never sign a blanket waiver without legal advice.', example_ko_5 = '법적 조언 없이 포괄적 권리 포기서에 서명하지 마세요.' WHERE id = 'w_negotiation_B2_32';
UPDATE words SET example_en_2 = 'The retention is released after final sign-off.', example_ko_2 = '유보금은 최종 승인 후에 해제돼요.', example_en_3 = 'A 5% retention was agreed at the start.', example_ko_3 = '시작 시 5% 유보금에 합의했어요.', example_en_4 = 'She negotiated the retention period down to 6 months.', example_ko_4 = '그녀는 유보 기간을 6개월로 낮추는 협상을 했어요.', example_en_5 = 'Retention provides security against defective work.', example_ko_5 = '유보금이 결함 있는 작업에 대한 보안을 제공해요.' WHERE id = 'w_negotiation_B2_33';
UPDATE words SET example_en_2 = 'The price cap protects us from sudden increases.', example_ko_2 = '가격 상한이 갑작스러운 인상으로부터 우리를 보호해요.', example_en_3 = 'She negotiated a price cap for three years.', example_ko_3 = '그녀는 3년간의 가격 상한을 협상했어요.', example_en_4 = 'A price cap clause is essential in long-term contracts.', example_ko_4 = '가격 상한 조항은 장기 계약에서 필수예요.', example_en_5 = 'Agree on a price cap before signing any multi-year deal.', example_ko_5 = '다년 거래에 서명하기 전에 가격 상한에 합의하세요.' WHERE id = 'w_negotiation_B2_34';
UPDATE words SET example_en_2 = 'Liquidated damages discourage delays effectively.', example_ko_2 = '손해배상 예정액이 지연을 효과적으로 억제해요.', example_en_3 = 'She challenged the liquidated damages rate as a penalty.', example_ko_3 = '그녀는 손해배상 예정액이 위약금이라고 이의를 제기했어요.', example_en_4 = 'The liquidated damages clause was revised down by 50%.', example_ko_4 = '손해배상 예정액 조항이 50% 낮아졌어요.', example_en_5 = 'Liquidated damages must reflect a genuine pre-estimate.', example_ko_5 = '손해배상 예정액은 진정한 사전 예상치를 반영해야 해요.' WHERE id = 'w_negotiation_B2_35';

