-- C2 (35단어)
-- ══════════════════════════════════════════════════════════════════
UPDATE words SET example_en_2 = 'Estoppel barred the claimant from changing its position.', example_ko_2 = '금반언이 청구인이 입장을 바꾸는 것을 막았어요.', example_en_3 = 'She raised proprietary estoppel over the disputed land.', example_ko_3 = '그녀는 분쟁 토지에 대해 재산권적 금반언을 제기했어요.', example_en_4 = 'Estoppel requires reliance and a clear representation.', example_ko_4 = '금반언은 신뢰와 명확한 진술을 요구해요.', example_en_5 = 'The estoppel doctrine prevented the bank from foreclosing.', example_ko_5 = '금반언 원칙이 은행의 담보권 실행을 막았어요.' WHERE id = 'w_negotiation_C2_01';
UPDATE words SET example_en_2 = 'Novation requires the consent of all three parties.', example_ko_2 = '계약 갱신은 세 당사자 모두의 동의가 필요해요.', example_en_3 = 'Through novation, the new partner assumed all debt.', example_ko_3 = '계약 갱신을 통해 새 파트너가 모든 부채를 인수했어요.', example_en_4 = 'She proposed novation to exit the joint venture.', example_ko_4 = '그녀는 합작 투자를 탈퇴하기 위해 계약 갱신을 제안했어요.', example_en_5 = 'Novation is the cleanest way to substitute a party.', example_ko_5 = '계약 갱신은 당사자를 교체하는 가장 깔끔한 방법이에요.' WHERE id = 'w_negotiation_C2_02';
UPDATE words SET example_en_2 = 'She pursued rescission after discovering the fraud.', example_ko_2 = '그녀는 사기를 발견한 후 계약 취소를 추구했어요.', example_en_3 = 'Rescission is barred if a third party has acquired rights.', example_ko_3 = '제3자가 권리를 취득하면 계약 취소가 차단돼요.', example_en_4 = 'The rescission restored both parties to the status quo ante.', example_ko_4 = '계약 취소가 양 당사자를 원래 상태로 회복시켰어요.', example_en_5 = 'Election to affirm bars a subsequent claim for rescission.', example_ko_5 = '계약 존속 선택이 이후의 계약 취소 청구를 차단해요.' WHERE id = 'w_negotiation_C2_03';
UPDATE words SET example_en_2 = 'She claimed quantum meruit for the work already done.', example_ko_2 = '그녀는 이미 완료된 작업에 대해 정당한 보수를 청구했어요.', example_en_3 = 'Quantum meruit fills the gap when no price is agreed.', example_ko_3 = '정당한 보수 청구권이 가격이 합의되지 않은 경우의 공백을 채워요.', example_en_4 = 'The reasonable value awarded on quantum meruit was fair.', example_ko_4 = '정당한 보수 청구권에 따라 지급된 합리적 가치가 공정했어요.', example_en_5 = 'Quantum meruit prevents unjust enrichment of one party.', example_ko_5 = '정당한 보수 청구권이 일방 당사자의 부당 이득을 방지해요.' WHERE id = 'w_negotiation_C2_04';
UPDATE words SET example_en_2 = 'The tortious interference destroyed the existing contract.', example_ko_2 = '불법 행위 간섭이 기존 계약을 파기했어요.', example_en_3 = 'She proved tortious conduct with documentary evidence.', example_ko_3 = '그녀는 문서 증거로 불법 행위를 증명했어요.', example_en_4 = 'A tortious misrepresentation induced her to sign.', example_ko_4 = '불법 행위 허위 진술이 그녀를 서명하도록 유도했어요.', example_en_5 = 'Tortious liability can co-exist with contractual liability.', example_ko_5 = '불법 행위 책임은 계약상 책임과 공존할 수 있어요.' WHERE id = 'w_negotiation_C2_05';
UPDATE words SET example_en_2 = 'Without mens rea, there can be no criminal conviction.', example_ko_2 = '범의 없이는 형사 유죄 판결이 없어요.', example_en_3 = 'She argued her client lacked the necessary mens rea.', example_ko_3 = '그녀는 의뢰인에게 필요한 범의가 없다고 주장했어요.', example_en_4 = 'Mens rea distinguishes a crime from an accident.', example_ko_4 = '범의가 범죄를 사고와 구별해요.', example_en_5 = 'Strict liability offences require no mens rea.', example_ko_5 = '엄격 책임 위반은 범의가 필요 없어요.' WHERE id = 'w_negotiation_C2_06';
UPDATE words SET example_en_2 = 'The actus reus was established beyond reasonable doubt.', example_ko_2 = '범죄 행위가 합리적 의심 없이 입증됐어요.', example_en_3 = 'She argued the actus reus was involuntary.', example_ko_3 = '그녀는 범죄 행위가 비자발적이라고 주장했어요.', example_en_4 = 'Both actus reus and mens rea must be proved.', example_ko_4 = '범죄 행위와 범의 모두 증명되어야 해요.', example_en_5 = 'The actus reus consisted of a deliberate omission.', example_ko_5 = '범죄 행위는 의도적인 부작위로 이루어져 있어요.' WHERE id = 'w_negotiation_C2_07';
UPDATE words SET example_en_2 = 'Promissory estoppel was applied to enforce the rent reduction.', example_ko_2 = '임대료 인하를 집행하기 위해 약속적 금반언이 적용됐어요.', example_en_3 = 'She relied on promissory estoppel to hold them to the offer.', example_ko_3 = '그녀는 그들을 제안에 묶어두기 위해 약속적 금반언에 의존했어요.', example_en_4 = 'Promissory estoppel is a shield, not a sword.', example_ko_4 = '약속적 금반언은 방패이지 창이 아니에요.', example_en_5 = 'Detriment must be shown for promissory estoppel to apply.', example_ko_5 = '약속적 금반언이 적용되려면 불이익이 입증되어야 해요.' WHERE id = 'w_negotiation_C2_08';
UPDATE words SET example_en_2 = 'The executory contract was assigned to the acquirer.', example_ko_2 = '미이행 계약이 인수자에게 양도됐어요.', example_en_3 = 'She asked to reject the burdensome executory contracts.', example_ko_3 = '그녀는 부담스러운 미이행 계약들을 거부할 것을 요청했어요.', example_en_4 = 'Executory contracts survive the seller''s insolvency.', example_ko_4 = '미이행 계약은 판매자의 파산 후에도 유효해요.', example_en_5 = 'Both sides had executory obligations at the time of dispute.', example_ko_5 = '분쟁 시점에 양측 모두 미이행 의무가 있었어요.' WHERE id = 'w_negotiation_C2_09';
UPDATE words SET example_en_2 = 'The liquidated damages clause was upheld as a genuine pre-estimate.', example_ko_2 = '약정 손해배상액 조항이 진정한 사전 예상치로 유효화됐어요.', example_en_3 = 'She argued the liquidated damages were extravagant and void.', example_ko_3 = '그녀는 약정 손해배상액이 과도하고 무효라고 주장했어요.', example_en_4 = 'Liquidated damages save both parties from proving actual loss.', example_ko_4 = '약정 손해배상액은 양 당사자가 실제 손실을 증명하는 것을 절약해요.', example_en_5 = 'She negotiated the liquidated damages cap to protect her firm.', example_ko_5 = '그녀는 회사를 보호하기 위해 약정 손해배상액 한도를 협상했어요.' WHERE id = 'w_negotiation_C2_10';
UPDATE words SET example_en_2 = 'She pled unjust enrichment as an alternative cause of action.', example_ko_2 = '그녀는 대안적 소인으로 부당 이득을 주장했어요.', example_en_3 = 'Unjust enrichment arises when one party is unfairly benefited.', example_ko_3 = '부당 이득은 한 당사자가 불공정하게 혜택을 받을 때 발생해요.', example_en_4 = 'The unjust enrichment claim required proof of benefit received.', example_ko_4 = '부당 이득 청구는 받은 혜택의 증명을 요구했어요.', example_en_5 = 'Restitution is the typical remedy for unjust enrichment.', example_ko_5 = '원상 회복이 부당 이득에 대한 전형적인 구제책이에요.' WHERE id = 'w_negotiation_C2_11';
UPDATE words SET example_en_2 = 'The court ordered restitution of all sums unjustly taken.', example_ko_2 = '법원은 부당하게 취한 모든 금액의 반환을 명령했어요.', example_en_3 = 'She sought restitution after the contract was rescinded.', example_ko_3 = '그녀는 계약이 취소된 후 원상 회복을 구했어요.', example_en_4 = 'Restitution puts the claimant back to their original position.', example_ko_4 = '원상 회복이 청구인을 원래 위치로 되돌려요.', example_en_5 = 'A restitution claim is independent of the contract itself.', example_ko_5 = '원상 회복 청구는 계약 자체와 독립적이에요.' WHERE id = 'w_negotiation_C2_12';
UPDATE words SET example_en_2 = 'The nemo dat rule voided the buyer''s title claim.', example_ko_2 = '권리 이전 불가 원칙이 매수인의 소유권 청구를 무효화했어요.', example_en_3 = 'She relied on nemo dat to recover the stolen goods.', example_ko_3 = '그녀는 훔친 물건을 되찾기 위해 권리 이전 불가 원칙에 의존했어요.', example_en_4 = 'The nemo dat rule protects true owners against rogues.', example_ko_4 = '권리 이전 불가 원칙이 진정한 소유자를 악당으로부터 보호해요.', example_en_5 = 'Exceptions to nemo dat apply in market overt situations.', example_ko_5 = '권리 이전 불가 원칙의 예외는 공개 시장 상황에 적용돼요.' WHERE id = 'w_negotiation_C2_13';
UPDATE words SET example_en_2 = 'Contra proferentem was applied against the insurer.', example_ko_2 = '작성자 불이익 원칙이 보험사에 적용됐어요.', example_en_3 = 'She used contra proferentem to widen the coverage.', example_ko_3 = '그녀는 보장 범위를 넓히기 위해 작성자 불이익 원칙을 사용했어요.', example_en_4 = 'Contra proferentem only applies if the clause is truly ambiguous.', example_ko_4 = '작성자 불이익 원칙은 조항이 진정으로 모호할 때만 적용돼요.', example_en_5 = 'Clear drafting is the best defence against contra proferentem.', example_ko_5 = '명확한 작성이 작성자 불이익 원칙에 대한 최선의 방어예요.' WHERE id = 'w_negotiation_C2_14';
UPDATE words SET example_en_2 = 'The contract was discharged for frustration of purpose.', example_ko_2 = '계약이 목적 이행 불능으로 해제됐어요.', example_en_3 = 'She argued frustration of purpose due to the export ban.', example_ko_3 = '그녀는 수출 금지로 인한 목적 이행 불능을 주장했어요.', example_en_4 = 'Frustration of purpose is rarely upheld by courts.', example_ko_4 = '목적 이행 불능은 법원에 의해 좀처럼 인정되지 않아요.', example_en_5 = 'The doctrine of frustration of purpose has narrow scope.', example_ko_5 = '목적 이행 불능 원칙은 적용 범위가 좁아요.' WHERE id = 'w_negotiation_C2_15';
UPDATE words SET example_en_2 = 'The court dismissed the fraud claim under in pari delicto.', example_ko_2 = '법원은 동등 과실 원칙에 따라 사기 청구를 기각했어요.', example_en_3 = 'She argued in pari delicto barred the other side''s claim.', example_ko_3 = '그녀는 동등 과실 원칙이 상대방의 청구를 막는다고 주장했어요.', example_en_4 = 'In pari delicto prevents courts from rewarding wrongdoers.', example_ko_4 = '동등 과실 원칙이 법원이 위법자에게 보상하는 것을 방지해요.', example_en_5 = 'The in pari delicto defence succeeded at first instance.', example_ko_5 = '동등 과실 원칙 방어가 1심에서 성공했어요.' WHERE id = 'w_negotiation_C2_16';
UPDATE words SET example_en_2 = 'The clean hands doctrine barred the claimant''s relief.', example_ko_2 = '형평법상 청결 원칙이 청구인의 구제책을 차단했어요.', example_en_3 = 'She invoked the clean hands doctrine against the landlord.', example_ko_3 = '그녀는 집주인에 대해 형평법상 청결 원칙을 발동했어요.', example_en_4 = 'A party seeking equity must come with clean hands.', example_ko_4 = '형평법적 구제를 구하는 당사자는 깨끗한 손으로 나와야 해요.', example_en_5 = 'The clean hands doctrine is a discretionary defence.', example_ko_5 = '형평법상 청결 원칙은 재량적 방어예요.' WHERE id = 'w_negotiation_C2_17';
UPDATE words SET example_en_2 = 'Mutuality of obligation is essential for a valid contract.', example_ko_2 = '쌍방 의무는 유효한 계약에 필수적이에요.', example_en_3 = 'The court found no mutuality of obligation in the arrangement.', example_ko_3 = '법원은 약정에서 쌍방 의무를 찾지 못했어요.', example_en_4 = 'She argued lack of mutuality of obligation made it voidable.', example_ko_4 = '그녀는 쌍방 의무의 결여가 취소 가능하게 만든다고 주장했어요.', example_en_5 = 'Without mutuality of obligation, there is no binding contract.', example_ko_5 = '쌍방 의무 없이는 구속력 있는 계약이 없어요.' WHERE id = 'w_negotiation_C2_18';
UPDATE words SET example_en_2 = 'The funding arrangement was struck down as champerty.', example_ko_2 = '자금 조달 약정이 소송 지원 계약으로 무효화됐어요.', example_en_3 = 'She argued the fee structure amounted to champerty.', example_ko_3 = '그녀는 수수료 구조가 소송 지원 계약에 해당한다고 주장했어요.', example_en_4 = 'Third-party litigation funding is sometimes challenged as champerty.', example_ko_4 = '제3자 소송 자금 조달은 때로 소송 지원 계약으로 이의가 제기돼요.', example_en_5 = 'Laws on champerty vary significantly between jurisdictions.', example_ko_5 = '소송 지원 계약에 관한 법률은 관할권마다 크게 달라요.' WHERE id = 'w_negotiation_C2_19';
UPDATE words SET example_en_2 = 'Subrogation rights were exercised after the claim was settled.', example_ko_2 = '청구가 해결된 후 대위 청구권이 행사됐어요.', example_en_3 = 'She waived subrogation rights in the insurance policy.', example_ko_3 = '그녀는 보험 약관에서 대위 청구권을 포기했어요.', example_en_4 = 'Subrogation prevents double recovery by the insured.', example_ko_4 = '대위 청구권이 피보험자의 이중 회수를 방지해요.', example_en_5 = 'She negotiated a full waiver of subrogation rights.', example_ko_5 = '그녀는 대위 청구권의 완전한 포기를 협상했어요.' WHERE id = 'w_negotiation_C2_20';
UPDATE words SET example_en_2 = 'The laches defence succeeded due to the long delay.', example_ko_2 = '오랜 지연으로 권리 해태 방어가 성공했어요.', example_en_3 = 'She argued laches barred the equitable claim.', example_ko_3 = '그녀는 권리 해태가 형평법적 청구를 차단한다고 주장했어요.', example_en_4 = 'Laches applies in equity where time limits do not.', example_ko_4 = '권리 해태는 시효 제한이 적용되지 않는 형평법에서 적용돼요.', example_en_5 = 'Unreasonable delay triggers the doctrine of laches.', example_ko_5 = '불합리한 지연이 권리 해태 원칙을 발동시켜요.' WHERE id = 'w_negotiation_C2_21';
UPDATE words SET example_en_2 = 'The court allowed piercing the veil to recover the debt.', example_ko_2 = '법원은 채무 회수를 위해 법인격 부인을 허용했어요.', example_en_3 = 'She sought piercing the veil due to deliberate fraud.', example_ko_3 = '그녀는 의도적인 사기로 인해 법인격 부인을 구했어요.', example_en_4 = 'Piercing the veil is a remedy of last resort.', example_ko_4 = '법인격 부인은 최후 수단의 구제책이에요.', example_en_5 = 'English courts rarely grant piercing the veil.', example_ko_5 = '영국 법원은 법인격 부인을 좀처럼 허가하지 않아요.' WHERE id = 'w_negotiation_C2_22';
UPDATE words SET example_en_2 = 'The judge issued a nunc pro tunc order to correct the filing.', example_ko_2 = '판사는 서류 제출을 수정하기 위해 소급 효력 명령을 발부했어요.', example_en_3 = 'She applied for a nunc pro tunc amendment to the decree.', example_ko_3 = '그녀는 판결에 대한 소급 효력 수정을 신청했어요.', example_en_4 = 'A nunc pro tunc order corrects the record retroactively.', example_ko_4 = '소급 효력 명령이 기록을 소급하여 수정해요.', example_en_5 = 'Nunc pro tunc relief is granted only to correct clerical errors.', example_ko_5 = '소급 효력 구제는 서기 오류 수정에만 허가돼요.' WHERE id = 'w_negotiation_C2_23';
UPDATE words SET example_en_2 = 'The contract was void ab initio due to illegality.', example_ko_2 = '계약이 불법성으로 인해 처음부터 무효였어요.', example_en_3 = 'She argued the consent was never given ab initio.', example_ko_3 = '그녀는 동의가 처음부터 주어지지 않았다고 주장했어요.', example_en_4 = 'A contract void ab initio has no legal effect at all.', example_ko_4 = '처음부터 무효인 계약은 법적 효력이 전혀 없어요.', example_en_5 = 'Misrepresentation can render a contract void ab initio.', example_ko_5 = '허위 진술은 계약을 처음부터 무효로 만들 수 있어요.' WHERE id = 'w_negotiation_C2_24';
UPDATE words SET example_en_2 = 'Economic duress made the signature involuntary.', example_ko_2 = '경제적 강박이 서명을 비자발적으로 만들었어요.', example_en_3 = 'She pleaded economic duress to avoid the penalty clause.', example_ko_3 = '그녀는 위약금 조항을 피하기 위해 경제적 강박을 주장했어요.', example_en_4 = 'Economic duress requires illegitimate pressure and no alternative.', example_ko_4 = '경제적 강박은 부당한 압박과 대안 부재를 요구해요.', example_en_5 = 'The economic duress claim was upheld and the contract voided.', example_ko_5 = '경제적 강박 청구가 인정되어 계약이 무효화됐어요.' WHERE id = 'w_negotiation_C2_25';
UPDATE words SET example_en_2 = 'Her affirmation of the contract barred the rescission claim.', example_ko_2 = '계약 존속 선택이 계약 취소 청구를 차단했어요.', example_en_3 = 'She made an affirmation by accepting further payments.', example_ko_3 = '그녀는 추가 지불을 수락함으로써 계약 존속을 선택했어요.', example_en_4 = 'Affirmation must be made with full knowledge of the breach.', example_ko_4 = '계약 존속 선택은 위반을 완전히 인지한 상태에서 이루어져야 해요.', example_en_5 = 'Once affirmation is made, rescission is no longer available.', example_ko_5 = '계약 존속이 선택되면 계약 취소는 더 이상 가능하지 않아요.' WHERE id = 'w_negotiation_C2_26';
UPDATE words SET example_en_2 = 'The court upheld equitable estoppel in favour of the tenant.', example_ko_2 = '법원이 세입자에게 유리한 형평법상 금반언을 지지했어요.', example_en_3 = 'She raised equitable estoppel to prevent the eviction.', example_ko_3 = '그녀는 퇴거를 막기 위해 형평법상 금반언을 제기했어요.', example_en_4 = 'Equitable estoppel requires a clear representation and reliance.', example_ko_4 = '형평법상 금반언은 명확한 진술과 신뢰를 요구해요.', example_en_5 = 'She successfully invoked equitable estoppel to protect her rights.', example_ko_5 = '그녀는 권리를 보호하기 위해 형평법상 금반언을 성공적으로 발동했어요.' WHERE id = 'w_negotiation_C2_27';
UPDATE words SET example_en_2 = 'Offer and acceptance must be clear and unconditional.', example_ko_2 = '청약과 승낙은 명확하고 무조건적이어야 해요.', example_en_3 = 'She argued there was no valid offer and acceptance.', example_ko_3 = '그녀는 유효한 청약과 승낙이 없었다고 주장했어요.', example_en_4 = 'Offer and acceptance are the building blocks of a contract.', example_ko_4 = '청약과 승낙이 계약의 구성 요소예요.', example_en_5 = 'A counter-offer destroys the original offer and acceptance.', example_ko_5 = '역제안이 원래의 청약과 승낙을 무효화해요.' WHERE id = 'w_negotiation_C2_28';
UPDATE words SET example_en_2 = 'The court ordered rectification to correct the obvious error.', example_ko_2 = '법원은 명백한 오류를 수정하기 위해 계약서 수정을 명령했어요.', example_en_3 = 'She sought rectification of the mistaken price clause.', example_ko_3 = '그녀는 잘못된 가격 조항의 수정을 구했어요.', example_en_4 = 'Rectification requires proof of common prior agreement.', example_ko_4 = '계약서 수정은 공통 이전 합의의 증명을 요구해요.', example_en_5 = 'A court may grant rectification even after the contract is signed.', example_ko_5 = '법원은 계약 서명 후에도 계약서 수정을 허가할 수 있어요.' WHERE id = 'w_negotiation_C2_29';
UPDATE words SET example_en_2 = 'The solus agreement was challenged on public policy grounds.', example_ko_2 = '독점 공급 계약이 공공 정책을 근거로 이의 제기됐어요.', example_en_3 = 'She negotiated a time-limited solus agreement of five years.', example_ko_3 = '그녀는 5년의 기간 제한 독점 공급 계약을 협상했어요.', example_en_4 = 'A solus agreement must not unreasonably restrain trade.', example_ko_4 = '독점 공급 계약은 거래를 불합리하게 제한해서는 안 돼요.', example_en_5 = 'The court voided the solus agreement as oppressive.', example_ko_5 = '법원은 독점 공급 계약을 억압적이라고 무효화했어요.' WHERE id = 'w_negotiation_C2_30';
UPDATE words SET example_en_2 = 'The agreement was void for champerty and maintenance.', example_ko_2 = '합의가 소송 지원 금지 원칙으로 무효였어요.', example_en_3 = 'She argued the funder''s role amounted to maintenance.', example_ko_3 = '그녀는 자금 제공자의 역할이 소송 지원에 해당한다고 주장했어요.', example_en_4 = 'Champerty and maintenance are becoming less relevant today.', example_ko_4 = '소송 지원 금지 원칙은 오늘날 덜 관련성이 있어지고 있어요.', example_en_5 = 'She reviewed the funding arrangement for champerty and maintenance risk.', example_ko_5 = '그녀는 소송 지원 금지 원칙 위험에 대해 자금 조달 약정을 검토했어요.' WHERE id = 'w_negotiation_C2_31';
UPDATE words SET example_en_2 = 'The court applied cy-pres to the failed charitable trust.', example_ko_2 = '법원은 실패한 자선 신탁에 유사 목적 원칙을 적용했어요.', example_en_3 = 'She proposed a cy-pres scheme to the Charity Commission.', example_ko_3 = '그녀는 자선 위원회에 유사 목적 계획을 제안했어요.', example_en_4 = 'Cy-pres preserves charitable funds when the purpose fails.', example_ko_4 = '유사 목적 원칙이 목적이 실패할 때 자선 기금을 보존해요.', example_en_5 = 'The cy-pres doctrine applies only in charitable trust cases.', example_ko_5 = '유사 목적 원칙은 자선 신탁 사건에만 적용돼요.' WHERE id = 'w_negotiation_C2_32';
UPDATE words SET example_en_2 = 'She successfully pleaded non est factum to void the deed.', example_ko_2 = '그녀는 증서를 무효화하기 위해 서명 착오를 성공적으로 주장했어요.', example_en_3 = 'Non est factum requires the document to be fundamentally different.', example_ko_3 = '서명 착오는 문서가 근본적으로 다를 것을 요구해요.', example_en_4 = 'A negligent failure to read cannot support non est factum.', example_ko_4 = '읽기를 소홀히 한 것은 서명 착오를 뒷받침할 수 없어요.', example_en_5 = 'Non est factum is a rare and narrowly applied defence.', example_ko_5 = '서명 착오는 드물고 좁게 적용되는 방어예요.' WHERE id = 'w_negotiation_C2_33';
UPDATE words SET example_en_2 = 'Under caveat emptor, the buyer takes all risks.', example_ko_2 = '구매자 위험 부담 원칙에 따라 구매자가 모든 위험을 부담해요.', example_en_3 = 'She relied on caveat emptor to resist the buyer''s claim.', example_ko_3 = '그녀는 구매자의 청구에 저항하기 위해 구매자 위험 부담 원칙에 의존했어요.', example_en_4 = 'Modern consumer law significantly limits caveat emptor.', example_ko_4 = '현대 소비자법이 구매자 위험 부담 원칙을 크게 제한해요.', example_en_5 = 'Caveat emptor still applies in many commercial property deals.', example_ko_5 = '구매자 위험 부담 원칙은 많은 상업 부동산 거래에 여전히 적용돼요.' WHERE id = 'w_negotiation_C2_34';
UPDATE words SET example_en_2 = 'The uberrimae fidei duty requires full disclosure.', example_ko_2 = '최고 선의 의무는 완전한 공개를 요구해요.', example_en_3 = 'She breached uberrimae fidei by hiding her medical history.', example_ko_3 = '그녀는 병력을 숨김으로써 최고 선의 의무를 위반했어요.', example_en_4 = 'Uberrimae fidei applies to all insurance contracts by default.', example_ko_4 = '최고 선의 의무는 모든 보험 계약에 기본적으로 적용돼요.', example_en_5 = 'A breach of uberrimae fidei entitles the insurer to avoid the policy.', example_ko_5 = '최고 선의 의무 위반은 보험사에게 보험 계약 취소권을 줘요.' WHERE id = 'w_negotiation_C2_35';

