UPDATE words SET example_en_2 = 'Intergovernmentalism explains why EU foreign policy often lacks coherence.', example_ko_2 = '정부 간주의는 EU 외교 정책이 왜 종종 일관성이 없는지를 설명해요.', example_en_3 = 'The debate between supranationalism and intergovernmentalism shapes EU reform.', example_ko_3 = '초국가주의와 정부 간주의 사이의 논쟁이 EU 개혁을 형성해요.', example_en_4 = 'Under intergovernmentalism, each member state retains a veto on key decisions.', example_ko_4 = '정부 간주의 하에서 각 회원국은 주요 결정에 거부권을 보유해요.', example_en_5 = 'Intergovernmentalism prioritizes national sovereignty over collective efficiency.', example_ko_5 = '정부 간주의는 집단적 효율성보다 국가 주권을 우선시해요.' WHERE id = 'w_news_C2_10';

UPDATE words SET example_en_2 = 'The country is in a state of political liminality after the failed election.', example_ko_2 = '그 나라는 실패한 선거 이후 정치적 경계성 상태에 있어요.', example_en_3 = 'Post-conflict societies often inhabit a prolonged period of liminality.', example_ko_3 = '분쟁 후 사회는 종종 장기적인 경계성 기간에 머물러요.', example_en_4 = 'Liminality can be productive: it opens space for new political possibilities.', example_ko_4 = '경계성은 생산적일 수 있어요. 새로운 정치적 가능성의 공간을 열거든요.', example_en_5 = 'The concept of liminality helps explain transitions between political regimes.', example_ko_5 = '경계성 개념은 정치적 체제 간의 전환을 설명하는 데 도움이 돼요.' WHERE id = 'w_news_C2_11';

