UPDATE words SET example_en_2 = 'American exceptionalism has often been invoked to justify unilateral action.', example_ko_2 = '미국 예외주의는 종종 일방적 행동을 정당화하기 위해 언급됐어요.', example_en_3 = 'Exceptionalism can prevent a country from engaging in critical self-reflection.', example_ko_3 = '예외주의는 나라가 비판적 자기 성찰에 참여하는 것을 막을 수 있어요.', example_en_4 = 'Critics of exceptionalism argue that no nation is above international law.', example_ko_4 = '예외주의 비평가들은 어떤 나라도 국제법 위에 있지 않다고 주장해요.', example_en_5 = 'Exceptionalism shapes how a country tells its own history to itself.', example_ko_5 = '예외주의는 나라가 스스로에게 자국의 역사를 이야기하는 방식을 형성해요.' WHERE id = 'w_news_C2_19';

UPDATE words SET example_en_2 = 'The transnational corporation operated across fifty countries simultaneously.', example_ko_2 = '초국가적 기업이 동시에 50개 나라에서 운영됐어요.', example_en_3 = 'A transnational movement mobilized activists from thirty different nations.', example_ko_3 = '초국가적 운동이 30개 다른 나라에서 활동가들을 동원했어요.', example_en_4 = 'Climate activism has become a truly transnational phenomenon.', example_ko_4 = '기후 행동주의는 진정으로 초국가적인 현상이 됐어요.', example_en_5 = 'Transnational crime networks exploit gaps in international law enforcement.', example_ko_5 = '초국가적 범죄 네트워크는 국제 법 집행의 허점을 이용해요.' WHERE id = 'w_news_C2_20';

UPDATE words SET example_en_2 = 'Mouffe''s agonistic democracy welcomes conflict as constitutive of politics.', example_ko_2 = '무페의 투쟁적 민주주의는 갈등을 정치의 구성적 요소로 환영해요.', example_en_3 = 'The agonistic model rejects the idea of rational consensus in politics.', example_ko_3 = '투쟁적 모델은 정치에서 이성적 합의의 개념을 거부해요.', example_en_4 = 'An agonistic approach to media regulation emphasizes adversarial pluralism.', example_ko_4 = '미디어 규제에 대한 투쟁적 접근은 적대적 다원주의를 강조해요.', example_en_5 = 'The agonistic theorist sees hegemony as always contested and provisional.', example_ko_5 = '투쟁적 이론가는 패권이 항상 논쟁되고 잠정적인 것으로 봐요.' WHERE id = 'w_news_C2_21';

UPDATE words SET example_en_2 = 'The discursive construction of the "enemy" legitimizes military action.', example_ko_2 = '"적"의 담론적 구성은 군사 행동을 정당화해요.', example_en_3 = 'A discursive analysis traces how policy language shapes public perception.', example_ko_3 = '담론적 분석은 정책 언어가 어떻게 대중 인식을 형성하는지를 추적해요.', example_en_4 = 'The discursive framing of the crisis influenced how states responded.', example_ko_4 = '위기의 담론적 틀이 국가가 대응하는 방식에 영향을 미쳤어요.', example_en_5 = 'Critical security studies take a discursive approach to understanding threats.', example_ko_5 = '비판 안보 연구는 위협을 이해하는 데 담론적 접근을 취해요.' WHERE id = 'w_news_C2_22';

UPDATE words SET example_en_2 = 'A counterfactual analysis asks: what if the ceasefire had held in 2014?', example_ko_2 = '반사실적 분석은 2014년 휴전이 유지됐다면 어땠을지를 물어요.', example_en_3 = 'Counterfactual reasoning has limitations but offers useful historical perspective.', example_ko_3 = '반사실적 추론에는 한계가 있지만 유용한 역사적 관점을 제공해요.', example_en_4 = 'The book explores a counterfactual world in which the US never joined NATO.', example_ko_4 = '그 책은 미국이 NATO에 가입하지 않은 반사실적 세계를 탐구해요.', example_en_5 = 'Scholars use counterfactual methods to test theories of international relations.', example_ko_5 = '학자들은 국제 관계 이론을 검증하기 위해 반사실적 방법을 사용해요.' WHERE id = 'w_news_C2_23';

UPDATE words SET example_en_2 = 'The scholar analyzed the semiotic function of the national flag in wartime.', example_ko_2 = '학자는 전시에 국기의 기호학적 기능을 분석했어요.', example_en_3 = 'The semiotic power of protest imagery can shift public opinion rapidly.', example_ko_3 = '항의 이미지의 기호학적 권력은 여론을 빠르게 바꿀 수 있어요.', example_en_4 = 'A semiotic reading of the speech reveals coded messages to supporters.', example_ko_4 = '연설의 기호학적 해독은 지지자들에 대한 코드화된 메시지를 드러내요.', example_en_5 = 'Political semiotic analysis examines how visual symbols construct meaning.', example_ko_5 = '정치적 기호학 분석은 시각적 기호가 어떻게 의미를 구성하는지를 검토해요.' WHERE id = 'w_news_C2_24';

UPDATE words SET example_en_2 = 'Economists extrapolate from current trends to predict future growth rates.', example_ko_2 = '경제학자들은 현재 추세에서 외삽하여 미래 성장률을 예측해요.', example_en_3 = 'It is risky to extrapolate global conclusions from a single case study.', example_ko_3 = '단일 사례 연구에서 글로벌 결론을 추론하는 것은 위험해요.', example_en_4 = 'The model extrapolates demographic shifts out to the year 2100.', example_ko_4 = '그 모델은 2100년까지의 인구통계적 변화를 외삽해요.', example_en_5 = 'Analysts extrapolate from polling data to forecast seat distributions.', example_ko_5 = '분석가들은 여론 조사 데이터에서 외삽하여 의석 분포를 예측해요.' WHERE id = 'w_news_C2_25';

UPDATE words SET example_en_2 = 'The temporality of the crisis matters for how policy responses are designed.', example_ko_2 = '위기의 시간성은 정책 대응이 어떻게 설계되는지에 영향을 미쳐요.', example_en_3 = 'The analyst examined the different temporalities of political and economic change.', example_ko_3 = '분석가는 정치적·경제적 변화의 다양한 시간성을 검토했어요.', example_en_4 = 'A sense of political temporality shapes how leaders frame their decisions.', example_ko_4 = '정치적 시간성 감각은 지도자들이 결정을 틀 짓는 방식을 형성해요.', example_en_5 = 'Electoral temporality can distort long-term policy thinking.', example_ko_5 = '선거 시간성은 장기 정책 사고를 왜곡할 수 있어요.' WHERE id = 'w_news_C2_26';

UPDATE words SET example_en_2 = 'The conflict has intensified along ideological lines in recent months.', example_ko_2 = '분쟁이 최근 몇 달 동안 이념적 노선을 따라 심화됐어요.', example_en_3 = 'The ideological divide between the two parties has widened since the election.', example_ko_3 = '두 당 사이의 이념적 분열이 선거 이후 더 커졌어요.', example_en_4 = 'Ideological rigidity prevents pragmatic solutions to complex problems.', example_ko_4 = '이념적 경직성은 복잡한 문제에 대한 실용적 해결책을 막아요.', example_en_5 = 'Analysts track ideological shifts within political parties over time.', example_ko_5 = '분석가들은 시간에 따라 정당 내의 이념적 변화를 추적해요.' WHERE id = 'w_news_C2_27';

UPDATE words SET example_en_2 = 'A genealogy of the concept of sovereignty reveals its contingent origins.', example_ko_2 = '주권 개념의 계보는 그 우연적 기원을 드러내요.', example_en_3 = 'The genealogy of human rights discourse is traced to Enlightenment philosophy.', example_ko_3 = '인권 담론의 계보는 계몽주의 철학으로 거슬러 올라가요.', example_en_4 = 'A Foucauldian genealogy examines how security norms emerged historically.', example_ko_4 = '푸코적 계보학은 안보 규범이 역사적으로 어떻게 등장했는지를 검토해요.', example_en_5 = 'The book traces a genealogy of propaganda from ancient rhetoric to social media.', example_ko_5 = '그 책은 고대 수사학에서 소셜 미디어까지 선전의 계보를 추적해요.' WHERE id = 'w_news_C2_28';

UPDATE words SET example_en_2 = 'A hermeneutic analysis of the speech reveals layers of unspoken assumptions.', example_ko_2 = '연설의 해석학적 분석은 말해지지 않은 가정의 층위를 드러내요.', example_en_3 = 'Hermeneutic philosophy asks how we can understand texts from other cultures.', example_ko_3 = '해석학 철학은 다른 문화의 텍스트를 어떻게 이해할 수 있는지를 물어요.', example_en_4 = 'The lawyer applied a hermeneutic approach to interpreting the treaty text.', example_ko_4 = '변호사는 조약 텍스트를 해석하는 데 해석학적 접근을 적용했어요.', example_en_5 = 'Political hermeneutics explores how different actors read the same events differently.', example_ko_5 = '정치적 해석학은 서로 다른 행위자들이 같은 사건을 어떻게 다르게 읽는지를 탐구해요.' WHERE id = 'w_news_C2_29';

UPDATE words SET example_en_2 = 'The hegemonic stability theory predicts that order requires a dominant power.', example_ko_2 = '패권 안정 이론은 질서가 지배적 권력을 필요로 한다고 예측해요.', example_en_3 = 'The hegemonic discourse frames terrorism as an existential threat.', example_ko_3 = '패권적 담론은 테러리즘을 실존적 위협으로 틀 짓고 있어요.', example_en_4 = 'The hegemonic order is increasingly being contested by emerging powers.', example_ko_4 = '패권적 질서가 신흥 강대국들에 의해 점점 도전받고 있어요.', example_en_5 = 'Critical IR scholars examine how hegemonic norms marginalize alternative voices.', example_ko_5 = '비판적 국제 관계 학자들은 패권적 규범이 어떻게 대안적 목소리를 소외시키는지를 검토해요.' WHERE id = 'w_news_C2_30';

UPDATE words SET example_en_2 = 'International norms are sustained through intersubjectivity among diplomatic actors.', example_ko_2 = '국제 규범은 외교 행위자들 사이의 상호주관성을 통해 유지돼요.', example_en_3 = 'Intersubjectivity allows states to share a common understanding of threats.', example_ko_3 = '상호주관성은 국가들이 위협에 대한 공통된 이해를 공유할 수 있게 해요.', example_en_4 = 'The analyst explored the intersubjectivity of identity in ethnic conflicts.', example_ko_4 = '분석가는 민족 분쟁에서 정체성의 상호주관성을 탐구했어요.', example_en_5 = 'Without a degree of intersubjectivity, multilateral cooperation is impossible.', example_ko_5 = '어느 정도의 상호주관성 없이는 다자간 협력이 불가능해요.' WHERE id = 'w_news_C2_31';

UPDATE words SET example_en_2 = 'The deterritorialization of capital weakens the state''s regulatory power.', example_ko_2 = '자본의 탈영토화가 국가의 규제 권력을 약화시켜요.', example_en_3 = 'Deterritorialization challenges traditional conceptions of citizenship.', example_ko_3 = '탈영토화는 시민권의 전통적 개념에 도전해요.', example_en_4 = 'The internet accelerates the deterritorialization of cultural production.', example_ko_4 = '인터넷은 문화적 생산의 탈영토화를 가속화해요.', example_en_5 = 'Deterritorialization means that states can no longer fully control information flows.', example_ko_5 = '탈영토화는 국가가 정보 흐름을 더 이상 완전히 통제할 수 없음을 의미해요.' WHERE id = 'w_news_C2_32';

UPDATE words SET example_en_2 = 'The political dialectic between reform and reaction shaped the decade.', example_ko_2 = '개혁과 반동 사이의 정치적 변증법이 그 10년을 형성했어요.', example_en_3 = 'The dialectic of globalization and nationalism defines contemporary politics.', example_ko_3 = '세계화와 민족주의의 변증법이 현대 정치를 규정해요.', example_en_4 = 'Hegel''s dialectic influenced how Marx analyzed historical materialism.', example_ko_4 = '헤겔의 변증법은 마르크스가 역사적 유물론을 분석하는 방식에 영향을 미쳤어요.', example_en_5 = 'The editorial used a dialectic between order and freedom to frame the debate.', example_ko_5 = '사설은 질서와 자유 사이의 변증법을 사용해 논쟁을 틀 지었어요.' WHERE id = 'w_news_C2_33';

UPDATE words SET example_en_2 = 'The crisis resulted in the disarticulation of the governing alliance.', example_ko_2 = '위기가 집권 연합의 연결 해체로 이어졌어요.', example_en_3 = 'Economic shocks can cause the disarticulation of previously coherent movements.', example_ko_3 = '경제적 충격은 이전에 일관된 운동의 연결 해체를 일으킬 수 있어요.', example_en_4 = 'The disarticulation of the welfare state left many citizens without support.', example_ko_4 = '복지 국가의 연결 해체가 많은 시민들을 지원 없이 남겨뒀어요.', example_en_5 = 'Scholars analyze the disarticulation of post-Cold War international institutions.', example_ko_5 = '학자들은 냉전 이후 국제 기관의 연결 해체를 분석해요.' WHERE id = 'w_news_C2_34';

UPDATE words SET example_en_2 = 'Advocates of epistemocracy argue that voters should pass a competency test.', example_ko_2 = '지식 기반 정치 체제 지지자들은 유권자가 능력 시험을 통과해야 한다고 주장해요.', example_en_3 = 'Critics say epistemocracy is inherently elitist and antidemocratic.', example_ko_3 = '비평가들은 지식 기반 정치 체제가 본질적으로 엘리트주의적이고 반민주적이라고 말해요.', example_en_4 = 'The concept of epistemocracy challenges the assumption of equal political voice.', example_ko_4 = '지식 기반 정치 체제 개념은 동등한 정치적 발언권의 가정에 도전해요.', example_en_5 = 'Technocracy is sometimes considered a mild form of epistemocracy.', example_ko_5 = '기술 관료제는 때때로 지식 기반 정치 체제의 온건한 형태로 여겨져요.' WHERE id = 'w_news_C2_35';


